let lastRenderedUrl = window.location.href;

function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function activeThemeSettings() {
  return normalizeThemeSettings(themeState.preview || themeState.settings);
}

function moduleThemeStyleAttribute() {
  const properties = themeSettingsToCssProperties(activeThemeSettings());
  const style = Object.entries(properties)
    .map(([name, value]) => `${name}: ${String(value).replaceAll('"', "&quot;")}`)
    .join("; ");

  return `style="${style}"`;
}

function applyActiveThemeToRoot() {
  const properties = themeSettingsToCssProperties(activeThemeSettings());
  for (const [name, value] of Object.entries(properties)) {
    document.documentElement.style.setProperty(name, value);
  }
}

function normalizePath(pathname) {
  let path = pathname || "/";

  if (basePath && (path === basePath || path.startsWith(`${basePath}/`))) {
    path = path.slice(basePath.length) || "/";
  }

  if (path === "/") {
    return "/";
  }

  return path.replace(/\/+$/, "") || "/";
}

function isCollectionRoutesPath(pathname = window.location.pathname) {
  return normalizePath(pathname).startsWith(COLLECTION_ROUTES_ROUTE);
}

function routeHref(route) {
  if (route === "/") {
    return `${basePath || ""}/`;
  }

  return `${basePath || ""}${route}`;
}

function apiHref(path) {
  return `${basePath || ""}${path}`;
}

function sarlotaOpenQuery() {
  return new URLSearchParams(window.location.search).get("open") || "";
}

function isSarlotaDeepLinkUrl() {
  return normalizePath(window.location.pathname) === SARLOTA_ROUTE ||
    sarlotaOpenQuery().trim().toLowerCase() === SARLOTA_OPEN_QUERY_VALUE;
}

function clearSarlotaDeepLinkUrl() {
  if (!isSarlotaDeepLinkUrl()) {
    return;
  }

  window.history.replaceState({}, "", routeHref("/"));
  lastRenderedUrl = window.location.href;
}

function employeeCardRoute(employeeId) {
  return `${EMPLOYEE_CARD_ROUTE_PREFIX}/${encodeURIComponent(employeeId || employeeIdForUser(currentUser()))}`;
}

function routeFleetVehicleId(path) {
  if (!path.startsWith(`${FLEET_ROUTE}/`) || path === `${FLEET_ROUTE}/dashboard`) {
    return "";
  }

  return decodeURIComponent(path.slice(`${FLEET_ROUTE}/`.length).split("/")[0] || "").trim();
}

function routeVehicleTrackingContext(path) {
  if (!path.startsWith(`${VEHICLE_TRACKING_BASE_ROUTE}/`)) {
    return null;
  }

  const parts = path
    .slice(`${VEHICLE_TRACKING_BASE_ROUTE}/`.length)
    .split("/")
    .map((part) => decodeURIComponent(part || "").trim())
    .filter(Boolean);

  if (!parts.length) {
    return null;
  }

  return {
    vehicleId: parts[0],
    view: parts[1] === "trasa-dnes" ? "today-trip" : parts[1] === "historie" ? "history" : "detail"
  };
}

function routeEmployeeId(path) {
  if (!path.startsWith(`${EMPLOYEE_CARD_ROUTE_PREFIX}/`)) {
    return "";
  }

  return decodeURIComponent(path.slice(`${EMPLOYEE_CARD_ROUTE_PREFIX}/`.length).split("/")[0] || "").trim();
}

function absenceTabForRoute(path) {
  if (path === "/dovolena-nemoc/dashboard") {
    return "dashboard";
  }

  return Object.entries(ABSENCE_TAB_ROUTES)
    .find(([, route]) => route === path)?.[0] || "";
}

function absenceRouteForTab(tabId) {
  return ABSENCE_TAB_ROUTES[tabId] || ABSENCE_ROUTE;
}

function absenceModuleItem() {
  return orderedModules.find((moduleItem) => moduleItem.id === "absence");
}

function renderModuleIcon(moduleItem) {
  return moduleItem.icon();
}

function statusBadge(moduleItem) {
  const label = moduleStatusLabel(moduleItem);

  if (!label) {
    return "";
  }

  return `<span class="status-badge status-badge--${moduleStatusTone(moduleItem)}">${escapeHtml(label)}</span>`;
}

function visibleModules(user) {
  const visible = filterModulesByUser(user, orderedModules);
  if (normalizeRole(user?.role) !== "ridic" || visible.some((moduleItem) => moduleItem.id === COLLECTION_ROUTES_MODULE_KEY)) {
    return visible;
  }
  const driverRoutesModule = orderedModules.find((moduleItem) => moduleItem.id === COLLECTION_ROUTES_MODULE_KEY);
  return driverRoutesModule ? [...visible, driverRoutesModule].sort((left, right) => left.order - right.order) : visible;
}

function menuModules(user) {
  const items = visibleModules(user);

  if (canViewModule(user, feedbackMenuItem.id)) {
    return [...items, feedbackMenuItem];
  }

  return items;
}

function routeForModuleCard(moduleItem, user) {
  return moduleItem.route;
}

function homeGreetingName(user) {
  const rawName = String(user?.name || user?.email || "").trim();
  const firstName = rawName.includes("@")
    ? rawName.split("@")[0].split(/[._-]/)[0]
    : rawName.split(/\s+/)[0];
  const normalized = firstName.trim();

  if (!normalized || normalized.toLowerCase() === "oplustil") {
    return "Radime";
  }

  if (normalized.toLowerCase() === "radim") {
    return "Radime";
  }

  return normalized;
}

function homeStatusMetric(value, label, tone = "neutral") {
  return `
    <span class="home-ops-metric home-ops-metric--${escapeHtml(tone)}">
      <span class="home-ops-metric__value">${escapeHtml(value)}</span>
      <span class="home-ops-metric__label">${escapeHtml(label)}</span>
    </span>
  `;
}

function homeDataBoxMetricValue() {
  const unreadMessages = dataBoxTotalUnreadCount();
  const unresolvedPlusMessages = dataBoxPlusHomeUnresolvedCount();
  const total = unreadMessages + unresolvedPlusMessages;

  if (dataBoxState.loaded || dataBoxPlusHomeState.loaded || total > 0) {
    return String(total);
  }

  return "čeká";
}

function homeCollectionRoutesMetricValue() {
  const rowCount = Array.isArray(collectionRoutesPilotState.sourceRows)
    ? collectionRoutesSourceDisplayRows().length
    : 0;

  if (rowCount > 0) {
    return String(rowCount);
  }

  if (collectionRoutesPilotState.sourceBatches.length || collectionRoutesPilotState.svozKaiserWatchdogLoaded) {
    return "0";
  }

  return "čeká";
}

function homeDriverReportsMetricValue() {
  if (!driverReportsState.loaded) {
    return "čeká";
  }

  const openCount = driverReportsState.items.filter((report) => {
    const status = String(report.status || "").toLowerCase();
    return !["completed", "cancelled", "canceled", "closed"].includes(status);
  }).length;

  return String(openCount);
}

function homeIssuesMetricValue() {
  const collectionRouteErrors = collectionRoutesSvozKaiserWatchdogErrorCount();
  const hasLoadedIssueSource = collectionRoutesPilotState.svozKaiserWatchdogLoaded || collectionRoutesPilotState.svozKaiserWatchdogError;

  if (hasLoadedIssueSource) {
    return String(collectionRouteErrors);
  }

  return "čeká";
}

function collectionRoutesSvozKaiserWatchdogSummary() {
  return collectionRoutesPilotState.svozKaiserWatchdog?.summary || {};
}

function collectionRoutesSvozKaiserWatchdogSourceRule() {
  return String(collectionRoutesSvozKaiserWatchdogSummary().sourceRule || "").trim();
}

function collectionRoutesSvozKaiserFieldConfirmed() {
  const summary = collectionRoutesSvozKaiserWatchdogSummary();
  if (summary.svozKaiserFieldConfirmed === true || summary.svozKaiserFilterConfirmed === true || summary.svozKaiserFiltered === true) {
    return true;
  }
  if (summary.svozKaiserFieldConfirmed === false || summary.svozKaiserFilterConfirmed === false) {
    return false;
  }

  const sourceRule = collectionRoutesSvozKaiserWatchdogSourceRule().toLocaleLowerCase("cs");
  if (!sourceRule) {
    return false;
  }
  if (sourceRule.includes("po potvrzení") || sourceRule.includes("po potvrzeni") || sourceRule.includes("bude tvrdý filtr") || sourceRule.includes("bude tvrdy filtr")) {
    return false;
  }

  return sourceRule.includes("svoz kaiser ano") && sourceRule.includes("tvrdý filtr");
}

function collectionRoutesSvozKaiserWatchdogRawIssueCount() {
  return Number(collectionRoutesSvozKaiserWatchdogSummary().errorCount || 0) || 0;
}

function collectionRoutesSvozKaiserWatchdogErrorCount() {
  return collectionRoutesSvozKaiserFieldConfirmed() ? collectionRoutesSvozKaiserWatchdogRawIssueCount() : 0;
}

function homeStatusMetrics() {
  return [
    homeStatusMetric(homeCollectionRoutesMetricValue(), "trasy dnes", "green"),
    homeStatusMetric(homeDriverReportsMetricValue(), "hlášení z vozidel", "blue"),
    homeStatusMetric(homeDataBoxMetricValue(), "datové zprávy", "blue"),
    homeStatusMetric(homeIssuesMetricValue(), "chyby k řešení", "muted")
  ].join("");
}

function homeModuleMeta(moduleItem) {
  if (moduleItem.id === COLLECTION_ROUTES_MODULE_KEY) {
    const errorCount = collectionRoutesSvozKaiserWatchdogErrorCount();
    if (errorCount > 0) {
      return `<span class="module-card__meta module-card__meta--danger">${escapeHtml(errorCount > 99 ? "99+ chyb ve Vistosu" : `${errorCount} chyb ve Vistosu`)}</span>`;
    }
    if (collectionRoutesPilotState.svozKaiserWatchdogLoading) {
      return `<span class="module-card__meta module-card__meta--waiting">Kontroluji Vistos...</span>`;
    }
    if (collectionRoutesPilotState.svozKaiserWatchdogLoaded && !collectionRoutesSvozKaiserFieldConfirmed()) {
      return `<span class="module-card__meta module-card__meta--waiting">Svoz Kaiser filtr čeká</span>`;
    }
    if (collectionRoutesPilotState.svozKaiserWatchdogLoaded && !collectionRoutesPilotState.svozKaiserWatchdogError) {
      return `<span class="module-card__meta module-card__meta--ok">Vistos kontrola OK</span>`;
    }
  }

  if (moduleItem.id !== DATA_BOX_MODULE_KEY) {
    return "";
  }

  const unreadCount = dataBoxTotalUnreadCount();
  if (unreadCount <= 0) {
    return "";
  }

  return `<span class="module-card__meta">${escapeHtml(unreadCount > 99 ? "99+ nových zpráv" : `${unreadCount} nových zpráv`)}</span>`;
}

function homeModuleCornerBadge(moduleItem) {
  if (moduleItem.id === DATA_BOX_PLUS_MODULE_KEY) {
    const unresolvedCount = dataBoxPlusHomeUnresolvedCount();
    if (!dataBoxPlusHomeState.loaded) {
      return "";
    }
    const value = unresolvedCount > 99 ? "99+" : String(unresolvedCount);
    return `
    <span class="data-box-plus-home-badge" title="${escapeHtml(`${value} nevyřízených zpráv v Datových schránkách`)}" aria-label="${escapeHtml(`Datové schránky: ${value} nevyřízených zpráv`)}">
      ${escapeHtml(value)}
    </span>
  `;
  }

  if (moduleItem.id === COLLECTION_ROUTES_MODULE_KEY) {
    const errorCount = collectionRoutesSvozKaiserWatchdogErrorCount();
    if (errorCount <= 0) {
      return "";
    }
    const value = errorCount > 99 ? "99+" : String(errorCount);
    return `
    <span class="collection-routes-home-alert-badge" title="${escapeHtml(`${value} chyb v datech svozu`)}" aria-label="${escapeHtml(`Svozové trasy: ${value} chyb`)}">
      ${escapeHtml(value)}
    </span>
  `;
  }

  return "";
}

function homeModuleCtaLabel(moduleItem) {
  return moduleItem.ctaLabel || "Otevřít";
}

function homeModuleCard(moduleItem, user, variant = "standard") {
  return `
    <a class="module-card module-card--${escapeHtml(variant)}" href="${routeHref(routeForModuleCard(moduleItem, user))}" data-link>
      ${homeModuleCornerBadge(moduleItem)}
      <span class="module-card__top">
        <span class="module-icon" aria-hidden="true">${renderModuleIcon(moduleItem)}</span>
        ${statusBadge(moduleItem)}
      </span>
      <span class="module-card__content">
        <span class="module-card__header">
          <span class="module-card__title">${escapeHtml(moduleItem.title)}</span>
        </span>
        <span class="module-card__description">${escapeHtml(moduleItem.description)}</span>
        ${homeModuleMeta(moduleItem)}
      </span>
      <span class="module-card__cta" aria-hidden="true">${escapeHtml(homeModuleCtaLabel(moduleItem))}</span>
    </a>
  `;
}

function homeModuleSections(modulesForUser, user) {
  const modulesById = new Map(modulesForUser.map((moduleItem) => [moduleItem.id, moduleItem]));
  const usedIds = new Set();

  return HOME_MODULE_SECTIONS
    .map((section) => {
      const items = section.moduleIds
        .map((moduleId) => {
          const moduleItem = modulesById.get(moduleId);
          if (moduleItem) {
            usedIds.add(moduleId);
          }
          return moduleItem;
        })
        .filter(Boolean);

      if (section.id === "system-settings") {
        for (const moduleItem of modulesForUser) {
          if (!usedIds.has(moduleItem.id)) {
            items.push(moduleItem);
            usedIds.add(moduleItem.id);
          }
        }
      }

      if (!items.length) {
        return "";
      }

      const variant = section.id === "today-tasks"
        ? "primary"
        : section.id === "system-settings"
          ? "system"
          : "standard";

      return `
        <section class="module-section module-section--${escapeHtml(section.id)}" aria-labelledby="module-section-${escapeHtml(section.id)}">
          <div class="module-section__header">
            <div class="module-section__title-group">
              ${section.eyebrow ? `<p class="module-section__eyebrow">${escapeHtml(section.eyebrow)}</p>` : ""}
              <h2 id="module-section-${escapeHtml(section.id)}">${escapeHtml(section.title)}</h2>
              <p>${escapeHtml(section.description)}</p>
            </div>
          </div>
          <div class="module-section__grid">
            ${items.map((moduleItem) => homeModuleCard(moduleItem, user, variant)).join("")}
          </div>
        </section>
      `;
    })
    .join("");
}

