    return collectionRoutesEmptyState(
      "13 Excelů zatím nejsou uložené přes API.",
      "Nahrajte historické soubory v této sekci. Řádky se uloží do D1 jako read-only zdroj pro Svozové trasy, ne do prohlížeče."
    );
