function collectionRoutesAddTextValue(target, value) {
  const text = String(value ?? "").trim();
  if (text && text !== "-") {
    target.add(text);
  }
}

function collectionRoutesTextList(values, fallback = "-", limit = 3) {
  const list = Array.from(values || [])
    .map((value) => String(value || "").trim())
    .filter(Boolean);
  if (!list.length) {
    return fallback;
  }
  const shown = list.slice(0, limit).join(", ");
  return list.length > limit ? `${shown} +${list.length - limit}` : shown;
}

function collectionRoutesIssueLabelsFromValue(value) {
  if (!Array.isArray(value)) {
    return [];
  }
  return value
    .map((issue) => {
      if (typeof issue === "string") {
        return issue;
      }
      return issue?.label || issue?.message || issue?.issueType || "";
    })
    .map((text) => String(text || "").trim())
    .filter(Boolean);
}

function collectionRoutesIssuesFromValue(value) {
  if (!Array.isArray(value)) {
    return [];
  }
  return value
    .map((issue) => {
      if (typeof issue === "string") {
        return { issueType: issue, label: issue };
      }
      const issueType = String(issue?.type || issue?.issueType || "").trim();
      const label = String(issue?.label || issue?.message || issueType || "").trim();
      return { issueType, label };
    })
    .filter((issue) => issue.issueType || issue.label);
}

function collectionRoutesVistosOnDemandNote(value = "") {
  const normalized = normalizeAccessSearchText(value);
  if (!normalized) {
    return false;
  }
  const tokens = new Set(normalized.split(/[^a-z0-9]+/).filter(Boolean));
  if (["vyzva", "vyzvu", "vyzvy", "vyzve"].some((token) => tokens.has(token))) {
    return true;
  }
  const compact = normalized.replace(/[^a-z0-9]+/g, "");
  return /navyzv(?:a|u|y|e)|navyzadani|nazavolani|dlepotreb(?:a|y)?|naobjednani|objednavk/.test(compact);
}

function collectionRoutesVistosEffectiveIssues(value, onDemand = false) {
  const issues = collectionRoutesIssuesFromValue(value);
  if (!onDemand) {
    return issues;
  }
  return issues.filter((issue) => issue.issueType !== "non-route-contract-row");
}

function collectionRoutesVistosAddressPartsFromItem(item = {}) {
  return {
    street: String(item.addressStreet || "").trim(),
    city: String(item.addressCity || "").trim(),
    region: String(item.addressRegion || "").trim(),
    country: String(item.addressCountry || "").trim(),
    postalCode: String(item.addressPostalCode || "").trim()
  };
}

function collectionRoutesVistosGenericAddressPlace(value = "") {
  const text = String(value || "").trim();
  const key = normalizeAccessSearchText(text).replace(/[^a-z0-9]+/g, "");
  if (!text) {
    return true;
  }
  if (["branch", "company", "customer", "directory", "directorybranch", "firma", "pobocka", "zakaznik"].includes(key)) {
    return true;
  }
  if (/\s-\s*\d{8}$/.test(text)) {
    return true;
  }
  return /\s-\s*\d{6,12}$/.test(text) && (
    /\b(?:s\.?\s*r\.?\s*o|a\.?\s*s|spol|druzstvo)\b/i.test(text) ||
    text.toLocaleLowerCase("cs").includes("s.r.o") ||
    text.toLocaleLowerCase("cs").includes("a.s")
  );
}

function collectionRoutesVistosStrictAddressPlace(...values) {
  return values
    .map((value) => String(value || "").trim())
    .find((value) => value && !collectionRoutesVistosGenericAddressPlace(value)) || "";
}

function collectionRoutesVistosAddressPartsLabel(parts = {}) {
  const region = /^\d+$/.test(String(parts.region || "").trim()) ? "" : parts.region;
  const country = /^\d+$/.test(String(parts.country || "").trim()) ? "" : parts.country;
  return [
    parts.street ? `svozová ulice: ${parts.street}` : "",
    parts.city ? `město: ${parts.city}` : "",
    region ? `kraj/stát: ${region}` : "",
    country ? `země: ${country}` : "",
    parts.postalCode ? `PSČ: ${parts.postalCode}` : ""
  ].filter(Boolean).join(" · ");
}

const COLLECTION_ROUTES_VISTOS_PICKUP_DAY_LABELS = {
  18330: "pondělí lichá",
  18331: "úterý lichá",
  18332: "středa lichá",
  18333: "čtvrtek lichá",
  18334: "pátek lichá",
  18335: "sobota lichá",
  18336: "neděle lichá",
  18337: "pondělí sudá",
  18338: "úterý sudá",
  18339: "středa sudá",
  18340: "čtvrtek sudá",
  18341: "pátek sudá",
  18342: "sobota sudá",
  18343: "neděle sudá"
};

function collectionRoutesVistosPickupDayDisplayValue(value = "") {
  const text = String(value || "").trim();
  if (!text) {
    return "";
  }
  const parts = text
    .split(/[,;|]+/)
    .map((part) => part.trim())
    .filter(Boolean);
  if (parts.length > 1) {
    return parts.map(collectionRoutesVistosPickupDayDisplayValue).filter(Boolean).join(", ");
  }
  return COLLECTION_ROUTES_VISTOS_PICKUP_DAY_LABELS[text] || text;
}

function collectionRoutesVistosPickupDaysDisplay(...values) {
  const seen = new Set();
  const labels = [];
  values.forEach((value) => {
    collectionRoutesVistosPickupDayDisplayValue(value)
      .split(/,\s*/)
      .map((part) => part.trim())
      .filter(Boolean)
      .forEach((label) => {
        const key = label.toLocaleLowerCase("cs");
        if (!seen.has(key)) {
          seen.add(key);
          labels.push(label);
        }
      });
  });
  return labels.join(", ");
}

const COLLECTION_ROUTES_VISTOS_PICKUP_DAY_CODE_LABELS = {
  PO: "pondělí",
  "ÚT": "úterý",
  ST: "středa",
  "ČT": "čtvrtek",
  "PÁ": "pátek",
  SO: "sobota",
  NE: "neděle"
};

function collectionRoutesVistosSmartPickupDaysDisplay(frequency, ...values) {
  const text = collectionRoutesVistosPickupDaysDisplay(...values) || values.map((value) => String(value || "").trim()).filter(Boolean).join(" ");
  const normalizedFrequency = String(frequency || "").trim().toLocaleLowerCase("cs");
  if (normalizedFrequency !== "1x7" || !text) {
    return text;
  }

  const dayCodes = collectionRoutesVistosPickupDayCodesFromText(text);
  const weekModes = collectionRoutesVistosWeekModesFromText(text)
    .filter((mode) => mode === "sudý týden" || mode === "lichý týden");
  if (dayCodes.length !== 1 || weekModes.length !== 1) {
    return text;
  }

  const dayLabel = COLLECTION_ROUTES_VISTOS_PICKUP_DAY_CODE_LABELS[dayCodes[0]] || dayCodes[0];
  const inferredParity = weekModes[0] === "sudý týden" ? "lichá" : "sudá";
  const inferredText = `${dayLabel} ${inferredParity}`;
  if (normalizeAccessSearchText(text).includes(normalizeAccessSearchText(inferredText))) {
    return text;
  }
  return `${text}, ${inferredText} (dopočteno)`;
}

function collectionRoutesVistosContainerEvidenceLabel(item = {}) {
  const fieldVolume = collectionRoutesMetricValue(item.containerFieldVolume, 0);
  const nameVolume = collectionRoutesMetricValue(item.containerNameVolume, 0);
  const source = String(item.containerVolumeSource || "").trim();
  const parts = [];
  if (fieldVolume > 0) {
    parts.push(`Vistos pole: ${fieldVolume} l`);
  }
  if (nameVolume > 0) {
    parts.push(`Název: ${nameVolume} l`);
  }
  if (source === "name") {
    parts.push("použito: Název");
  } else if (source === "field") {
    parts.push("použito: Vistos pole");
  } else if (source === "text_alias") {
    parts.push("použito: alias textu");
  }
  return parts.join(" · ");
}

function collectionRoutesIssueTypesForCell(item, cell) {
  const types = new Set((item.issues || []).map((issue) => String(issue.issueType || issue.label || "").toLowerCase()));
  const hasAny = (...needles) => Array.from(types).some((type) => needles.some((needle) => type.includes(needle)));
  if (cell === "dateRange") {
    return hasAny("date", "svoz od", "svoz do", "start", "end");
  }
  if (cell === "addressPlace") {
    return hasAny("address", "adresa", "adresni", "adresní", "loading");
  }
  if (cell === "waste") {
    return hasAny("waste", "odpad", "product", "produkt", "mappable");
  }
  if (cell === "container") {
    return hasAny("container", "nadob", "nádob", "volume");
  }
  if (cell === "interval") {
    return hasAny("frequency", "interval", "cetnost", "četnost");
  }
  if (cell === "pickupDays") {
    return hasAny("pickup-day", "pickup-days", "svozovy", "svozové", "collectionday", "parity", "sudy", "lichy");
  }
  return false;
}

function collectionRoutesDetailCellClass(item, cell) {
  return collectionRoutesIssueTypesForCell(item, cell) ? "collection-routes-site-detail-cell--danger" : "";
}

function collectionRoutesVistosSourceRows() {
  return collectionRoutesSvozKaiserFieldConfirmed()
    ? collectionRoutesPilotState.kommunalPairingRows.filter((row) => collectionRoutesImportRowSummary(row).svozKaiserIncluded === true)
    : collectionRoutesPilotState.kommunalPairingRows;
}

function collectionRoutesContractKey(sourceRow, summary, fallback = "") {
  const key = collectionRoutesWatchdogTextKey(
    summary.contractNumber,
    summary.sourceContractId,
    summary.contractId,
    sourceRow.sourceContractId,
    sourceRow.contractId
  );
  return key || fallback;
}

function collectionRoutesVistosContractDetailItem(sourceRow, index) {
  const summary = collectionRoutesImportRowSummary(sourceRow);
  const note = summary.note || sourceRow.note || "";
  const storedServiceMode = summary.serviceMode || sourceRow.serviceMode || "";
  const onDemand = summary.onDemand === true || sourceRow.onDemand === true || storedServiceMode === "on_demand" || collectionRoutesVistosOnDemandNote(note);
  const serviceMode = onDemand ? "on_demand" : storedServiceMode || "regular";
  const serviceModeLabel = summary.serviceModeLabel || sourceRow.serviceModeLabel || (onDemand ? "Na výzvu" : "");
  const issues = collectionRoutesVistosEffectiveIssues(summary.issues || sourceRow.issues, onDemand);
  const addressParts = collectionRoutesVistosAddressPartsFromItem({ ...sourceRow, ...summary });
  const addressPlace = collectionRoutesVistosStrictAddressPlace(summary.addressPlaceRaw, sourceRow.addressPlaceRaw);
  const containerCount = collectionRoutesMetricValue(summary.containerCount, 0);
  const normalizedContainerCount = containerCount > 0 ? containerCount : summary.containerVolume ? 1 : 0;
  const container = summary.containerVolume
    ? `${normalizedContainerCount || 1}× ${summary.containerVolume} l${summary.containerType ? ` ${summary.containerType}` : ""}`
    : summary.containerType || "neurčeno";
  const containerEvidence = {
    containerFieldVolume: summary.containerFieldVolume ?? sourceRow.containerFieldVolume,
    containerNameVolume: summary.containerNameVolume ?? sourceRow.containerNameVolume,
    containerVolumeSource: summary.containerVolumeSource || sourceRow.containerVolumeSource || ""
  };
  const interval = summary.frequency || sourceRow.frequency || (onDemand ? "Na výzvu" : "neurčeno");
  return {
    order: index + 1,
    contractKey: collectionRoutesContractKey(sourceRow, summary, `contract-row-${index}`),
    sourceRow,
    summary,
    dateRange: collectionRoutesVistosDateRangeLabel(summary.pickupFrom || sourceRow.pickupFrom, summary.pickupTo || sourceRow.pickupTo),
    addressPlace: addressPlace || "chybí Adresní místo",
    addressPlaceMissing: !addressPlace,
    addressParts,
    addressPartsLabel: collectionRoutesVistosAddressPartsLabel(addressParts),
    stationName: summary.stationName || sourceRow.stationName || "",
    waste: [summary.wasteType, summary.wasteCode].filter(Boolean).join(" / ") || "neurčeno",
    container,
    containerEvidenceLabel: collectionRoutesVistosContainerEvidenceLabel(containerEvidence),
    interval,
    pickupDays: collectionRoutesVistosSmartPickupDaysDisplay(
      interval,
      summary.pickupDaysText,
      summary.pickupDays,
      sourceRow.pickupDaysText,
      sourceRow.pickupDays
    ) || (onDemand ? "Dle výzvy" : "neurčeno"),
    serviceMode,
    serviceModeLabel,
    onDemand,
    note,
    customerManagerName: summary.customerManagerName || sourceRow.customerManagerName || "",
    customerManagerMobile: summary.customerManagerMobile || sourceRow.customerManagerMobile || "",
    customerManagerEmail: summary.customerManagerEmail || sourceRow.customerManagerEmail || "",
    customerManagerContact: [
      summary.customerManagerName || sourceRow.customerManagerName,
      summary.customerManagerMobile || sourceRow.customerManagerMobile,
      summary.customerManagerEmail || sourceRow.customerManagerEmail
    ].filter(Boolean).join(" · "),
    containerVolumeMismatch: Boolean(summary.containerVolumeMismatch || sourceRow.containerVolumeMismatch),
    issues,
    issueLabels: issues.map((issue) => issue.label).filter(Boolean),
    issueCount: onDemand ? issues.length : collectionRoutesMetricValue(summary.issueCount ?? sourceRow.issueCount, issues.length),
    containerCount: normalizedContainerCount
  };
}

function collectionRoutesVistosDateRangeLabel(from, to) {
  const fromLabel = collectionRoutesVistosDateLabel(from);
  const toLabel = collectionRoutesVistosDateLabel(to);
  if (fromLabel && toLabel) {
    return `${fromLabel} - ${toLabel}`;
  }
  return fromLabel || toLabel || "neurčeno";
}

function collectionRoutesVistosDateLabel(value) {
  const text = String(value || "").trim();
  if (!text) {
    return "";
  }
  const iso = text.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (iso) {
    return `${iso[3]}. ${iso[2]}. ${iso[1]}`;
  }
  return text;
}

function collectionRoutesVistosContractRows() {
  const rows = collectionRoutesVistosSourceRows();
  const contractsByKey = new Map();

  rows.forEach((sourceRow, index) => {
    const summary = collectionRoutesImportRowSummary(sourceRow);
    const key = collectionRoutesContractKey(sourceRow, summary, `vistos-contract-${index}`) || `vistos-contract-${index}`;
    const existing = contractsByKey.get(key) || {
      key,
      order: contractsByKey.size + 1,
      contractNumber: summary.contractNumber || summary.sourceContractId || sourceRow.sourceContractId || "-",
      customerName: summary.customerName || "-",
      issueLabels: new Set(),
      items: [],
      itemCount: 0,
      onDemandItemCount: 0,
      containerCount: 0,
      issueCount: 0
    };

    if ((summary.contractNumber || summary.sourceContractId || sourceRow.sourceContractId) && existing.contractNumber === "-") {
      existing.contractNumber = summary.contractNumber || summary.sourceContractId || sourceRow.sourceContractId;
    }
    if (summary.customerName && existing.customerName === "-") {
      existing.customerName = summary.customerName;
    }

    const detailItem = collectionRoutesVistosContractDetailItem(sourceRow, index);
    const issueLabels = detailItem.issueLabels;
    issueLabels.forEach((label) => collectionRoutesAddTextValue(existing.issueLabels, label));
    const issueCount = detailItem.issueCount || issueLabels.length;
    if (issueCount > 0 && !issueLabels.length) {
      collectionRoutesAddTextValue(existing.issueLabels, `${issueCount} upozornění`);
    }

    existing.items.push(detailItem);
    existing.itemCount += 1;
    existing.onDemandItemCount += detailItem.onDemand ? 1 : 0;
    existing.containerCount += detailItem.containerCount;
    existing.issueCount += Math.max(0, issueCount);
    contractsByKey.set(key, existing);
  });

  return Array.from(contractsByKey.values()).sort((left, right) => (
    String(left.contractNumber || "").localeCompare(String(right.contractNumber || ""), "cs") ||
    String(left.customerName || "").localeCompare(String(right.customerName || ""), "cs") ||
    left.order - right.order
  ));
}

function collectionRoutesVistosSitesStats(contractRows = collectionRoutesVistosContractRows()) {
  const sourceRows = collectionRoutesVistosSourceRows();
  const contracts = new Set();
  const sites = new Set();
  let containerCount = 0;
  sourceRows.forEach((sourceRow) => {
    const summary = collectionRoutesImportRowSummary(sourceRow);
    collectionRoutesAddTextValue(contracts, summary.contractNumber || summary.sourceContractId || sourceRow.sourceContractId);
    const siteKey = collectionRoutesWatchdogTextKey(
      summary.siteKey || sourceRow.siteKey,
      summary.sourceSiteId || sourceRow.sourceSiteId,
      summary.customerName,
      summary.siteName,
      summary.addressRaw
    );
    if (siteKey) {
      sites.add(siteKey);
    }
    const count = collectionRoutesMetricValue(summary.containerCount, 0);
    containerCount += count > 0 ? count : summary.containerVolume ? 1 : 0;
  });
  return {
    siteCount: sites.size || contractRows.length,
    contractCount: contracts.size || contractRows.length,
    itemCount: sourceRows.length,
    containerCount
  };
}

function collectionRoutesVistosSitesSummaryStats(contractRows = collectionRoutesVistosContractRows()) {
  const snapshotSummary = collectionRoutesPilotState.kommunalPairingSummary || {};
  const fallback = collectionRoutesVistosSitesStats(contractRows);
  return {
    siteCount: collectionRoutesMetricValue(snapshotSummary.siteCount, fallback.siteCount),
    contractCount: collectionRoutesMetricValue(snapshotSummary.contractCount, fallback.contractCount),
    itemCount: collectionRoutesMetricValue(snapshotSummary.itemCount || snapshotSummary.rowCount, fallback.itemCount),
    containerCount: collectionRoutesMetricValue(snapshotSummary.containerCount, fallback.containerCount)
  };
}

function collectionRoutesVistosSitesFilterValue(name) {
  const filters = collectionRoutesPilotState.vistosSitesFilter || {};
  return filters[name] || "all";
}

function collectionRoutesVistosFilteredContractRows(contractRows = collectionRoutesVistosContractRows()) {
  const status = collectionRoutesVistosSitesFilterValue("status");
  if (status === "errors") {
    return contractRows.filter((row) => collectionRoutesMetricValue(row.issueCount, 0) > 0);
  }
  if (status === "on_demand") {
    return contractRows.filter((row) => collectionRoutesMetricValue(row.onDemandItemCount, 0) > 0);
  }
  if (status === "ok") {
    return contractRows.filter((row) => (
      collectionRoutesMetricValue(row.issueCount, 0) === 0 &&
      collectionRoutesMetricValue(row.onDemandItemCount, 0) === 0
    ));
  }
  return contractRows;
}

function collectionRoutesVistosSitesFilterPanel(contractRows = collectionRoutesVistosContractRows()) {
  const selected = collectionRoutesVistosSitesFilterValue("status");
  const errorCount = contractRows.filter((row) => collectionRoutesMetricValue(row.issueCount, 0) > 0).length;
  const onDemandCount = contractRows.filter((row) => collectionRoutesMetricValue(row.onDemandItemCount, 0) > 0).length;
  const okCount = contractRows.filter((row) => (
    collectionRoutesMetricValue(row.issueCount, 0) === 0 &&
    collectionRoutesMetricValue(row.onDemandItemCount, 0) === 0
  )).length;
  return `
    <div class="collection-routes-sites-filter" role="group" aria-label="Filtr stanovišť">
      ${[
        ["all", "Všechna", contractRows.length],
        ["errors", "Jen s chybou", errorCount],
        ["on_demand", "Na výzvu", onDemandCount],
        ["ok", "OK", okCount]
      ].map(([value, label, count]) => `
        <button
          class="collection-routes-sites-filter__button ${selected === value ? "collection-routes-sites-filter__button--active" : ""}"
          type="button"
          data-collection-routes-sites-filter="${escapeHtml(value)}"
          aria-pressed="${selected === value ? "true" : "false"}"
        >
          <span>${escapeHtml(label)}</span>
          <strong>${escapeHtml(count)}</strong>
        </button>
      `).join("")}
    </div>
  `;
}

function collectionRoutesVistosRouteFilterValue(name) {
  const filters = collectionRoutesPilotState.vistosRouteFilters || {};
  return filters[name] || "all";
}

function collectionRoutesVistosPickupDayCodesFromText(value) {
  const text = normalizeAccessSearchText(value);
  const days = [];
  const addDay = (code) => {
    if (code && !days.includes(code)) {
      days.push(code);
    }
  };
  if (/(^|[^a-z])po([^a-z]|$)|pondeli|pondel|monday|pondelok|montag/.test(text)) {
    addDay("PO");
  }
  if (/(^|[^a-z])ut([^a-z]|$)|utery|uter|tuesday|utorok|dienstag/.test(text)) {
    addDay("ÚT");
  }
  if (/(^|[^a-z])st([^a-z]|$)|streda|stre|wednesday|mittwoch/.test(text)) {
    addDay("ST");
  }
  if (/(^|[^a-z])ct([^a-z]|$)|ctvrtek|ctvrt|thursday|stvrtok|donnerstag/.test(text)) {
    addDay("ČT");
  }
  if (/(^|[^a-z])pa([^a-z]|$)|patek|pat|friday|piatok|freitag/.test(text)) {
    addDay("PÁ");
  }
  if (/(^|[^a-z])so([^a-z]|$)|sobota|saturday|samstag/.test(text)) {
    addDay("SO");
  }
  if (/(^|[^a-z])ne([^a-z]|$)|nedele|nedela|sunday|sonntag/.test(text)) {
    addDay("NE");
  }
  return days;
}

function collectionRoutesVistosWeekModeFromText(value) {
  return collectionRoutesVistosWeekModesFromText(value)[0] || "každý týden";
}

function collectionRoutesVistosWeekModesFromText(value) {
  const text = normalizeAccessSearchText(value);
  const compact = text.replace(/\s+/g, "");
  const compactWithoutOdd = compact
    .replaceAll("neparny", "")
    .replaceAll("neparna", "")
    .replaceAll("neparn", "")
    .replaceAll("ungerade", "");
  const modes = [];
  const addMode = (mode) => {
    if (mode && !modes.includes(mode)) {
      modes.push(mode);
    }
  };
  if (/mesic|1x30|30/.test(text)) {
    addMode("měsíční / 1x30");
  }
  if (/lich|odd|nepar|ungerade/.test(text)) {
    addMode("lichý týden");
  }
  if (/sud|even|parn|gerade/.test(compactWithoutOdd)) {
    addMode("sudý týden");
  }
  if (!modes.length) {
    addMode("každý týden");
  }
  return modes;
}

function collectionRoutesVistosRouteStatus(row) {
  if (!collectionRoutesSvozKaiserFieldConfirmed()) {
    return { value: "waiting", label: "Čeká", tone: "waiting" };
  }
  if (collectionRoutesMetricValue(row?.issueCount, 0) > 0) {
    return { value: "review", label: "Zkontrolovat", tone: "warning" };
  }
  if (row?.onDemand === true || row?.serviceMode === "on_demand") {
    return { value: "on_demand", label: "Na výzvu", tone: "waiting" };
  }
  return { value: "ok", label: "OK", tone: "ok" };
}

function collectionRoutesVistosRouteRows() {
  return collectionRoutesVistosSourceRows().map((sourceRow, index) => {
    const summary = collectionRoutesImportRowSummary(sourceRow);
    const note = summary.note || sourceRow.note || "";
    const storedServiceMode = summary.serviceMode || sourceRow.serviceMode || "";
    const onDemand = summary.onDemand === true || sourceRow.onDemand === true || storedServiceMode === "on_demand" || collectionRoutesVistosOnDemandNote(note);
    const serviceMode = onDemand ? "on_demand" : storedServiceMode || "regular";
    const serviceModeLabel = summary.serviceModeLabel || sourceRow.serviceModeLabel || (onDemand ? "Na výzvu" : "");
    const issues = collectionRoutesVistosEffectiveIssues(summary.issues || sourceRow.issues, onDemand);
    const frequency = summary.frequency || sourceRow.frequency || (onDemand ? "Na výzvu" : "");
    const pickupDaysRawText = [
      summary.pickupDaysText,
      summary.pickupDays,
      sourceRow.pickupDaysText,
      sourceRow.pickupDays,
      summary.collectionDay,
      sourceRow.collectionDay
    ].filter(Boolean).join(" ");
    const pickupDaysText = collectionRoutesVistosSmartPickupDaysDisplay(
      frequency,
      summary.pickupDaysText,
      summary.pickupDays,
      sourceRow.pickupDaysText,
      sourceRow.pickupDays,
      summary.collectionDay,
      sourceRow.collectionDay
    ) || pickupDaysRawText || (onDemand ? "Dle výzvy" : "");
    const pickupDayCodes = collectionRoutesVistosPickupDayCodesFromText(pickupDaysText);
    const containerCount = collectionRoutesMetricValue(summary.containerCount ?? sourceRow.containerCount, 0);
    const containerVolume = summary.containerVolume ?? sourceRow.containerVolume ?? "";
    const issueCount = onDemand ? issues.length : collectionRoutesMetricValue(summary.issueCount ?? sourceRow.issueCount, issues.length);
    const wasteType = summary.wasteType || sourceRow.wasteType || (onDemand ? "neurčeno" : "ostatní");
    const strictAddressPlace = collectionRoutesVistosStrictAddressPlace(summary.addressPlaceRaw, sourceRow.addressPlaceRaw);
    const routeAddressText = strictAddressPlace || summary.addressRaw || sourceRow.addressRaw || "-";
    const routeRow = {
      id: sourceRow.id || sourceRow.rowId || `vistos-route-${index + 1}`,
      sourceKind: "vistos",
      routeOrder: index + 1,
      customerName: summary.customerName || sourceRow.customerName || "-",
      addressText: routeAddressText,
      addressPlaceText: strictAddressPlace,
      addressParts: collectionRoutesVistosAddressPartsFromItem({ ...sourceRow, ...summary }),
      stationName: summary.stationName || sourceRow.stationName || "",
      wasteType,
      wasteCode: summary.wasteCode || sourceRow.wasteCode || "",
      containerVolume,
      containerCount: containerCount > 0 ? containerCount : containerVolume ? 1 : 0,
      containerFieldVolume: summary.containerFieldVolume ?? sourceRow.containerFieldVolume ?? 0,
      containerNameVolume: summary.containerNameVolume ?? sourceRow.containerNameVolume ?? 0,
      containerVolumeSource: summary.containerVolumeSource || sourceRow.containerVolumeSource || "",
      containerVolumeMismatch: Boolean(summary.containerVolumeMismatch || sourceRow.containerVolumeMismatch),
      frequency,
      serviceMode,
      serviceModeLabel,
      onDemand,
      note,
      pickupDaysText: pickupDaysText || "neurčeno",
      pickupDayCodes,
      weekMode: onDemand
        ? "na výzvu"
        : collectionRoutesVistosWeekModeFromText(pickupDaysText || pickupDaysRawText || summary.frequency || sourceRow.frequency),
      weekModes: onDemand
        ? ["na výzvu"]
        : collectionRoutesVistosWeekModesFromText(pickupDaysText || pickupDaysRawText || summary.frequency || sourceRow.frequency),
      vehicleCode: summary.vehicleCode || sourceRow.vehicleCode || "all",
      sourceFile: "Vistos API",
      sourceSheet: summary.contractNumber || summary.sourceContractId || sourceRow.sourceContractId || "-",
      sourceRowNumber: summary.rowNumber || sourceRow.rowNumber || index + 1,
      vistosMatchStatus: issueCount > 0 ? "zkontrolovat" : "OK",
      vistosIssue: issues.map((issue) => issue.label || issue.issueType || issue.type).filter(Boolean).join(", "),
      vistosContractNumber: summary.contractNumber || summary.sourceContractId || sourceRow.sourceContractId || "-",
      vistosCustomerName: summary.customerName || sourceRow.customerName || "-",
      vistosSiteName: summary.siteName || strictAddressPlace || summary.addressRaw || sourceRow.addressRaw || "-",
      customerManagerMobile: summary.customerManagerMobile || sourceRow.customerManagerMobile || "",
      customerManagerEmail: summary.customerManagerEmail || sourceRow.customerManagerEmail || "",
      customerManagerName: summary.customerManagerName || sourceRow.customerManagerName || "",
      issueCount,
      issues,
      rawSourceRow: sourceRow
    };
    return routeRow;
  });
}

function collectionRoutesVistosRouteDisplayRows() {
  const day = collectionRoutesVistosRouteFilterValue("day");
  const week = collectionRoutesVistosRouteFilterValue("week");
  const waste = collectionRoutesVistosRouteFilterValue("waste");
  const status = collectionRoutesVistosRouteFilterValue("status");
  const wasteValues = collectionRoutesSourceWasteValues(waste);
  return collectionRoutesVistosRouteRows().filter((row) => {
    const routeStatus = collectionRoutesVistosRouteStatus(row).value;
    const rowWaste = collectionRoutesSourceRowWasteFilterValue(row);
    const matchesDay = day === "all" || row.pickupDayCodes.includes(day);
    const matchesWeek = week === "all" || row.weekModes.includes(week) || row.weekModes.includes("každý týden");
    const matchesWaste = !wasteValues.length || wasteValues.includes(rowWaste);
    const matchesStatus = status === "all" || routeStatus === status;
    return matchesDay && matchesWeek && matchesWaste && matchesStatus;
  });
}

function collectionRoutesVistosRouteWasteMultiFilter() {
  const selectedValues = collectionRoutesSourceWasteValues(collectionRoutesVistosRouteFilterValue("waste"));
  return `
    <div class="collection-routes-waste-multi" role="group" aria-label="Filtr odpadu">
      ${COLLECTION_ROUTES_SOURCE_WASTE_FILTER_OPTIONS.map(([value, label]) => {
        const checked = value === "all"
          ? selectedValues.length === 0
          : selectedValues.includes(value);
        return `
          <label class="collection-routes-waste-chip ${checked ? "collection-routes-waste-chip--active" : ""}">
            <input
              type="checkbox"
              value="${escapeHtml(value)}"
              data-collection-routes-vistos-route-waste-option
              ${checked ? "checked" : ""}
            >
            <span>${escapeHtml(label)}</span>
          </label>
        `;
      }).join("")}
    </div>
  `;
}

function collectionRoutesVistosRouteFilterPanel(rows = collectionRoutesVistosRouteDisplayRows()) {
  return `
    <div class="collection-routes-print-filter collection-routes-print-filter--driver" id="collection-routes-vistos-route-filter">
      <div class="collection-routes-print-filter__head">
        <div>
          <p class="module-feedback__eyebrow">Filtr trasy</p>
          <h3>Vistos Svoz Kaiser</h3>
        </div>
        <span class="employee-card-status employee-card-status--ready">${collectionRoutesMetricValue(rows.length)} položek</span>
      </div>
      <div class="collection-routes-route-filter collection-routes-route-filter--wide" data-collection-routes-vistos-route-panel>
        <label>
          <span>Den svozu</span>
          <select data-collection-routes-vistos-route-filter="day">
            ${[
              ["all", "vše"],
              ["PO", "pondělí"],
              ["ÚT", "úterý"],
              ["ST", "středa"],
              ["ČT", "čtvrtek"],
              ["PÁ", "pátek"],
              ["SO", "sobota"],
              ["NE", "neděle"]
            ].map(([value, label]) => `<option value="${escapeHtml(value)}" ${collectionRoutesVistosRouteFilterValue("day") === value ? "selected" : ""}>${escapeHtml(label)}</option>`).join("")}
          </select>
        </label>
        <label>
          <span>Týden</span>
          <select data-collection-routes-vistos-route-filter="week">
            ${["all", "na výzvu", "sudý týden", "lichý týden", "každý týden", "měsíční / 1x30"].map((value) => `
              <option value="${escapeHtml(value)}" ${collectionRoutesVistosRouteFilterValue("week") === value ? "selected" : ""}>${collectionRoutesSourceLabel(value)}</option>
            `).join("")}
          </select>
        </label>
        <div class="collection-routes-field collection-routes-field--waste">
          <span>Odpad</span>
          ${collectionRoutesVistosRouteWasteMultiFilter()}
        </div>
        <label>
          <span>Stav</span>
          <select data-collection-routes-vistos-route-filter="status">
            ${[
              ["all", "vše"],
              ["ok", "OK"],
              ["on_demand", "na výzvu"],
              ["review", "zkontrolovat"],
              ["waiting", "čeká"]
            ].map(([value, label]) => `<option value="${escapeHtml(value)}" ${collectionRoutesVistosRouteFilterValue("status") === value ? "selected" : ""}>${escapeHtml(label)}</option>`).join("")}
          </select>
        </label>
      </div>
    </div>
  `;
}

function collectionRoutesVistosRouteSummaryCards(rows = collectionRoutesVistosRouteDisplayRows()) {
  const summary = collectionRoutesSourceRowsMetrics(rows);
  const reviewCount = rows.filter((row) => collectionRoutesVistosRouteStatus(row).value === "review").length;
  const loadedAt = collectionRoutesPilotState.kommunalPairingLoadedAt ? formatDateTime(collectionRoutesPilotState.kommunalPairingLoadedAt) : "čeká";
  return `
    <div class="collection-routes-stats collection-routes-stats--route collection-routes-stats--vistos-route" aria-label="Souhrn Vistos Svoz Kaiser trasy">
      <article><span>Zdroj</span><strong>Vistos API</strong></article>
      <article><span>Položky</span><strong>${collectionRoutesMetricValue(rows.length)}</strong></article>
      <article><span>Nádoby</span><strong>${collectionRoutesMetricValue(summary.containerCount)}</strong></article>
      <article><span>Ke kontrole</span><strong>${collectionRoutesMetricValue(reviewCount)}</strong></article>
      <article><span>Snapshot</span><strong>${escapeHtml(loadedAt)}</strong></article>
    </div>
  `;
}

function collectionRoutesVistosRouteTable(rows = collectionRoutesVistosRouteDisplayRows()) {
  if (collectionRoutesPilotState.kommunalPairingLoading && !rows.length) {
    return collectionRoutesEmptyState("Načítám Svoz Kaiser trasy.", "Beru poslední Vistos snapshot.");
  }
  if (!rows.length) {
    return collectionRoutesEmptyState("Žádná položka neodpovídá filtru.", "Změň den, týden, odpad nebo stav.");
  }
  return `
    ${collectionRoutesVistosSitesPagination()}
    <div class="collection-routes-sites-table collection-routes-preview-table" role="region" aria-label="Svozové trasy z Vistosu">
      <table>
        <thead>
          <tr>
            <th>Stav</th>
            <th>Pořadí</th>
            <th>Zákazník</th>
            <th>Stanoviště</th>
            <th>Odpad / nádoba</th>
            <th>Interval</th>
            <th>Den svozu</th>
            <th>Smlouva</th>
          </tr>
        </thead>
        <tbody>
          ${rows.map((row) => {
            const status = collectionRoutesVistosRouteStatus(row);
            return `
              <tr class="collection-routes-site-contract-row ${row.issueCount > 0 ? "collection-routes-site-contract-row--danger" : ""}">
                <td data-label="Stav">
                  <span class="collection-routes-site-status collection-routes-site-status--${escapeHtml(status.tone)}">${escapeHtml(status.label)}</span>
                </td>
                <td data-label="Pořadí">${escapeHtml(row.routeOrder)}</td>
                <td data-label="Zákazník">${escapeHtml(row.customerName || "-")}</td>
                <td data-label="Stanoviště">
                  <strong>${escapeHtml(row.stationName || row.addressText || "-")}</strong>
                  ${row.stationName && row.addressText ? `<span>${escapeHtml(row.addressText)}</span>` : ""}
                </td>
                <td data-label="Odpad / nádoba">
                  <strong>${escapeHtml(collectionRoutesSourceDriverWasteLabel(row))}</strong>
                  <span>${escapeHtml(collectionRoutesSourceDriverContainerLabel(row))}</span>
                </td>
                <td data-label="Interval">${escapeHtml(row.frequency || "-")}</td>
                <td data-label="Den svozu">${escapeHtml(row.pickupDaysText || "-")}</td>
                <td data-label="Smlouva">
                  <strong>${escapeHtml(row.vistosContractNumber || "-")}</strong>
                  ${row.vistosIssue ? `<span>${escapeHtml(row.vistosIssue)}</span>` : ""}
                </td>
              </tr>
            `;
          }).join("")}
        </tbody>
      </table>
    </div>
    ${collectionRoutesVistosSitesPagination()}
  `;
}

function collectionRoutesVistosSitesPagination() {
  const pagination = collectionRoutesPilotState.kommunalPairingPagination || {};
  const totalRows = collectionRoutesMetricValue(pagination.totalRows, collectionRoutesVistosSourceRows().length);
  const pageSize = collectionRoutesMetricValue(pagination.pageSize, 100);
  const totalPages = Math.max(1, collectionRoutesMetricValue(pagination.totalPages, 1));
  const page = Math.min(Math.max(1, collectionRoutesMetricValue(pagination.page, 1)), totalPages);
  if (!totalRows || totalPages <= 1) {
    return "";
  }
  const start = ((page - 1) * pageSize) + 1;
  const end = Math.min(totalRows, page * pageSize);
  return `
    <div class="collection-routes-sites-pagination" role="navigation" aria-label="Stránkování Stanovišť">
      <span>Zobrazeno ${escapeHtml(start)}-${escapeHtml(end)} z ${escapeHtml(totalRows)} řádků · strana ${escapeHtml(page)} / ${escapeHtml(totalPages)}</span>
      <div>
        <button class="secondary-link" type="button" data-collection-routes-sites-page="${escapeHtml(page - 1)}" ${page <= 1 ? "disabled" : ""}>Předchozí</button>
        <button class="secondary-link" type="button" data-collection-routes-sites-page="${escapeHtml(page + 1)}" ${page >= totalPages ? "disabled" : ""}>Další</button>
      </div>
    </div>
  `;
}

function collectionRoutesVistosSiteStatus(contractRow) {
  if (!collectionRoutesSvozKaiserFieldConfirmed()) {
    return { label: "Čeká na Svoz Kaiser", tone: "waiting" };
  }
  if (contractRow.issueCount > 0) {
    return { label: "Zkontrolovat", tone: "warning" };
  }
  if (contractRow.onDemandItemCount > 0 && contractRow.onDemandItemCount === contractRow.itemCount) {
    return { label: "Na výzvu", tone: "waiting" };
  }
  return { label: "OK", tone: "ok" };
}

function collectionRoutesVistosContractExpanded(contractKey) {
  return collectionRoutesPilotState.kommunalExpandedContractKeys.includes(contractKey);
}

function toggleCollectionRoutesVistosContractDetail(contractKey) {
  if (!contractKey) {
    return;
  }
  const keys = collectionRoutesPilotState.kommunalExpandedContractKeys;
  if (keys.includes(contractKey)) {
    collectionRoutesPilotState.kommunalExpandedContractKeys = keys.filter((key) => key !== contractKey);
  } else {
    collectionRoutesPilotState.kommunalExpandedContractKeys = [...keys, contractKey];
  }
  render();
}

function collectionRoutesVistosContractDetailTable(contractRow) {
  return `
    <div class="collection-routes-site-detail-table" aria-label="Detail položek smlouvy ${escapeHtml(contractRow.contractNumber || "-")}">
      <table>
        <thead>
          <tr>
            <th>Od-do</th>
            <th>Adresní místo</th>
            <th>Stanoviště</th>
            <th>Odpad</th>
            <th>Nádoba</th>
            <th>Interval</th>
            <th>Den svozu</th>
            <th>Poznámka</th>
            <th>Zákaznický manažer</th>
          </tr>
        </thead>
        <tbody>
          ${contractRow.items.map((item) => `
            <tr class="${item.issueCount > 0 || item.issues.length ? "collection-routes-site-detail-item--danger" : ""}">
              <td class="${collectionRoutesDetailCellClass(item, "dateRange")}" data-label="Od-do">${escapeHtml(item.dateRange)}</td>
              <td class="${collectionRoutesDetailCellClass(item, "addressPlace")} ${item.addressPlaceMissing ? "collection-routes-site-detail-cell--danger" : ""}" data-label="Adresní místo">
                <strong>${escapeHtml(item.addressPlace)}</strong>
                ${item.addressPartsLabel ? `<span class="collection-routes-site-detail-subline">${escapeHtml(item.addressPartsLabel)}</span>` : ""}
              </td>
              <td data-label="Stanoviště">${escapeHtml(item.stationName || "-")}</td>
              <td class="${collectionRoutesDetailCellClass(item, "waste")}" data-label="Odpad">${escapeHtml(item.waste)}</td>
              <td class="${collectionRoutesDetailCellClass(item, "container")}" data-label="Nádoba">
                <strong>${escapeHtml(item.container)}</strong>
                ${item.containerEvidenceLabel ? `<span class="collection-routes-site-detail-subline">${escapeHtml(item.containerEvidenceLabel)}</span>` : ""}
              </td>
              <td class="${collectionRoutesDetailCellClass(item, "interval")}" data-label="Interval">${escapeHtml(item.interval)}</td>
              <td class="${collectionRoutesDetailCellClass(item, "pickupDays")}" data-label="Den svozu">${escapeHtml(item.pickupDays)}</td>
              <td data-label="Poznámka">${escapeHtml(item.note || "-")}</td>
              <td data-label="Zákaznický manažer">${escapeHtml(item.customerManagerContact || "-")}</td>
            </tr>
          `).join("")}
        </tbody>
      </table>
    </div>
  `;
}

function collectionRoutesVistosSitesTable(contractRows = collectionRoutesVistosFilteredContractRows()) {
  if (collectionRoutesPilotState.kommunalPairingLoading && !contractRows.length) {
    return collectionRoutesEmptyState(
      "Načítám uložený snapshot stanovišť.",
      "Běžné otevření čte D1 snapshot. Nový snapshot průběžně připravuje cloud runner."
    );
  }
  if (!contractRows.length) {
    return collectionRoutesEmptyState(
      collectionRoutesVistosSitesFilterValue("status") === "errors" ? "Žádné stanoviště s chybou." : "Zatím nejsou načtená Vistos stanoviště.",
      collectionRoutesVistosSitesFilterValue("status") === "errors"
        ? "V aktuálním snapshotu filtr nenašel chybová stanoviště."
        : "Počkej na nejbližší běh cloud runneru, který připravuje nový read-only snapshot."
    );
  }

  return `
    <div class="collection-routes-sites-table collection-routes-preview-table" role="region" aria-label="Řádkový seznam stanovišť z Vistosu">
      <table>
        <thead>
          <tr>
            <th>Stav</th>
            <th>Zákazník</th>
            <th>Smlouva</th>
            <th>Detail</th>
          </tr>
        </thead>
        <tbody>
          ${contractRows.map((contractRow) => {
            const status = collectionRoutesVistosSiteStatus(contractRow);
            const expanded = collectionRoutesVistosContractExpanded(contractRow.key);
            return `
              <tr class="collection-routes-site-contract-row ${contractRow.issueCount > 0 ? "collection-routes-site-contract-row--danger" : ""}">
                <td data-label="Stav">
                  <span class="collection-routes-site-status collection-routes-site-status--${escapeHtml(status.tone)}">${escapeHtml(status.label)}</span>
                </td>
                <td data-label="Zákazník">${escapeHtml(contractRow.customerName || "-")}</td>
                <td data-label="Smlouva">
                  <strong>${escapeHtml(contractRow.contractNumber || "-")}</strong>
                  <span>${escapeHtml(contractRow.itemCount)} položek · ${escapeHtml(contractRow.containerCount)} nádob</span>
                </td>
                <td data-label="Detail">
                  <button class="secondary-link collection-routes-site-detail-toggle" type="button" data-collection-routes-site-contract-detail="${escapeHtml(contractRow.key)}" aria-expanded="${expanded ? "true" : "false"}">
                    ${expanded ? "Skrýt detail" : "Detail"}
                  </button>
                </td>
              </tr>
              ${expanded ? `
                <tr class="collection-routes-site-detail-row">
                  <td class="collection-routes-site-detail-cell" colspan="4">
                    ${collectionRoutesVistosContractDetailTable(contractRow)}
                    ${contractRow.issueLabels.size ? `
                      <p class="collection-routes-site-detail-warning">Kontrola: ${escapeHtml(collectionRoutesTextList(contractRow.issueLabels, "bez blokace", 4))}</p>
                    ` : ""}
                  </td>
                </tr>
              ` : ""}
            `;
          }).join("")}
        </tbody>
      </table>
    </div>
  `;
}

function ensureCollectionRoutesSitesReadOnlyData(user = currentUser()) {
  scheduleCollectionRoutesSitesAutoRefresh(user);
  if (
    collectionRoutesCanLoadVistosSnapshot(user) &&
    !collectionRoutesPilotState.kommunalPairingRows.length &&
    !collectionRoutesPilotState.kommunalPairingLoading &&
    !collectionRoutesPilotState.kommunalPairingError &&
    !collectionRoutesPilotState.kommunalPairingLoadAttempted
  ) {
    collectionRoutesPilotState.kommunalPairingLoadAttempted = true;
    void Promise.resolve().then(() => loadCollectionRoutesKommunalPairingRows());
  }
}

function collectionRoutesSitesSection(user) {
  ensureCollectionRoutesSitesReadOnlyData(user);
  const contractRows = collectionRoutesVistosContractRows();
  const filteredContractRows = collectionRoutesVistosFilteredContractRows(contractRows);
  const stats = collectionRoutesVistosSitesStats(contractRows);
  const filterConfirmed = collectionRoutesSvozKaiserFieldConfirmed();
  const loadedAt = collectionRoutesPilotState.kommunalPairingLoadedAt ? formatDateTime(collectionRoutesPilotState.kommunalPairingLoadedAt) : "";
  const isLoadingVistosSites = collectionRoutesPilotState.kommunalPairingLoading;
  const loadingNotice = collectionRoutesPilotState.kommunalPairingLoading
    ? collectionRoutesPilotState.kommunalPairingRefreshMode === "live"
      ? "Načítám data z Vistosu a připravuji nový pracovní snapshot."
      : "Načítám uložený D1 snapshot. Nový read-only Vistos snapshot připravuje cloud runner každých 15 minut."
    : !loadedAt && !collectionRoutesPilotState.kommunalPairingError
      ? "Stanoviště se načtou z posledního uloženého snapshotu."
      : "";
  const sourceLabel = collectionRoutesSitesSourceLabel();
  return `
    <section class="collection-routes-panel" id="collection-routes-sites" aria-labelledby="collection-routes-sites-title">
      <div class="collection-routes-panel__head">
        <div>
          <p class="module-feedback__eyebrow">Stanoviště</p>
          <h2 id="collection-routes-sites-title">Stanoviště z Vistosu</h2>
          <p>Rychlý pracovní přehled z posledního D1 snapshotu. Cloud runner připravuje nový read-only Vistos snapshot každých 15 minut.</p>
        </div>
        <div class="collection-routes-panel__head-status">
          <span class="employee-card-status employee-card-status--${filterConfirmed ? "ready" : "waiting"}">${escapeHtml(isLoadingVistosSites ? collectionRoutesSitesRefreshLabel() : filterConfirmed ? "Svoz Kaiser filtr aktivní" : "čeká na Svoz Kaiser pole")}</span>
          ${collectionRoutesSitesRefreshStatusHtml()}
        </div>
      </div>
      ${loadingNotice ? `<p class="module-feedback__notice">${escapeHtml(loadingNotice)}</p>` : ""}
      <div class="collection-routes-stats collection-routes-sites-summary">
        <article><span>Zdroj</span><strong>${escapeHtml(sourceLabel)}</strong></article>
        <article><span>Stanoviště</span><strong>${escapeHtml(stats.siteCount)}</strong></article>
        <article><span>Položky</span><strong>${escapeHtml(stats.itemCount)}</strong></article>
        <article><span>Smlouvy</span><strong>${escapeHtml(stats.contractCount)}</strong></article>
        <article><span>Nádoby</span><strong>${escapeHtml(stats.containerCount)}</strong></article>
        <article class="collection-routes-stats__item--warning"><span>Svoz Kaiser ANO</span><strong>${escapeHtml(filterConfirmed ? "ověřeno" : "čeká")}</strong></article>
      </div>
      ${collectionRoutesVistosSitesFilterPanel(contractRows)}
      <div class="collection-routes-phase-note collection-routes-phase-note--warning">
        <strong>${escapeHtml(filterConfirmed ? "Seznam je filtrovaný podle potvrzeného Svoz Kaiser pravidla." : "Čeká se na potvrzení pole Svoz Kaiser ANO ve snapshotu.")}</strong>
        <span>${escapeHtml(filterConfirmed ? "Těžké Vistos načtení nespouštím při otevření stránky. Nový snapshot vytváří cloud runner bez ručního klikání." : "Pokud snapshot ještě nemá potvrzený filtr, počkej na nejbližší běh cloud runneru.")}</span>
      </div>
      ${loadedAt ? `<p class="module-feedback__notice">Načteno: ${escapeHtml(loadedAt)} · zdroj: ${escapeHtml(sourceLabel)} · zobrazeno ${escapeHtml(filteredContractRows.length)} / ${escapeHtml(contractRows.length)}</p>` : ""}
      ${collectionRoutesPilotState.kommunalPairingError ? `<p class="module-feedback__error">${escapeHtml(collectionRoutesPilotState.kommunalPairingError)}</p>` : ""}
      ${collectionRoutesVistosSitesTable(filteredContractRows)}
    </section>
  `;
}

function collectionRoutesLocationIssuesSection() {
  const issues = collectionRoutesPilotState.issues;
  return `
    <section class="collection-routes-panel" id="collection-routes-location-issues" aria-labelledby="collection-routes-location-issues-title">
      <div class="collection-routes-panel__head">
        <div>
          <p class="module-feedback__eyebrow">K doplnění polohy</p>
          <h2 id="collection-routes-location-issues-title">K doplnění polohy</h2>
          <p>Nejasné adresy a chybějící GPS se nesmí vydávat za pravdivou polohu.</p>
        </div>
      </div>
      ${issues.length ? `
        <div class="collection-routes-list">
          ${issues.map((issue) => `
            <article class="collection-routes-list-item">
              <div>
                <strong>${escapeHtml(issue.issueType || "data-quality")}</strong>
                <span>${escapeHtml(issue.severity || "info")} · ${escapeHtml(formatDateTime(issue.createdAt) || "-")}</span>
              </div>
              <p>${escapeHtml(issue.message || "Bez popisu problému.")}</p>
            </article>
          `).join("")}
        </div>
      ` : collectionRoutesEmptyState(
        "Žádné položky k doplnění polohy.",
        "Po reálném import preview se zde objeví nejasné adresy a stanoviště bez potvrzené polohy."
      )}
    </section>
  `;
}

function collectionRoutesSelectedSitePayload() {
  const detail = collectionRoutesPilotState.selectedSiteDetail;
  if (detail?.site) {
    return detail;
  }

  const site = collectionRoutesPilotState.sites.find((item) => item.id === collectionRoutesPilotState.selectedSiteId) ||
    collectionRoutesPilotState.sites[0] ||
    null;
  return site ? { site, services: [], containers: [], issues: [] } : null;
}

function collectionRoutesSiteDetailSection() {
  const payload = collectionRoutesSelectedSitePayload();
  if (!payload?.site) {
    return `
      <section class="collection-routes-panel" id="collection-routes-site-detail" aria-labelledby="collection-routes-site-detail-title">
        <div class="collection-routes-panel__head">
          <div>
            <p class="module-feedback__eyebrow">Detail</p>
            <h2 id="collection-routes-site-detail-title">Detail stanoviště</h2>
            <p>Detail se zobrazí po načtení reálného stanoviště z Vistos preview.</p>
          </div>
        </div>
        ${collectionRoutesEmptyState("Čeká na data.", "Žádné stanoviště zatím není dostupné.")}
      </section>
    `;
  }

  const { site, services = [], containers = [], issues = [] } = payload;
  return `
    <section class="collection-routes-panel" id="collection-routes-site-detail" aria-labelledby="collection-routes-site-detail-title">
      <div class="collection-routes-panel__head">
        <div>
          <p class="module-feedback__eyebrow">Detail</p>
          <h2 id="collection-routes-site-detail-title">Detail stanoviště</h2>
          <p>${escapeHtml(site.siteName || site.customerName || "Stanoviště")}</p>
        </div>
      </div>
      <div class="collection-routes-detail-grid">
        <article><span>Zákazník</span><strong>${escapeHtml(site.customerName || "-")}</strong></article>
        <article><span>Adresa</span><strong>${escapeHtml(site.addressText || "-")}</strong></article>
        <article><span>Kvalita polohy</span><strong>${escapeHtml(site.locationQuality || "missing")}</strong></article>
        <article><span>Služby</span><strong>${services.length}</strong></article>
        <article><span>Nádoby</span><strong>${containers.length}</strong></article>
        <article><span>Problémy</span><strong>${issues.length}</strong></article>
      </div>
    </section>
  `;
}

function collectionRoutesRulesSection(user) {
  ensureModuleRulesData(COLLECTION_ROUTES_MODULE_KEY);
  return moduleRulesAutomationPanel({
    moduleKey: COLLECTION_ROUTES_MODULE_KEY,
    moduleName: "Trasy svozu",
    user,
    description: "Read-only pilot pravidel a automatizací modulu Trasy svozu. Nejde o ostré cloud automatizace pro svoz.",
    cloudNote: "Fáze 1A pouze čte evidenci pravidel. Nevzniká žádný runner, cron ani queue pro Trasy svozu.",
    readOnly: true
  });
}

function collectionRoutesSettingsSection() {
  return `
    <section class="collection-routes-internal" id="collection-routes-settings" aria-labelledby="collection-routes-settings-title">
      <div class="collection-routes-internal__head">
        <div>
          <p class="module-feedback__eyebrow">Nastavení modulu</p>
          <h2 id="collection-routes-settings-title">Nastavení</h2>
          <p>Provozní stav Tras svozu bez technických detailů v hlavním pracovním pohledu.</p>
        </div>
        <span class="employee-card-status employee-card-status--waiting">Log událostí</span>
      </div>
      ${moduleEventLogForModule({ id: COLLECTION_ROUTES_MODULE_KEY, title: "Trasy svozu", route: COLLECTION_ROUTES_ROUTE, status: "Řízený online pilot" })}
    </section>
  `;
}

function collectionRoutesInternalSection(user) {
  return `
    <section class="collection-routes-internal" id="collection-routes-internal" aria-labelledby="collection-routes-internal-title">
      <div class="collection-routes-internal__head">
        <div>
          <p class="module-feedback__eyebrow">Admin / interní správa</p>
          <h2 id="collection-routes-internal-title">Interní správa svozových tras</h2>
          <p>Importy, diagnostika, Vistos-only pilot a technické kontroly jsou mimo hlavní pracovní záložku.</p>
        </div>
        <span class="employee-card-status employee-card-status--waiting">read-only / admin</span>
      </div>
      <div class="collection-routes-internal__links" aria-label="Rychlá interní navigace">
        <a href="#collection-routes-source-data">Zdroj 13 Excelů</a>
        <a href="#collection-routes-vistos-komunal">Vistos-only pilot</a>
        <a href="#collection-routes-location-issues">Poloha</a>
        <a href="#collection-routes-manual-import">Import preview</a>
      </div>
      <div class="collection-routes-phase-note">
        <strong>Interní správa nevytváří ostré trasy.</strong>
        <span>Slouží pro import, read-only párování a kontrolu dat. Běžná práce řidiče/dispečera zůstává v záložce Svozové trasy.</span>
      </div>
    </section>

    <details class="collection-routes-internal-group" open>
      <summary>
        <span>Stav modulu</span>
        <small>read-only souhrn, ostré trasy NE</small>
      </summary>
      ${collectionRoutesDashboardSection()}
    </details>

    <details class="collection-routes-internal-group" open>
      <summary>
        <span>Zdroj 13 Excelů</span>
        <small>import, filtry, Vistos match, řádky k opravě</small>
      </summary>
      ${collectionRoutesSourceDataSection(user)}
    </details>

    <details class="collection-routes-internal-group">
      <summary>
        <span>Vistos-only pilot a historická kalibrace</span>
        <small>samostatný Vistos náhled, ne pracovní trasa z 13 Excelů</small>
      </summary>
      ${collectionRoutesVistosKommunalSection(user)}
    </details>

    <details class="collection-routes-internal-group">
      <summary>
        <span>Poloha a staré import preview</span>
        <small>nejasné adresy, ruční JSON/CSV a Vistos API discovery</small>
      </summary>
      ${collectionRoutesLocationIssuesSection()}
      ${collectionRoutesManualImportSection(user)}
      ${collectionRoutesImportSection(user)}
    </details>
  `;
}

function collectionRoutesActiveSection(user) {
  const activeTab = activeCollectionRoutesTabId();
  if (activeTab === "svozove-trasy") {
    return collectionRoutesSourceRoutesSection(user);
  }
  if (activeTab === "sites") {
    return `${collectionRoutesSitesSection(user)}${collectionRoutesPilotState.selectedSiteId ? collectionRoutesSiteDetailSection() : ""}`;
  }
  if (activeTab === "rules") {
    return collectionRoutesRulesSection(user);
  }
  if (activeTab === "settings") {
    return collectionRoutesSettingsSection();
  }
  if (activeTab === "internal") {
    return collectionRoutesInternalSection(user);
  }
  return collectionRoutesSourceRoutesSection(user);
}

function collectionRoutesModulePage(moduleItem, user, isDashboard = false) {
  if (normalizeRole(user?.role) === "ridic") {
    return collectionDailyRouteDriverPage(moduleItem, user);
  }
  if (!collectionRoutesCanViewPilot(user)) {
    return forbiddenPage(user);
  }

  const title = isDashboard ? "Dashboard Trasy svozu" : "Trasy svozu";
  let activeTab = activeCollectionRoutesTabId();
  const visibleTabs = collectionRoutesVisibleTabs(user);
  if (!visibleTabs.some((tab) => tab.id === activeTab)) {
    activeTab = "svozove-trasy";
    collectionRoutesPilotState.activeTab = activeTab;
  }
  const isSourceRoutesTab = activeTab === "svozove-trasy";
  return `
    <main class="app-shell module-page module-theme-scope collection-routes-page ui-system-pilot ui-system-pilot--routes" ${moduleThemeStyleAttribute()}>
      ${uiSystemPilotSidebar(user, "collection-routes")}
      <div class="ui-pilot-toolbar">
        <nav class="topbar" aria-label="Navigace">
          <a class="back-button" href="${routeHref("/")}" data-link>Zpět na HP</a>
        </nav>
        ${userBar(user)}
      </div>

      <section class="module-detail collection-routes-hero ui-pilot-hero ui-pilot-module-hero" aria-labelledby="collection-routes-title">
        <div class="module-detail__icon">${renderModuleIcon(moduleItem)}</div>
        <div class="module-detail__body">
          <div class="module-detail__eyebrow">SMART ODPADY / TRASY SVOZU</div>
          <h1 id="collection-routes-title">${escapeHtml(title)}</h1>
          <p>${isSourceRoutesTab ? "Denní trasy, filtry, tiskové podklady a řidičský náhled v jednom pracovním toku." : "Správa kontrol a read-only mapování pro svozové trasy."}</p>
          <div class="ui-pilot-chip-row" aria-label="Provozní stav modulu">
            <span class="ui-pilot-chip ui-pilot-chip--active">Uložené denní trasy</span>
            <span class="ui-pilot-chip">Ruční potvrzení dispečerem</span>
            <span class="ui-pilot-chip">Bez zápisu do Vistosu</span>
          </div>
          <div class="module-detail__status">
            <span>Stav</span>
            <strong>Řízený provozní pilot</strong>
          </div>
        </div>
        <div class="ui-pilot-hero__icon" aria-hidden="true">${renderModuleIcon(moduleItem)}</div>
      </section>

      <nav class="collection-routes-tabs" aria-label="Sekce Tras svozu" role="tablist">
        ${visibleTabs.map((tab) => `
          <button
            class="collection-routes-tab ${tab.adminOnly ? "collection-routes-tab--admin" : ""} ${tab.id === activeTab ? "collection-routes-tab--active" : ""}"
            type="button"
            role="tab"
            aria-selected="${tab.id === activeTab ? "true" : "false"}"
            data-collection-routes-tab="${escapeHtml(tab.id)}"
          >
            ${escapeHtml(tab.label)}
          </button>
        `).join("")}
      </nav>

      ${collectionRoutesPilotState.loading ? `<p class="module-feedback__notice">Načítám pilotní data z API...</p>` : ""}
      ${collectionRoutesActiveSection(user)}
    </main>
  `;
}

function dataBoxPlusSearchText(parts) {
  return parts
    .filter((part) => part !== null && part !== undefined)
    .join(" ")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();
}

function dataBoxPlusHumanError(message) {
  const text = String(message || "").trim();
  if (!text) return "";
  const normalized = dataBoxPlusSearchText([text]);
  if (normalized.includes("d1") || normalized.includes("tabulk") || normalized.includes("migraci")) {
    return "Ostré úložiště Datových schránek Plus ještě není připravené. Po dokončení nasazení se zprávy začnou načítat samy.";
  }
  if (normalized.includes("opravnen") || normalized.includes("prihlas")) {
    return "Pro načtení Datových schránek Plus je potřeba platné přihlášení a oprávnění k modulu.";
  }
  return text;
}

function dataBoxPlusMailboxes() {
  return Array.isArray(dataBoxPlusState.mailboxes) ? dataBoxPlusState.mailboxes : [];
}

function dataBoxPlusMessages() {
  return Array.isArray(dataBoxPlusState.messages) ? dataBoxPlusState.messages : [];
}

function dataBoxPlusIsUnresolvedMessage(message) {
  const state = dataBoxPlusSearchText([dataBoxPlusMessageWorkflow(message).state]);
  return !["archivovano", "vyreseno", "odeslano e-mailem", "odeslano emailem"].includes(state);
}

function dataBoxPlusRecommendations({ includeClosed = false } = {}) {
  const recommendations = Array.isArray(dataBoxPlusState.recommendations) ? dataBoxPlusState.recommendations : [];
  if (includeClosed) return recommendations;
  return recommendations.filter((item) => item.status !== "confirmed" && item.status !== "rejected");
}

function dataBoxPlusRules() {
  return Array.isArray(dataBoxPlusState.rules) ? dataBoxPlusState.rules : [];
}

function dataBoxPlusInstructionPlan(item = {}) {
  return item?.instructionPlan || null;
}

function dataBoxPlusIsInstructionRecommendation(item = {}) {
  return Boolean(dataBoxPlusInstructionPlan(item)?.userInstruction);
}

function dataBoxPlusAutopilotDoneItems() {
  const executedCount = dataBoxPlusMessages()
    .filter((message) => Array.isArray(message.history) && message.history.some((event) => {
      const isChatInstruction = dataBoxPlusSearchText([event.actionType]).includes("chatovy pokyn");
      const result = String(event.result || event.payload?.outcome || "").trim().toLowerCase();
      return isChatInstruction && (result === "done" || result === "sent");
    }))
    .length;
  if (executedCount > 0) {
    return [`Autopilot provedl ${executedCount} chatových pokynů a každý zapsal do historie.`];
  }
  const lastSync = dataBoxPlusState.syncRuns?.[0];
  if (lastSync?.messagesDownloaded) {
    return [`Autopilot načetl ${lastSync.messagesDownloaded} zpráv a připravil je k vyřízení.`];
  }
  return ["Autopilot čeká na první pokyn v chatu."];
}

function dataBoxPlusLastSyncTimeMs() {
  const lastSync = dataBoxPlusState.syncRuns?.[0];
  const value = lastSync?.finishedAt || lastSync?.startedAt || "";
  const timestamp = Date.parse(value);
  return Number.isFinite(timestamp) ? timestamp : 0;
}

function dataBoxPlusNextSyncInfo(now = Date.now()) {
  const lastSyncTime = dataBoxPlusLastSyncTimeMs();
  if (!lastSyncTime) {
    return {
      label: "Čekám na první načtení",
      note: "Jakmile proběhne první automatické načtení, uvidíš přesný odpočet.",
      nextAt: 0
    };
  }

  let nextAt = lastSyncTime + DATA_BOX_PLUS_SYNC_INTERVAL_MS;
  while (nextAt <= now) {
    nextAt += DATA_BOX_PLUS_SYNC_INTERVAL_MS;
  }
  const remainingMs = Math.max(0, nextAt - now);
  const minutes = String(Math.floor(remainingMs / 60000)).padStart(2, "0");
  const seconds = String(Math.floor((remainingMs % 60000) / 1000)).padStart(2, "0");
  return {
    label: `${minutes}:${seconds}`,
    note: `Poslední načtení: ${formatDateTime(lastSyncTime)}.`,
    nextAt
  };
}

function dataBoxPlusCountdownBlock() {
  const info = dataBoxPlusNextSyncInfo();
  return `
    <div class="ds-plus-sync-countdown" data-ds-plus-countdown data-next-sync-at="${escapeHtml(info.nextAt || "")}">
      <span>Další načtení</span>
      <strong data-ds-plus-countdown-value>${escapeHtml(info.label)}</strong>
      <small data-ds-plus-countdown-note>${escapeHtml(info.note)}</small>
    </div>
  `;
}

function dataBoxPlusLearningStage() {
  const learning = dataBoxPlusState.learning || {};
  const confirmed = Number(learning.confirmedDecisions || 0) || 0;
  if (confirmed >= 120) {
    return {
      label: "Velmi vysoký",
      percent: 92,
      text: "Autopilot spolehlivě provádí rutinní chatové pokyny a chybějící údaje si umí vyžádat konkrétně."
    };
  }
  if (confirmed >= 60) {
    return {
      label: "Vysoký",
      percent: 74,
      text: "Autopilot má ověřené vzory pro běžné zprávy a výsledek zapíše až po potvrzení člověka."
    };
  }
  if (confirmed >= 20) {
    return {
      label: "Střední",
      percent: 48,
      text: "Autopilot rozpoznává opakované vzory a potvrzené pokyny z chatu provádí přes backend."
    };
  }
  return {
    label: "Nízký",
    percent: Math.max(8, Math.min(30, confirmed * 2)),
    text: "Autopilot se učí z pokynů a zastaví se jen při chybějícím údaji."
  };
}

function dataBoxPlusLearningBlock() {
  const learning = dataBoxPlusState.learning || {};
  const stage = dataBoxPlusLearningStage();
  return `
    <div class="ds-plus-learning-status" aria-label="Stav učení Autopilota">
      <span>Stav učení</span>
      <div class="ds-plus-learning-status__bar" aria-hidden="true"><i style="width: ${escapeHtml(stage.percent)}%"></i></div>
      <dl class="ds-plus-learning-status__metrics">
        <div><dt>Stav učení</dt><dd>${escapeHtml(stage.label)}</dd></div>
        <div><dt>Rozhodnutí</dt><dd>${escapeHtml(Number(learning.confirmedDecisions || 0))}</dd></div>
        <div><dt>Vzory</dt><dd>${escapeHtml(Number(learning.learnedPatterns || 0))}</dd></div>
      </dl>
      <p>Učí se z pokynů.</p>
    </div>
  `;
}

function dataBoxPlusModelFlag() {
  return `
    <span class="ds-plus-model-flag" title="${escapeHtml(DATA_BOX_PLUS_MODEL_FLAG.detail)}">
      ${escapeHtml(DATA_BOX_PLUS_MODEL_FLAG.label)}
    </span>
  `;
}

function updateDataBoxPlusCountdownNodes() {
  document.querySelectorAll("[data-ds-plus-countdown]").forEach((node) => {
    const valueNode = node.querySelector("[data-ds-plus-countdown-value]");
    const noteNode = node.querySelector("[data-ds-plus-countdown-note]");
    const info = dataBoxPlusNextSyncInfo();
    node.dataset.nextSyncAt = info.nextAt ? String(info.nextAt) : "";
    if (valueNode) valueNode.textContent = info.label;
    if (noteNode) noteNode.textContent = info.note;
  });
}

function ensureDataBoxPlusCountdownTimer() {
  if (dataBoxPlusCountdownTimer) return;
  dataBoxPlusCountdownTimer = window.setInterval(updateDataBoxPlusCountdownNodes, 1000);
}

function dataBoxPlusMailbox(messageOrMailboxId) {
  const mailboxId = typeof messageOrMailboxId === "object"
    ? messageOrMailboxId.mailboxId
    : messageOrMailboxId;
  return dataBoxPlusMailboxes().find((mailbox) => mailbox.id === mailboxId) || null;
}

function dataBoxPlusMessageById(messageId) {
  return dataBoxPlusMessages().find((message) => message.id === String(messageId || "")) || null;
}

function restoreDataBoxPlusInputFocus(selector, start, end) {
  window.requestAnimationFrame(() => {
    const input = document.querySelector(selector);
    if (!input) {
      return;
    }
    input.focus({ preventScroll: true });
    if (typeof input.setSelectionRange === "function") {
      input.setSelectionRange(Number.isFinite(start) ? start : input.value.length, Number.isFinite(end) ? end : input.value.length);
    }
  });
}

function dataBoxPlusSelectedMessage() {
  return dataBoxPlusMessageById(dataBoxPlusState.selectedMessageId) || null;
}

function dataBoxPlusTone(value) {
  const normalized = dataBoxPlusSearchText([value]);
  if (normalized.includes("vysoke") || normalized.includes("urgent") || normalized.includes("problem")) return "danger";
  if (normalized.includes("pravni") || normalized.includes("exekuce") || normalized.includes("legal")) return "legal";
  if (normalized.includes("stredni") || normalized.includes("ceka") || normalized.includes("uci")) return "warning";
  if (normalized.includes("nizke") || normalized.includes("archiv") || normalized.includes("spolehlive")) return "quiet";
  if (normalized.includes("aktivni") || normalized.includes("text nacteny")) return "success";
  return "neutral";
}

function dataBoxPlusIsDueToday(message) {
  const workflow = dataBoxPlusMessageWorkflow(message);
  return ["Nová", "Potřebuje pokyn", "Potřebuje upřesnit", "Potřebuje adresáta", "Chybí vozidlo", "Chybí příloha", "Nelze provést"].includes(workflow.state);
}

function dataBoxPlusBadge(label, tone = "neutral") {
  return `<span class="ds-plus-badge ds-plus-badge--${escapeHtml(tone)}">${escapeHtml(label)}</span>`;
}

function dataBoxPlusOpenRecommendationForMessage(message) {
  const messageId = String(message?.id || "");
  if (!messageId) return null;
  return dataBoxPlusRecommendations().find((item) => (
    item.messageId === messageId
    && dataBoxPlusIsInstructionRecommendation(item)
    && item.status !== "confirmed"
    && item.status !== "rejected"
    && !dataBoxPlusState.confirmedRecommendationIds.includes(item.id)
    && !dataBoxPlusState.dismissedRecommendationIds.includes(item.id)
  )) || null;
}

function dataBoxPlusWorkflowTone(state = "") {
  const normalized = dataBoxPlusSearchText([state]);
  if (normalized.includes("problem") || normalized.includes("nelze") || normalized.includes("chybi")) return "problem";
  if (normalized.includes("archiv")) return "archive";
  if (normalized.includes("vyreseno") || normalized.includes("odeslano") || normalized.includes("nevyrizene")) return "resolved";
  if (normalized.includes("predano")) return "handoff";
  if (normalized.includes("upresnit") || normalized.includes("adresata") || normalized.includes("rucni") || normalized.includes("pokyn")) return "waiting";
  if (normalized.includes("nova")) return "new";
  return "neutral";
}

function dataBoxPlusWorkflowAction({ label, messageId, variant = "secondary-link", attrs = "", help = "" }) {
  const safeMessageId = escapeHtml(messageId || "");
  return {
    label,
    variant,
    attrs: attrs || `data-ds-plus-open="${safeMessageId}"`,
    help
  };
}

function dataBoxPlusRenderWorkflowAction(action) {
  if (!action?.label) return "";
  return dataBoxPlusActionButton({
    label: action.label,
    variant: action.variant || "secondary-link",
    attrs: action.attrs || "",
    help: action.help || dataBoxPlusActionHelpText(action.label)
  });
}

function dataBoxPlusOverviewNextStep(message, workflow) {
  const normalized = dataBoxPlusSearchText([
    message?.senderName,
    message?.subject,
    message?.type,
    message?.recommendedAction,
    message?.suggestedAction,
    workflow?.result,
    workflow?.nextStep
  ]);
  if (workflow?.closed) return "Bez další akce.";
  if (workflow?.state === "Chybí příloha") return "Otevřít přílohu";
  if (workflow?.state === "Chybí vozidlo") return "Vybrat vozidlo";
  if (workflow?.state === "Potřebuje adresáta") return "Vybrat adresáta";
  if (workflow?.state === "Potřebuje upřesnit") return "Upřesnit pokyn";
  if (workflow?.state === "Nelze provést") return "Zkusit znovu";
  if (workflow?.state === "Předáno fakturám") return "Čeká na účetní";
  if (workflow?.state === "Předáno mzdové účetní") return "Čeká na mzdovou účetní";
  if (workflow?.state === "Předáno garážmistrovi") return "Čeká na garážmistra";
  if (normalized.includes("faktur") || normalized.includes("upom")) return "Pravděpodobně faktura.";
  if (normalized.includes("stk") || normalized.includes("vozid") || normalized.includes("technick")) return "Ověřit termín STK.";
  if (dataBoxPlusIsCsszPayrollMessage({}, message)) return "Uložit k evidenci.";
  return "Potřebuje pokyn.";
}

function dataBoxPlusOverviewAction(message, workflow) {
  const messageId = message?.id || "";
  if (workflow?.state === "Potřebuje adresáta") {
    return dataBoxPlusWorkflowAction({
      label: "Vybrat adresáta",
      messageId,
      variant: "primary-action",
      help: "Otevře se detail zprávy a výběr adresáta pro e-mail."
    });
  }
  if (workflow?.state === "Potřebuje upřesnit") {
    return dataBoxPlusWorkflowAction({
      label: "Upřesnit pokyn",
      messageId,
      variant: "primary-action",
      help: "Otevře se chat, kde doplníš přesnější pokyn."
    });
  }
  if (workflow?.state === "Chybí vozidlo") {
    return dataBoxPlusWorkflowAction({
      label: "Vybrat vozidlo",
      messageId,
      variant: "primary-action",
      help: "Otevře se zpráva pro doplnění vazby na vozidlo."
    });
  }
  if (workflow?.state === "Chybí příloha") {
    return dataBoxPlusWorkflowAction({
      label: "Otevřít přílohu",
      messageId,
      variant: "primary-action",
      help: "Otevře se dostupná příloha nebo detail chyby přílohy."
    });
  }
  if (workflow?.state === "Nelze provést") {
    return dataBoxPlusWorkflowAction({
      label: "Zkusit znovu",
      messageId,
      variant: "primary-action",
      help: "Otevře se detail zprávy pro nový pokus."
    });
  }
  if (workflow?.closed || dataBoxPlusSearchText([workflow?.state]).includes("predano")) {
    return dataBoxPlusWorkflowAction({
      label: "Detail historie",
      messageId,
      variant: "secondary-link",
      help: "Otevře se detail a historie zprávy. Nic se tím nemění ani neodesílá."
    });
  }
  return dataBoxPlusWorkflowAction({
    label: "Otevřít",
    messageId,
    variant: "primary-action",
    help: "Otevře se detail zprávy. Stav se tím nezmění a nic se neodešle mimo systém."
  });
}

function dataBoxPlusCompactWorkflow(workflow, nextStep) {
  return `
    <div class="ds-plus-compact-workflow" aria-label="Stav a další krok">
      <span class="ds-plus-work-state ds-plus-work-state--${escapeHtml(workflow.tone)}">${escapeHtml(workflow.stateLabel || workflow.state)}</span>
      <span class="ds-plus-compact-workflow__next">${escapeHtml(nextStep)}</span>
    </div>
  `;
}

function dataBoxPlusRecipientText(value = "") {
  const normalized = dataBoxPlusSearchText([value]);
  if (normalized.includes("mzd")) return "mzdové účetní";
  if (normalized.includes("faktur")) return "účetnímu oddělení";
  if (normalized.includes("pravnik") || normalized.includes("gt brno")) return "právníkovi nebo GT Brno";
  if (normalized.includes("garaz")) return "garážmistrovi";
  return String(value || "odpovědné osobě").trim();
}

function dataBoxPlusPreparedSummary(action = {}) {
  const normalized = dataBoxPlusSearchText([action.type, action.prepared, action.confirmLabel]);
  if (normalized.includes("archive")) return "archivaci zprávy";
  if (normalized.includes("email") || normalized.includes("e-mail")) return "odeslání e-mailu nebo výběr adresáta";
  if (normalized.includes("deadline") || normalized.includes("lhut")) return "zapsání lhůty";
  if (normalized.includes("assignment") || normalized.includes("priraz")) return "přiřazení odpovědné osobě";
  if (normalized.includes("handoff") || normalized.includes("predan")) return `předání ${action.recipient ? dataBoxPlusRecipientText(action.recipient) : "odpovědné osobě"}`;
  if (normalized.includes("payroll_record")) return "uložení potvrzení ČSSZ k evidenci";
  return String(action.prepared || "konkrétní akci").replace(/\.$/, "").toLocaleLowerCase("cs-CZ");
}

function dataBoxPlusArchiveResult(message) {
  const normalized = dataBoxPlusSearchText([message.senderName, message.subject, message.type, message.recommendedAction, message.suggestedAction]);
  if (dataBoxPlusIsCsszPayrollMessage({}, message) && normalized.includes("prijat")) {
    return "Podání bylo přijato ČSSZ.";
  }
  if (normalized.includes("registr smluv")) {
    return "Informační zpráva z Registru smluv byla uložena do archivu.";
  }
  if (normalized.includes("informativ")) {
    return "Informační zpráva byla uložena do archivu.";
  }
  return "Zpráva byla uložena do archivu jako vyřízená nebo informativní.";
}

function dataBoxPlusMessageWorkflow(message, options = {}) {
  const recommendation = Object.prototype.hasOwnProperty.call(options, "recommendation")
    ? options.recommendation
    : dataBoxPlusOpenRecommendationForMessage(message);
  const preparedAction = Object.prototype.hasOwnProperty.call(options, "preparedAction")
    ? options.preparedAction
    : recommendation
      ? dataBoxPlusPreparedAction(recommendation)
      : null;
  const normalized = dataBoxPlusSearchText([
    message?.status,
    message?.archiveStatus,
    message?.attachmentStatus,
    message?.riskLevel,
    message?.recommendedAction,
    message?.subject,
    message?.type
  ]);
  const messageId = message?.id || recommendation?.messageId || "";
  const openAction = dataBoxPlusWorkflowAction({
    label: "Otevřít zprávu",
    messageId,
    variant: "primary-action",
    help: "Otevře se detail zprávy pro ruční rozhodnutí. Stav zprávy se tím nezmění a nic se neodešle mimo systém."
  });
  const detailAction = dataBoxPlusWorkflowAction({
    label: "Detail historie",
    messageId,
    variant: "secondary-link",
    help: "Otevře se detail zprávy včetně historie a příloh. Nic se tím nemění ani neodesílá."
  });

  if (preparedAction && recommendation) {
    return {
      state: "Potřebuje pokyn",
      stateLabel: "Potřebuje pokyn",
      result: "Autopilot čeká na jasný chatový pokyn.",
      nextStep: "Chat s Autopilotem",
      primaryAction: dataBoxPlusWorkflowAction({
        label: "Chat s Autopilotem",
        variant: "primary-action",
        attrs: `data-ds-plus-chat="${escapeHtml(messageId)}"`,
        help: "Otevře se chat. Autopilot pokyn shrne a provede ho až po vašem souhlasu."
      }),
      secondaryActions: [
        dataBoxPlusWorkflowAction({ label: "Detail historie", messageId, help: "Otevře se detail zprávy a historie." })
      ],
      tone: dataBoxPlusWorkflowTone("Potřebuje pokyn"),
      risk: preparedAction.risk || message?.riskLevel || "Střední",
      closed: false
    };
  }

  if (normalized.includes("nepodarilo") || normalized.includes("problem")) {
    return {
      state: normalized.includes("priloha") ? "Chybí příloha" : "Nelze provést",
      stateLabel: normalized.includes("priloha") ? "Chybí příloha" : "Nelze provést",
      result: normalized.includes("priloha") ? "Přílohu se nepodařilo načíst." : "Zpráva má problém, který potřebuje člověka.",
      nextStep: normalized.includes("priloha") ? "Otevřít přílohu" : "Zkusit znovu",
      primaryAction: openAction,
      secondaryActions: [],
      tone: dataBoxPlusWorkflowTone(normalized.includes("priloha") ? "Chybí příloha" : "Nelze provést"),
      risk: message?.riskLevel || "Střední",
      closed: false
    };
  }

  if (normalized.includes("potrebuje adresata")) {
    return {
      state: "Potřebuje adresáta",
      stateLabel: "Potřebuje adresáta",
      result: message?.recommendedAction || "Adresát není jasný.",
      nextStep: "Vybrat adresáta",
      primaryAction: dataBoxPlusWorkflowAction({ label: "Vybrat adresáta", messageId, variant: "primary-action", help: "Vyber adresáta pro e-mail." }),
      secondaryActions: [detailAction],
      tone: dataBoxPlusWorkflowTone("Potřebuje adresáta"),
      risk: message?.riskLevel || "Běžné",
      closed: false
    };
  }

  if (normalized.includes("potrebuje upresnit")) {
    return {
      state: "Potřebuje upřesnit",
      stateLabel: "Potřebuje upřesnit",
      result: message?.recommendedAction || "Pokyn není jasný.",
      nextStep: "Upřesnit pokyn",
      primaryAction: dataBoxPlusWorkflowAction({ label: "Upřesnit pokyn", messageId, variant: "primary-action", help: "Doplň přesnější pokyn v chatu." }),
      secondaryActions: [detailAction],
      tone: dataBoxPlusWorkflowTone("Potřebuje upřesnit"),
      risk: message?.riskLevel || "Běžné",
      closed: false
    };
  }

  if (normalized.includes("chybi vozidlo")) {
    return {
      state: "Chybí vozidlo",
      stateLabel: "Chybí vozidlo",
      result: message?.recommendedAction || "Chybí vazba na vozidlo.",
      nextStep: "Vybrat vozidlo",
      primaryAction: dataBoxPlusWorkflowAction({ label: "Vybrat vozidlo", messageId, variant: "primary-action", help: "Doplň vozidlo pro zápis." }),
      secondaryActions: [detailAction],
      tone: dataBoxPlusWorkflowTone("Chybí vozidlo"),
      risk: message?.riskLevel || "Běžné",
      closed: false
    };
  }

  if (normalized.includes("archivovan") || normalized.includes("archived")) {
    const csszResolved = dataBoxPlusIsCsszPayrollMessage({}, message) && dataBoxPlusSearchText([message?.subject, message?.recommendedAction]).includes("prijat");
    if (csszResolved) {
      return {
      state: "Vyřešeno",
      stateLabel: "Vyřešeno",
      result: "Podání bylo přijato ČSSZ.",
      nextStep: "Bez další akce.",
      primaryAction: detailAction,
      secondaryActions: [dataBoxPlusWorkflowAction({ label: "Vrátit zpět", messageId, help: "Otevře detail zprávy pro případnou změnu stavu." })],
        tone: dataBoxPlusWorkflowTone("Vyřešeno"),
        risk: dataBoxPlusCsszPayrollRisk({}, message),
        closed: true
      };
    }
    return {
      state: "Archivováno",
      stateLabel: "Archivováno",
      result: dataBoxPlusArchiveResult(message),
      nextStep: "Bez další akce.",
      primaryAction: detailAction,
      secondaryActions: [dataBoxPlusWorkflowAction({ label: "Vrátit zpět", messageId, help: "Otevře detail zprávy pro případnou změnu stavu." })],
      tone: dataBoxPlusWorkflowTone("Archivováno"),
      risk: message?.riskLevel || "Nízké",
      closed: true
    };
  }

  if (normalized.includes("vyreseno")) {
    return {
      state: "Vyřešeno",
      stateLabel: "Vyřešeno",
      result: message?.recommendedAction || "Zpráva byla zpracovaná.",
      nextStep: "Bez další akce.",
      primaryAction: detailAction,
      secondaryActions: [dataBoxPlusWorkflowAction({ label: "Vrátit zpět", messageId, help: "Otevře detail zprávy pro případnou změnu stavu." })],
      tone: dataBoxPlusWorkflowTone("Vyřešeno"),
      risk: message?.riskLevel || "Běžné",
      closed: true
    };
  }

  if (normalized.includes("odeslano e-mailem")) {
    const recipient = message?.assignedTo || message?.recommendedAction || "";
    return {
      state: "Odesláno e-mailem",
      stateLabel: "Odesláno e-mailem",
      result: recipient ? `Odesláno na ${recipient}.` : "E-mail byl odeslán.",
      nextStep: "Bez další akce.",
      primaryAction: detailAction,
      secondaryActions: [dataBoxPlusWorkflowAction({ label: "Vrátit zpět", messageId, help: "Otevře detail zprávy pro případnou změnu stavu." })],
      tone: dataBoxPlusWorkflowTone("Odesláno e-mailem"),
      risk: message?.riskLevel || "Běžné",
      closed: true
    };
  }

  if (normalized.includes("nevyrizene")) {
    return {
      state: "Nevyřízené",
      stateLabel: "Nevyřízené",
      result: message?.recommendedAction || "Zpráva zůstává nevyřízená.",
      nextStep: "Bez další akce.",
      primaryAction: detailAction,
      secondaryActions: [dataBoxPlusWorkflowAction({ label: "Vrátit zpět", messageId, help: "Otevře detail zprávy pro případnou změnu stavu." })],
      tone: dataBoxPlusWorkflowTone("Nevyřízené"),
      risk: message?.riskLevel || "Běžné",
      closed: true
    };
  }

  if (message?.assignedTo || normalized.includes("predano")) {
    const recipient = dataBoxPlusRecipientText(message?.assignedTo || message?.recommendedAction || "odpovědné osobě");
    const state = normalized.includes("predano fakturam")
      ? "Předáno fakturám"
      : normalized.includes("predano mzdove ucetni")
        ? "Předáno mzdové účetní"
        : normalized.includes("predano garazmistrovi")
          ? "Předáno garážmistrovi"
          : "Předáno fakturám";
    const nextStep = state === "Předáno fakturám"
      ? "Čeká na účetní"
      : state === "Předáno mzdové účetní"
        ? "Čeká na mzdovou účetní"
        : "Čeká na garážmistra";
    return {
      state,
      stateLabel: state,
      result: `Předáno ${recipient}.`,
      nextStep,
      primaryAction: detailAction,
      secondaryActions: [dataBoxPlusWorkflowAction({ label: "Vrátit zpět", messageId, help: "Otevře detail zprávy pro případnou změnu stavu." })],
      tone: dataBoxPlusWorkflowTone(state),
      risk: message?.riskLevel || "Střední",
      closed: false
    };
  }

  if (recommendation && !preparedAction) {
    return {
      state: "Potřebuje pokyn",
      stateLabel: "Potřebuje pokyn",
      result: "Nezpracováno.",
      nextStep: "Chat s Autopilotem",
      primaryAction: openAction,
      secondaryActions: [
        dataBoxPlusWorkflowAction({ label: "Detail historie", messageId, help: dataBoxPlusActionHelpText("Historie") })
      ],
      tone: dataBoxPlusWorkflowTone("Potřebuje pokyn"),
      risk: message?.riskLevel || "Běžné",
      closed: false
    };
  }

  if (normalized.includes("dnes k vyrizeni") || normalized.includes("vysoke") || normalized.includes("urgent")) {
    return {
      state: "Potřebuje pokyn",
      stateLabel: "Potřebuje pokyn",
      result: "Zpráva čeká na chatový pokyn.",
      nextStep: "Chat s Autopilotem",
      primaryAction: openAction,
      secondaryActions: [],
      tone: dataBoxPlusWorkflowTone("Potřebuje pokyn"),
      risk: message?.riskLevel || "Střední",
      closed: false
    };
  }

  return {
    state: "Nová",
    stateLabel: "Nová",
    result: "Nezpracováno.",
    nextStep: "Potřebuje pokyn.",
    primaryAction: openAction,
    secondaryActions: [],
    tone: dataBoxPlusWorkflowTone("Nová"),
    risk: message?.riskLevel || "Běžné",
    closed: false
  };
}

function dataBoxPlusWorkflowSummary(workflow) {
  return `
    <dl class="ds-plus-workflow-summary">
      <div>
        <dt>Stav</dt>
        <dd><span class="ds-plus-work-state ds-plus-work-state--${escapeHtml(workflow.tone)}">${escapeHtml(workflow.stateLabel || workflow.state)}</span></dd>
      </div>
      <div><dt>Výsledek</dt><dd>${escapeHtml(workflow.result)}</dd></div>
      <div><dt>Další krok</dt><dd>${escapeHtml(workflow.nextStep)}</dd></div>
    </dl>
  `;
}

function dataBoxPlusInstructionPlanSummary(plan = {}) {
  const rows = [
    ["Stav", plan.messageStatus || "Připraví se"],
    ["Předání", plan.assignedTo || "Nikomu"],
    ["Mimo systém", plan.sendsOutsideSystem ? "Ano" : "Ne"],
    ["Historie", plan.writesHistory ? "Ano" : "Ne"]
  ];
  return `
    <dl class="ds-plus-instruction-plan">
      ${rows.map(([label, value]) => `<div><dt>${escapeHtml(label)}</dt><dd>${escapeHtml(value)}</dd></div>`).join("")}
    </dl>
  `;
}

function dataBoxPlusComposeLauncher() {
  return `
    <section class="ds-plus-send-strip" aria-label="Odesílání datových zpráv">
      <div>
        <h2>Odesílání</h2>
        <p>Nová datová zpráva je samostatný proces. Chat každý úkon nejdřív přesně shrne a po potvrzení ho skutečně provede přes backend.</p>
      </div>
      <button class="primary-action" type="button" data-ds-plus-compose-open>Nová zpráva</button>
    </section>
  `;
}

function dataBoxPlusComposeOverlay() {
  if (!dataBoxPlusState.composeOpen) return "";
  const mailboxes = dataBoxPlusMailboxes();
  const selectedMailbox = mailboxes.find((mailbox) => mailbox.id === dataBoxPlusState.composeMailboxId) || null;
  const recipientStep = dataBoxPlusState.composeStep === "recipient" && selectedMailbox;
  return `
    <div class="ds-plus-detail-overlay" role="presentation">
      <button class="ds-plus-detail-backdrop" type="button" data-ds-plus-compose-close aria-label="Zavřít novou zprávu"></button>
      <section class="ds-plus-detail ds-plus-compose" role="dialog" aria-modal="true" aria-labelledby="ds-plus-compose-title">
        <div class="ds-plus-detail__head">
          <div>
            <span>Nová datová zpráva</span>
            <h2 id="ds-plus-compose-title">${recipientStep ? "2. Připrav návrh" : "1. Vyber schránku"}</h2>
          </div>
          <button class="secondary-link" type="button" data-ds-plus-compose-close>Zavřít</button>
        </div>
        <div class="ds-plus-detail__body">
          ${recipientStep ? `
          <section class="ds-plus-detail-section ds-plus-detail-section--workflow">
            <h3>Komu a co odeslat?</h3>
            <p>Schránka ${escapeHtml(selectedMailbox.name || selectedMailbox.company || "Datová schránka")} je vybraná. Vyplň návrh zprávy; nic se neodešle bez dalšího napojení a potvrzení.</p>
          </section>
          <form class="ds-plus-compose-form" data-ds-plus-compose-form>
            <label>
              <span>Adresát datové schránky</span>
              <input name="recipient" value="${escapeHtml(dataBoxPlusState.composeRecipient)}" placeholder="ID datové schránky nebo název" required />
            </label>
            <label>
              <span>Předmět</span>
              <input name="subject" value="${escapeHtml(dataBoxPlusState.composeSubject)}" placeholder="Předmět zprávy" required />
            </label>
            <label>
              <span>Text zprávy</span>
              <textarea name="body" rows="7" placeholder="Text nové datové zprávy" required>${escapeHtml(dataBoxPlusState.composeBody)}</textarea>
            </label>
            <div class="ds-plus-compose-footer">
              <button class="secondary-link" type="button" data-ds-plus-compose-back>Zpět k výběru</button>
              <button class="primary-action" type="submit">Připravit návrh</button>
            </div>
            <p class="ds-plus-compose-note" role="status">Návrh se pouze připraví v pracovním okně. Datová zpráva se neodešle.</p>
          </form>
          ` : `
          <section class="ds-plus-detail-section ds-plus-detail-section--workflow">
            <h3>Odkud chceš odeslat?</h3>
            <p>Vyber firemní datovou schránku. Další kroky budou příjemce, text, přílohy a kontrola před odesláním.</p>
          </section>
          <section class="ds-plus-compose-mailboxes" aria-label="Výběr schránky pro odeslání">
            ${mailboxes.length ? mailboxes.map((mailbox) => {
              const selected = mailbox.id === dataBoxPlusState.composeMailboxId;
              const status = mailbox.connectionStatus || mailbox.status || "";
              return `
                <article class="ds-plus-compose-mailbox ${selected ? "ds-plus-compose-mailbox--selected" : ""}">
                  <div>
                    <strong>${escapeHtml(mailbox.name || mailbox.company || "Datová schránka")}</strong>
                    <span>${escapeHtml(mailbox.company || mailbox.name || "Firma")}</span>
                    <small>ID: ${escapeHtml(dataBoxPlusMailboxValue(mailbox.isdsId))}</small>
                  </div>
                  <button class="${selected ? "primary-action" : "secondary-link"}" type="button" data-ds-plus-compose-mailbox="${escapeHtml(mailbox.id)}">
                    ${escapeHtml(selected ? "Vybráno" : "Vybrat")}
                  </button>
                  ${status ? `<em>${escapeHtml(status)}</em>` : ""}
                </article>
              `;
            }).join("") : `<p class="ds-plus-empty">Nejdřív připoj datovou schránku v Nastavení DSP.</p>`}
          </section>
          <section class="ds-plus-detail-section ds-plus-compose-next">
            <h3>Další krok</h3>
            <p>${selectedMailbox
              ? `Vybraná schránka: ${escapeHtml(selectedMailbox.name || selectedMailbox.company || "Datová schránka")}. Další krok bude výběr příjemce.`
              : "Vyber schránku, ze které se má zpráva připravit."}</p>
            <small>Odeslání nebude možné bez závěrečné kontroly a výslovného potvrzení.</small>
          </section>
          <div class="ds-plus-compose-footer">
            <span role="status">${selectedMailbox
              ? "Schránka je vybraná."
              : "Nejdřív vyber schránku."}</span>
            <button class="primary-action" type="button" data-ds-plus-compose-recipient ${selectedMailbox ? "" : "disabled"}>
              Zadat příjemce
            </button>
          </div>
          `}
        </div>
      </section>
    </div>
  `;
}

function dataBoxPlusShortAssistantText(recommendation = {}, plan = {}) {
  const text = String(recommendation.text || plan.assistantText || "").trim();
  const normalized = dataBoxPlusSearchText([text, plan.recommendedAction, plan.actionType, plan.confirmLabel]);
  if (normalized.includes("faktur") || normalized.includes("predan")) {
    return "Připravím předání. Nic se neodešle mimo systém.";
  }
  if (normalized.includes("archiv")) {
    return "Připravím archivaci. Nic se nesmaže.";
  }
  if (normalized.includes("vyresen") || normalized.includes("zpracovan") || normalized.includes("cssz")) {
    return "Připravím označení jako vyřešené. Nic se neodešle mimo systém.";
  }
  if (normalized.includes("nechat nevyrizene")) {
    return "Zpráva zůstane nevyřízená. Nic se neodešle mimo systém.";
  }
  if (text) {
    return text.length > 120 ? `${text.slice(0, 117).trim()}...` : text;
  }
  return "Připravím krok k potvrzení. Nic se zatím neprovede.";
}

function dataBoxPlusChatSuggestions(message) {
  const suggestions = [
    "Archivuj jako informativní",
    "Označ jako vyřízené",
    "Odpověz datovou schránkou",
    "Předej kolegovi"
  ];
  return `
    <div class="ds-plus-chat-suggestions" aria-label="Návrhy pokynů">
      ${suggestions.map((instruction) => `
        <button type="button" data-ds-plus-quick-instruction="${escapeHtml(instruction)}" data-message-id="${escapeHtml(message.id)}">
          ${escapeHtml(instruction)}
        </button>
      `).join("")}
    </div>
  `;
}

function dataBoxPlusChatActionLabel(type) {
  return ({
    archive_info: "Archivovat zprávu",
    mark_done: "Označit jako vyřízenou",
    need_more_info: "Označit k doplnění",
    mark_cannot_execute: "Označit jako neproveditelné",
    internal_note: "Přidat interní poznámku",
    create_task: "Vytvořit interní úkol",
    prepare_reply: "Připravit návrh odpovědi",
    send_data_box_reply: "Odeslat datovou zprávu",
    send_email: "Odeslat e-mail",
    send_sms: "Odeslat SMS",
    set_reminder: "Uložit termín připomínky",
    assign_to_user: "Předat kolegovi"
  })[String(type || "")] || "Provést připravenou akci";
}

function dataBoxPlusChatConfirmationCard(entry, message, loading) {
  const action = entry?.proposedAction && typeof entry.proposedAction === "object" ? entry.proposedAction : null;
  const confirmationId = String(action?.confirmationId || entry?.confirmationId || "").trim();
  if (!action || !confirmationId || entry?.outcome !== "waiting_confirmation") return "";
  const recipient = action.recipientName || action.recipientEmail || action.recipientPhone || action.recipientDataBoxId || action.assignedTo || "";
  return `
    <section class="ds-plus-chat-confirmation" aria-label="Akce čeká na potvrzení">
      <span class="ds-plus-chat-confirmation__eyebrow">Před provedením zkontrolujte</span>
      <h4>${escapeHtml(dataBoxPlusChatActionLabel(action.type))}</h4>
      <p>${escapeHtml(action.summary || "Připravená akce")}</p>
      <dl>
        ${recipient ? `<div><dt>Pro koho</dt><dd>${escapeHtml(recipient)}</dd></div>` : ""}
        ${action.subject ? `<div><dt>Předmět</dt><dd>${escapeHtml(action.subject)}</dd></div>` : ""}
        ${action.body ? `<div><dt>Text</dt><dd>${escapeHtml(action.body)}</dd></div>` : ""}
        ${action.noteText ? `<div><dt>Poznámka</dt><dd>${escapeHtml(action.noteText)}</dd></div>` : ""}
        ${action.dueDate ? `<div><dt>Termín</dt><dd>${escapeHtml(action.dueDate)}</dd></div>` : ""}
      </dl>
      <p class="ds-plus-chat-confirmation__help">Akce se provede jednou a zapíše se do historie. Bez potvrzení se nic nezmění ani neodešle.</p>
      <div class="ds-plus-chat-confirmation__actions">
        <button
          class="primary-action"
          type="button"
          data-ds-plus-chat-confirm="${escapeHtml(message.id)}"
          data-confirmation-id="${escapeHtml(confirmationId)}"
          ${loading ? "disabled" : ""}
        >${escapeHtml(dataBoxPlusChatActionLabel(action.type))}</button>
        <button
          class="secondary-link"
          type="button"
          data-ds-plus-chat-cancel="${escapeHtml(message.id)}"
          data-confirmation-id="${escapeHtml(confirmationId)}"
          ${loading ? "disabled" : ""}
        >Zrušit</button>
      </div>
    </section>
  `;
}

function dataBoxPlusInstructionCard(message) {
  const draft = Object.prototype.hasOwnProperty.call(dataBoxPlusState.instructionDrafts, message.id)
    ? dataBoxPlusState.instructionDrafts[message.id]
    : "";
  const loading = dataBoxPlusState.instructionLoadingId === message.id;
  const localChat = dataBoxPlusState.instructionChats[message.id] || [];
  const history = Array.isArray(message.history) ? message.history : [];
  const conversation = dataBoxPlusConversationEntries(history, localChat);

  return `
    <section class="ds-plus-instruction-card ds-plus-chat-window" aria-label="Chat k datové zprávě">
      <div class="ds-plus-chat-window__messages" data-ds-plus-chat-messages aria-live="polite" aria-busy="${loading ? "true" : "false"}">
        ${conversation.length ? conversation.map((entry) => `
          <div class="ds-plus-chat-message ds-plus-chat-message--${entry.role === "user" ? "user" : "assistant"} ${entry.pending ? "ds-plus-chat-message--pending" : ""} ${entry.error ? "ds-plus-chat-message--error" : ""}">
            <span>${entry.role === "user" ? "Radim" : "Autopilot"}</span>
            <p>${escapeHtml(entry.text)}</p>
            ${entry.role === "assistant" ? dataBoxPlusChatConfirmationCard(entry, message, loading) : ""}
          </div>
        `).join("") : `
          <div class="ds-plus-chat-message ds-plus-chat-message--assistant">
            <span>Autopilot</span>
            <p>Tady můžete napsat pokyn k této datové zprávě.</p>
          </div>
        `}
      </div>
      <div class="ds-plus-chat-window__footer">
        ${dataBoxPlusChatSuggestions(message)}
        <form class="ds-plus-chat-composer" data-ds-plus-instruction-form data-message-id="${escapeHtml(message.id)}">
          <textarea
            name="instruction"
            rows="2"
            aria-label="Zpráva pro Autopilota"
            placeholder="Napište, co mám se zprávou udělat…"
            ${loading ? "disabled" : ""}
          >${escapeHtml(draft)}</textarea>
          <button class="primary-action" type="submit" aria-label="Odeslat zprávu Autopilotovi" title="Odeslat" ${loading ? "disabled" : ""}>
            ${loading ? `<span class="ds-plus-chat-composer__loading" aria-hidden="true"></span>` : `<span aria-hidden="true">→</span>`}
          </button>
        </form>
      </div>
    </section>
  `;
}

function dataBoxPlusChatPanel(message) {
  return `
    <section class="ds-plus-chat-panel" aria-label="Chat k datové zprávě">
      ${dataBoxPlusInstructionCard(message)}
    </section>
  `;
}
function dataBoxPlusStatusHistory(message, workflow) {
  const history = Array.isArray(message.history) ? message.history : [];
  if (history.length) {
    return `
      <section class="ds-plus-detail-section">
        <h3>Historie</h3>
        <ol class="ds-plus-status-history">
          ${history.map((event) => `
            <li>
              <span>${escapeHtml(formatDateTime(event.createdAt))} - ${escapeHtml(event.actor || "Systém")}</span>
              <p>${escapeHtml(event.auditNote || event.actionType || event.result)}</p>
            </li>
          `).join("")}
        </ol>
      </section>
    `;
  }
  const events = [
    {
      time: message?.receivedAt || message?.deliveredAt,
      text: "Zpráva byla načtena do Datových schránek Plus."
    }
  ];
  if (message?.attachmentStatus) {
    events.push({
      time: message?.receivedAt || message?.deliveredAt,
      text: `Příloha: ${message.attachmentStatus}.`
    });
  }
  events.push({
    time: message?.updatedAt || message?.receivedAt || message?.deliveredAt,
    text: `${workflow.state}: ${workflow.result}`
  });
  return `
    <section class="ds-plus-detail-section">
      <h3>Historie stavu</h3>
      <ol class="ds-plus-status-history">
        ${events.map((event) => `
          <li>
            <span>${escapeHtml(formatDateTime(event.time))}</span>
            <p>${escapeHtml(event.text)}</p>
          </li>
        `).join("")}
      </ol>
    </section>
  `;
}

function dataBoxPlusActionHelpText(label = "") {
  const normalized = dataBoxPlusSearchText([label]);
  if (normalized.includes("predat mzdove ucetni")) {
    return "Zpráva se interně označí pro mzdovou účetní. Datová zpráva se nikam neodesílá a akce se zapíše do historie.";
  }
  if (normalized.includes("oznacit jako zpracovane")) {
    return "Zpráva se uloží k evidenci jako zpracovaná. Nic se nesmaže, nic se neodešle mimo systém a krok bude dohledatelný.";
  }
  if (normalized.includes("zrusit")) {
    return "Připravená akce se zruší. Zpráva zůstane k vyřízení, nic se neodešle a rozhodnutí bude dohledatelné.";
  }
  if (normalized.includes("zaradit rucne")) {
    return "Otevře se detail zprávy, kde ji můžeš ručně zařadit nebo předat. Nic se tím samo neodešle ani neuzavře.";
  }
  if (normalized.includes("nechat nevyrizene")) {
    return "Zpráva zůstane nevyřízená pro pozdější rozhodnutí a krok se zapíše do historie.";
  }
  if (normalized.includes("potvrdit predani")) {
    return "Zpráva se označí jako předaná odpovědné osobě nebo týmu. Nic se neodešle mimo systém a akce se zapíše do historie.";
  }
  if (normalized.includes("potvrdit archivaci")) {
    return "Zpráva se přesune do archivu jako vyřízená. Nic se nemaže a akci lze dohledat v historii.";
  }
  if (normalized.includes("potvrdit vytvoreni e-mailu")) {
    return "E-mail se odešle jen tehdy, když je v pokynu jasný adresát.";
  }
  if (normalized.includes("potvrdit zapsani lhuty")) {
    return "Zpráva se označí jako zpracovaná pro zadání lhůty. Nic se neodešle mimo systém a akce se zapíše do historie.";
  }
  if (normalized.includes("potvrdit prirazeni")) {
    return "Zpráva se přiřadí odpovědné osobě. Datová zpráva se nikam neodesílá a přiřazení bude dohledatelné v historii.";
  }
  if (normalized.includes("zapamatovat pro priste")) {
    return "Systém si uloží toto rozhodnutí jako vzor pro příští podobné zprávy.";
  }
  if (normalized.includes("predat") || normalized.includes("priradit")) {
    return "Zpráva se přiřadí vybrané osobě k vyřízení. Datová zpráva se nikam neodesílá. V ostré fázi se akce zapíše do historie a přiřazení půjde změnit.";
  }
  if (normalized.includes("archiv")) {
    return "Zpráva se přesune do archivu jako vyřízená nebo informativní. Nic se nesmaže ani neodešle mimo systém. Akci lze dohledat v historii a zprávu vrátit do práce.";
  }
  if (normalized.includes("potvrdit")) {
    return "Provede se akce připravená Autopilotem. Před provedením uvidíš přesně, co se stane. Nic se neodešle mimo systém bez schválení a krok bude dohledatelný.";
  }
  if (normalized.includes("zamit")) {
    return "Zpráva zůstane nevyřízená a rozhodnutí bude dohledatelné v historii.";
  }
  if (normalized.includes("znovu nacist")) {
    return "Systém se znovu pokusí stáhnout přílohu z datové schránky. Nic se neodešle mimo systém. Výsledek se zapíše do historie a pokus lze zopakovat.";
  }
  if (normalized.includes("pripravit e-mail")) {
    return "Když je adresát jasný, e-mail se odešle přes backend. Když jasný není, systém si vyžádá adresáta.";
  }
  if (normalized.includes("otevrit pdf") || normalized.includes("otevrit prilohu")) {
    return "Otevře se dostupná příloha ke kontrole. Zpráva se tím nevyřídí, nic se neodešle, nic se nesmaže a krok lze bezpečně zopakovat.";
  }
  if (normalized.includes("stahnout")) {
    return "Stáhne se kopie přílohy. Zpráva zůstane beze změny, nic se neodešle mimo systém a stažení bude v ostré fázi dohledatelné.";
  }
  if (normalized.includes("zadat lhutu")) {
    return "Připraví se zápis termínu k potvrzení. Bez schválení se nic neuloží ani neodešle. Termín půjde upravit a krok bude dohledatelný.";
  }
  if (normalized.includes("upravit")) {
    return "Pokyn můžeš upřesnit v chatu. Původní zpráva se nezmění a úprava bude dohledatelná.";
  }
  if (normalized.includes("pozastavit")) {
    return "Doporučení se dočasně vypne. Zprávy se nemažou, nic se neodešle a změnu lze vrátit.";
  }
  if (normalized.includes("audit") || normalized.includes("historii")) {
    return "Zobrazí se historie rozhodnutí a provedených kroků. Nic se tím nemění ani neodesílá.";
  }
  if (normalized.includes("zkontrolovat") || normalized.includes("otevrit zpravu")) {
    return "Otevře se pracovní kontrola zprávy. Stav zprávy se nezmění, nic se neodešle a kontrolu můžeš zavřít bez následku.";
  }
  if (normalized.includes("poznamku")) {
    return "Připraví se interní poznámka ke zprávě. Datová zpráva se nikam neodesílá, poznámku půjde upravit a v ostré fázi bude dohledatelná.";
  }
  return "Akce čeká na jasné potvrzení. Nic se neodešle mimo systém, nic se nesmaže a krok bude dohledatelný.";
}

function dataBoxPlusHelp(label, text) {
  const helpText = String(text || "").trim();
  if (!helpText) return "";
  return `
    <span class="ds-plus-help">
      <button class="ds-plus-help__button" type="button" aria-label="${escapeHtml(`Informace: ${label}`)}" title="${escapeHtml(helpText)}">i</button>
    </span>
  `;
}

function dataBoxPlusActionButton({ label, variant = "secondary-link", attrs = "", help = "" }) {
  const safeLabel = String(label || "Akce");
  return `
    <span class="ds-plus-action-with-help">
      <button class="${escapeHtml(variant)}" type="button" ${attrs}>${escapeHtml(safeLabel)}</button>
      ${dataBoxPlusHelp(safeLabel, help || dataBoxPlusActionHelpText(safeLabel))}
    </span>
  `;
}

function dataBoxPlusRecommendationMessage(item = {}) {
  return dataBoxPlusMessageById(item.messageId) || null;
}

function dataBoxPlusIsCsszPayrollMessage(item = {}, message = null) {
  const normalized = dataBoxPlusSearchText([
    item.recommendedAction,
    item.text,
    item.summary,
    item.evidence,
    message?.senderName,
    message?.subject,
    message?.recommendedAction,
    message?.type
  ]);
  return (
    normalized.includes("jmhz") ||
    normalized.includes("jednotne mesicni hlaseni zamestnavatele") ||
    normalized.includes("cssz") ||
    normalized.includes("ceska sprava socialniho zabezpeceni") ||
    normalized.includes("e-podani") ||
    normalized.includes("podani bylo prijato") ||
    normalized.includes("odpoved na e-podani")
  );
}

function dataBoxPlusCsszPayrollRisk(item = {}, message = null) {
  const normalized = dataBoxPlusSearchText([
    item.recommendedAction,
    item.text,
    item.summary,
    item.evidence,
    message?.subject,
    message?.recommendedAction
  ]);
  const highRisk = normalized.includes("sankc") || normalized.includes("pokut") || normalized.includes("lhut") || normalized.includes("pravni") || normalized.includes("financni narok");
  const mediumRisk = highRisk || normalized.includes("vyzv") || normalized.includes("chyb") || normalized.includes("odmit") || normalized.includes("oprav") || normalized.includes("povinnost") || normalized.includes("doplnit");
  if (highRisk) return "Vysoké";
  if (mediumRisk) return "Střední";
  return "Nízké";
}

function dataBoxPlusPreparedAction(item = {}) {
  const instructionPlan = dataBoxPlusInstructionPlan(item);
  if (instructionPlan) {
    return {
      type: instructionPlan.actionType || "instruction",
      prepared: instructionPlan.recommendedAction || item.recommendedAction || "Provedení pokynu.",
      confirmLabel: instructionPlan.confirmLabel || "Potvrdit provedení",
      afterConfirm: instructionPlan.afterConfirm || "Akce se zapíše do historie. Pokud chybí údaj, systém si ho vyžádá.",
      risk: instructionPlan.risk || item.riskReason || "Běžné",
      messageType: "Pokyn uživatele",
      recipient: instructionPlan.assignedTo || "Nikomu mimo systém.",
      reason: instructionPlan.sendsOutsideSystem
        ? "Akce vyžaduje potvrzení, protože by mohla něco odeslat mimo systém."
        : "Akce je interní, dohledatelná a nic se neodešle mimo systém.",
      instructionPlan
    };
  }
  const message = dataBoxPlusRecommendationMessage(item);
  const normalized = dataBoxPlusSearchText([
    item.recommendedAction,
    item.text,
    message?.recommendedAction,
    message?.primaryAction,
    message?.type,
    message?.subject
  ]);
  const messageSignal = dataBoxPlusSearchText([
    message?.senderName,
    message?.subject
  ]);
  const risk = message?.riskLevel || item.riskReason || item.risk || "Střední";

  if (dataBoxPlusIsCsszPayrollMessage(item, message)) {
    const payrollRisk = dataBoxPlusCsszPayrollRisk(item, message);
    const needsPayrollReview = payrollRisk !== "Nízké";
    return {
      type: needsPayrollReview ? "payroll_handoff" : "payroll_record",
      prepared: needsPayrollReview
        ? "Předání mzdové účetní k ověření."
        : "Uložení potvrzení ČSSZ k evidenci.",
      confirmLabel: needsPayrollReview ? "Předat mzdové účetní" : "Označit jako zpracované",
      afterConfirm: needsPayrollReview
        ? "Zpráva se interně označí pro mzdovou účetní. Nic se nesmaže a datová zpráva se nikam neodesílá."
        : "Zpráva se uloží k evidenci jako zpracovaná. Nic se nesmaže a datová zpráva se nikam neodesílá.",
      risk: payrollRisk,
      messageType: "Potvrzení o přijetí podání / mzdová agenda / ČSSZ",
      recipient: needsPayrollReview ? "Mzdová účetní" : "Nikomu. Zpráva zůstane uložená k evidenci.",
      reason: needsPayrollReview
        ? "Zpráva obsahuje signál k ověření, ale nejde o vozidlovou lhůtu ani předání garážmistrovi."
        : "Zpráva pouze potvrzuje přijetí podání ČSSZ, proto má běžné nebo nízké riziko.",
      secondaryConfirmActions: needsPayrollReview
        ? []
        : [{
            type: "payroll_handoff",
            label: "Předat mzdové účetní",
            help: "Zpráva se interně označí pro mzdovou účetní. Datová zpráva se nikam neodesílá a akce se zapíše do historie."
          }]
    };
  }

  if (normalized.includes("priloha neni nactena") || normalized.includes("znovu") || normalized.includes("rucni kontrol")) {
    return null;
  }
  if (normalized.includes("otevrit pdf") || normalized.includes("overit castku") || normalized.includes("vyzva k uhrade")) {
    return null;
  }
  if (normalized.includes("archiv")) {
    return {
      type: "archive",
      prepared: "Archivaci zprávy jako vyřízené nebo informativní.",
      confirmLabel: "Potvrdit archivaci",
      afterConfirm: "Zpráva se přesune do archivu jako vyřízená. Nic se nesmaže a akci lze dohledat v historii.",
      risk,
      messageType: message?.type || "Archivace",
      recipient: "Nikomu. Zpráva se jen interně přesune do archivu.",
      reason: "Jde o známý informační typ, u kterého archivace nic nemaže ani neodesílá."
    };
  }
  if (
    (normalized.includes("lhutu") || normalized.includes("lhuta") || normalized.includes("kalendar") || normalized.includes("technick") || normalized.includes("stk")) &&
    (messageSignal.includes("vozid") || messageSignal.includes("stk") || messageSignal.includes("registr vozidel") || messageSignal.includes("technick") || messageSignal.includes("prohlidk"))
  ) {
    return {
      type: "deadline",
      prepared: "Zapsání lhůty a předání garážmistrovi.",
      confirmLabel: "Potvrdit zapsání lhůty",
      afterConfirm: "Zpráva se označí pro zadání lhůty a předání garážmistrovi. Nic se neodešle mimo systém a akce se zapíše do historie.",
      risk,
      messageType: message?.type || "Vozidla",
      recipient: "Garážmistr",
      reason: "Akce se provede jen u zpráv se signálem vozidla, technické kontroly nebo konkrétní provozní lhůty."
    };
  }
  if (normalized.includes("faktury") || normalized.includes("faktura") || normalized.includes("upom")) {
    return {
      type: "handoff",
      prepared: "Předání na faktury@kaiserservis.cz.",
      confirmLabel: "Potvrdit předání",
      afterConfirm: "Zpráva se označí jako předaná účetnímu oddělení. Nic se nesmaže a datová zpráva se nikam neodesílá.",
      risk,
      messageType: message?.type || "Faktury / upomínky",
      recipient: "faktury@kaiserservis.cz",
      reason: "Zpráva vypadá jako faktura nebo upomínka, proto se pouze interně označí pro účetní oddělení."
    };
  }
  if (normalized.includes("pravnik") || normalized.includes("gt brno") || normalized.includes("exekuc") || normalized.includes("soud")) {
    return {
      type: "handoff",
      prepared: "Předání právníkovi nebo GT Brno.",
      confirmLabel: "Potvrdit předání",
      afterConfirm: "Zpráva se označí jako předaná právníkovi nebo GT Brno. Nic se neodešle mimo systém a akce se zapíše do historie.",
      risk,
      messageType: message?.type || "Exekuce / právní",
      recipient: "Právník / GT Brno",
      reason: "Právní zprávy se neuzavírají automaticky a zůstávají pod lidskou kontrolou."
    };
  }
  if (normalized.includes("predat") || normalized.includes("priradit")) {
    return {
      type: "assignment",
      prepared: "Přiřazení odpovědné osobě.",
      confirmLabel: "Potvrdit přiřazení",
      afterConfirm: "Zpráva se přiřadí odpovědné osobě k vyřízení. Datová zpráva se nikam neodesílá a akce se zapíše do historie.",
      risk,
      messageType: message?.type || "Přiřazení",
      recipient: "Odpovědná osoba",
      reason: "Přiřazení mění jen interní odpovědnost za vyřízení zprávy."
    };
  }
  if (normalized.includes("e-mail") || normalized.includes("email")) {
    return {
      type: "email",
      prepared: "Odeslání e-mailu nebo vyžádání adresáta.",
      confirmLabel: "Potvrdit vytvoření e-mailu",
      afterConfirm: "E-mail se odešle při jasném adresátovi. Pokud adresát chybí, Autopilot si ho vyžádá.",
      risk,
      messageType: message?.type || "E-mail",
      recipient: "Vyžaduje jasného adresáta.",
      reason: "E-mailový pokyn vyžaduje jasného adresáta."
    };
  }
  return null;
}

function dataBoxPlusMetricItems() {
  const messages = dataBoxPlusMessages();
  const workflows = messages.map((message) => dataBoxPlusMessageWorkflow(message));
  return [
    ["Nové", workflows.filter((workflow) => workflow.state === "Nová").length, "neutral"],
    ["Potřebuje pokyn", workflows.filter((workflow) => workflow.state === "Potřebuje pokyn").length, "warning"],
    ["Vyžaduje zásah", workflows.filter((workflow) => ["Potřebuje upřesnit", "Potřebuje adresáta", "Chybí vozidlo", "Chybí příloha", "Nelze provést"].includes(workflow.state)).length, "warning"],
    ["Vyřešeno dnes", workflows.filter((workflow) => workflow.state === "Vyřešeno").length, "success"],
    ["Nelze provést", workflows.filter((workflow) => workflow.state === "Nelze provést").length, "danger"]
  ];
}

function dataBoxPlusTabNav() {
  return `
    <nav class="ds-plus-tabs" aria-label="Sekce Datových schránek Plus">
      ${DATA_BOX_PLUS_TABS.map((tab) => `
        <button
          class="ds-plus-tab ${dataBoxPlusState.activeTab === tab.id ? "ds-plus-tab--active" : ""}"
          type="button"
          data-ds-plus-tab="${escapeHtml(tab.id)}"
          aria-pressed="${dataBoxPlusState.activeTab === tab.id ? "true" : "false"}"
        >
          ${escapeHtml(tab.label)}
        </button>
      `).join("")}
    </nav>
  `;
}

function dataBoxPlusStatusNotice() {
  if (dataBoxPlusState.loading && !dataBoxPlusState.loaded) {
    return `
      <div class="ds-plus-status-note" role="status">
        <strong>Načítám ostrý provoz</strong>
        <span>Datové schránky Plus si samy tahají stav z backendu. Ruční načtení není součást běžné práce.</span>
      </div>
    `;
  }
  if (dataBoxPlusState.error) {
    return `
      <div class="ds-plus-status-note ds-plus-status-note--warning" role="status">
        <strong>Ostré napojení čeká na dokončení</strong>
        <span>${escapeHtml(dataBoxPlusHumanError(dataBoxPlusState.error))}</span>
      </div>
    `;
  }
  return `
    <div class="ds-plus-status-note" role="status">
      <strong>Ostrá verze</strong>
      <span>Zprávy se načítají na pozadí. Autopilot připraví přesnou akci, doptá se na chybějící údaj a provede ji až po potvrzení.</span>
    </div>
  `;
}

function dataBoxPlusMetrics() {
  return `
    <section class="ds-plus-metrics" aria-label="Klíčové metriky">
      ${dataBoxPlusMetricItems().map(([label, value, tone]) => `
        <article class="ds-plus-metric ds-plus-metric--${escapeHtml(tone)}">
          <span>${escapeHtml(label)}</span>
          <strong>${escapeHtml(value)}</strong>
        </article>
      `).join("")}
    </section>
  `;
}

function dataBoxPlusPriorityCard(message) {
  const mailbox = dataBoxPlusMailbox(message);
  const workflow = dataBoxPlusMessageWorkflow(message);
  return `
    <article class="ds-plus-priority ds-plus-priority--${escapeHtml(workflow.tone)}">
      <div class="ds-plus-priority__topline">
        <span class="ds-plus-priority__mailbox">${escapeHtml(mailbox?.name || "Schránka")}</span>
        <span class="ds-plus-work-state ds-plus-work-state--${escapeHtml(workflow.tone)}">${escapeHtml(workflow.stateLabel || workflow.state)}</span>
      </div>
      <div class="ds-plus-priority__content">
        <h3>${escapeHtml(message.senderName)}</h3>
        <p>${escapeHtml(message.subject)}</p>
        <span>Doručeno: ${escapeHtml(formatDateTime(message.deliveredAt))}</span>
      </div>
      <div class="ds-plus-priority__actions">
        <button class="primary-action ds-plus-priority__open" type="button" data-ds-plus-chat="${escapeHtml(message.id)}">Chat s Autopilotem</button>
        <button class="secondary-link" type="button" data-ds-plus-open="${escapeHtml(message.id)}">Otevřít zprávu</button>
      </div>
    </article>
  `;
}

function dataBoxPlusCommandCenter() {
  const messages = dataBoxPlusMessages();
  const withWorkflow = messages.map((message) => ({ message, workflow: dataBoxPlusMessageWorkflow(message) }));
  const priorityCandidates = withWorkflow
    .filter((item) => ["Nová", "Potřebuje pokyn", "Potřebuje upřesnit", "Potřebuje adresáta", "Chybí vozidlo", "Chybí příloha", "Nelze provést"].includes(item.workflow.state))
    .map((item) => item.message);
  const pageSize = 5;
  const totalPages = Math.max(1, Math.ceil(priorityCandidates.length / pageSize));
  const currentPage = Math.min(
    Math.max(1, Number(dataBoxPlusState.commandCenterPage) || 1),
    totalPages
  );
  if (dataBoxPlusState.commandCenterPage !== currentPage) {
    dataBoxPlusState.commandCenterPage = currentPage;
  }
  const startIndex = (currentPage - 1) * pageSize;
  const visiblePriorityCandidates = priorityCandidates.slice(startIndex, startIndex + pageSize);
  const visibleStart = priorityCandidates.length ? startIndex + 1 : 0;
  const visibleEnd = Math.min(startIndex + pageSize, priorityCandidates.length);
  const priorityMessages = visiblePriorityCandidates;
  const resolvedToday = withWorkflow
    .filter((item) => ["Vyřešeno", "Archivováno"].includes(item.workflow.state))
    .slice(0, 2)
    .map((item) => item.workflow.result);
  const blockedMessages = messages
    .filter((message) => {
      const workflow = dataBoxPlusMessageWorkflow(message);
      return ["Potřebuje upřesnit", "Potřebuje adresáta", "Chybí vozidlo", "Chybí příloha", "Nelze provést"].includes(workflow.state);
    })
    .slice(0, 2);
  const readyForCommandCount = messages.filter((message) => {
    const workflow = dataBoxPlusMessageWorkflow(message);
    return workflow.state === "Potřebuje pokyn" || workflow.state === "Nová";
  }).length;
  const autopilotDone = dataBoxPlusAutopilotDoneItems();

  return `
    ${dataBoxPlusMetrics()}
    <section class="ds-plus-command-grid" aria-label="Řídicí centrum">
      <div class="ds-plus-command-main">
        ${dataBoxPlusComposeLauncher()}
        <section class="ds-plus-band" aria-labelledby="ds-plus-today-title">
          <div class="ds-plus-section-head">
            <div>
              <span>Dnes</span>
              <h2 id="ds-plus-today-title">Dnes vyřídit</h2>
            </div>
            <strong>${priorityCandidates.length ? `${visibleStart}–${visibleEnd} z ${priorityCandidates.length}` : "0 zpráv"}</strong>
          </div>
          <div class="ds-plus-command-pagination" aria-label="Stránkování přijatých zpráv">
            <span aria-live="polite">Stránka ${currentPage} z ${totalPages}</span>
            <div class="ds-plus-command-pagination__controls">
              <button
                class="secondary-link"
                type="button"
                data-ds-plus-command-page="${currentPage - 1}"
                aria-label="Předchozí stránka"
                title="Předchozí stránka"
                ${currentPage <= 1 ? "disabled" : ""}
              >‹</button>
              <button
                class="secondary-link"
                type="button"
                data-ds-plus-command-page="${currentPage + 1}"
                aria-label="Další stránka"
                title="Další stránka"
                ${currentPage >= totalPages ? "disabled" : ""}
              >›</button>
            </div>
          </div>
          <div class="ds-plus-priority-list">
            ${priorityMessages.length ? priorityMessages.map(dataBoxPlusPriorityCard).join("") : `<p class="ds-plus-empty">Teď tu není žádná ostrá zpráva k dnešnímu vyřízení.</p>`}
          </div>
        </section>
      </div>

      <aside class="ds-plus-command-side" aria-label="Souhrn práce">
        <section class="ds-plus-side-block ds-plus-side-block--done">
          <h2>Vyřešeno dnes</h2>
          <p>${escapeHtml(autopilotDone[0] || "Zatím nic.")}</p>
          <ul>
            ${resolvedToday.length ? resolvedToday.map((item) => `<li>${escapeHtml(item)}</li>`).join("") : `<li>Žádné uzavření dnes.</li>`}
          </ul>
        </section>
        <section class="ds-plus-side-block ds-plus-side-block--risk">
          <h2>Vyžaduje zásah</h2>
          <ul>
            ${blockedMessages.length ? blockedMessages.map((message) => `<li>${escapeHtml(message.subject)}</li>`).join("") : `<li>Nic nechybí.</li>`}
          </ul>
        </section>
        <section class="ds-plus-side-block">
          <h2>Čeká na pokyn</h2>
          <p>${escapeHtml(`${readyForCommandCount} zpráv připravených na chatový pokyn.`)}</p>
        </section>
      </aside>
    </section>
  `;
}

function dataBoxPlusFilterOptions() {
  return [
    ["new", "Nové"],
    ["today", "Dnes k vyřízení"],
    ["invoice", "Faktury"],
    ["reminder", "Upomínky"],
    ["office", "Úřady"],
    ["fine", "Výzvy / pokuty"],
    ["legal", "Exekuce / právní"],
    ["contracts", "Registr smluv"],
    ["vehicles", "Vozidla"],
    ["technical", "Technická oznámení"],
    ["safe", "Potřebuje pokyn"],
    ["archive", "Archivované"],
    ["problem", "Vyžaduje zásah"],
    ["all", "Vše"]
  ];
}

function dataBoxPlusMessageMatchesFilter(message, filter) {
  const normalized = dataBoxPlusSearchText([message.type, message.status, message.subject, message.senderName]);
  const workflow = dataBoxPlusMessageWorkflow(message);
  if (filter === "all") return true;
  if (filter === "new") return workflow.state === "Nová";
  if (filter === "today") return dataBoxPlusIsDueToday(message);
  if (filter === "invoice") return normalized.includes("faktur");
  if (filter === "reminder") return normalized.includes("upom");
  if (filter === "office") return normalized.includes("urad");
  if (filter === "fine") return normalized.includes("vyzvy") || normalized.includes("pokut");
  if (filter === "legal") return normalized.includes("exekuce") || normalized.includes("pravni");
  if (filter === "contracts") return normalized.includes("registr");
  if (filter === "vehicles") return normalized.includes("vozid");
  if (filter === "technical") return normalized.includes("technick");
  if (filter === "archive") return workflow.state === "Archivováno" || workflow.state === "Vyřešeno";
  if (filter === "problem") return ["Potřebuje upřesnit", "Potřebuje adresáta", "Chybí vozidlo", "Chybí příloha", "Nelze provést"].includes(workflow.state);
  if (filter === "safe") return workflow.state === "Potřebuje pokyn";
  return true;
}

function dataBoxPlusFilteredMessages() {
  const query = dataBoxPlusSearchText([dataBoxPlusState.search]);
  return dataBoxPlusMessages().filter((message) => {
    const mailbox = dataBoxPlusMailbox(message);
    const haystack = dataBoxPlusSearchText([
      message.senderName,
      message.subject,
      message.id,
      message.senderBoxId,
      message.recipientBoxId,
      mailbox?.name,
      message.referenceNumber,
      message.amount,
      message.plateNumber,
      message.attachments.map((attachment) => attachment.extractedText).join(" ")
    ]);
    return dataBoxPlusMessageMatchesFilter(message, dataBoxPlusState.filter) && (!query || haystack.includes(query));
  });
}

