function receivablesCaseSection() {
  if (receivablesState.caseLoading) {
    return `<section class="receivables-panel"><p class="receivables-empty">Načítám právní podklady...</p></section>`;
  }
  if (receivablesState.caseError) {
    return `<section class="receivables-panel"><p class="module-feedback__error">${escapeHtml(receivablesState.caseError)}</p></section>`;
  }
  const caseFile = receivablesState.caseDetail?.caseFile;
  if (!caseFile) {
    return `<section class="receivables-panel"><p class="receivables-empty">Případ zatím není načtený.</p></section>`;
  }
  return `
    <section class="receivables-panel" aria-labelledby="receivables-case-title">
      <div class="receivables-panel__head">
        <div>
          <p class="module-feedback__eyebrow">Právní podklady</p>
          <h2 id="receivables-case-title">${escapeHtml(caseFile.id)}</h2>
          <p>Aktuální fáze připravuje jen interní case file. ZIP/PDF export je další fáze.</p>
        </div>
        ${receivablesPill(caseFile.status, receivablesStatusTone(caseFile.status))}
      </div>
      <div class="receivables-detail-grid">
        <article><span>Celkem otevřeno</span><strong>${escapeHtml(formatReceivableMoney(caseFile.totalOpenAmount))}</strong></article>
        <article><span>Nejstarší splatnost</span><strong>${escapeHtml(caseFile.oldestDueDate || "-")}</strong></article>
        <article><span>Důvod</span><strong>${escapeHtml(caseFile.triggerReason || "-")}</strong></article>
        <article><span>Vytvořeno</span><strong>${escapeHtml(formatDateTime(caseFile.createdAt))}</strong></article>
      </div>
    </section>
  `;
}

function receivablesPage(moduleItem, user, isDashboard = false, context = { view: "dashboard" }) {
  const view = context.view || "dashboard";
  const activeTab = receivablesActiveTab(view, window.location.hash);
  const content = view === "customer"
    ? receivablesCustomerDetailSection()
    : view === "directory-audit"
      ? receivablesDirectoryAuditSection()
    : view === "import"
      ? receivablesImportSection()
    : view === "settings"
      ? receivablesSettingsSection()
      : view === "case"
        ? receivablesCaseSection()
        : receivablesDashboardSection();

  return `
    <main class="app-shell module-page module-theme-scope receivables-page" ${moduleThemeStyleAttribute()}>
      ${userBar(user)}
      <nav class="topbar" aria-label="Navigace">
        <a class="kaiser-logo kaiser-logo--small" href="${routeHref("/")}" data-link aria-label="Zpět na ${APP_NAME}">kaiser.</a>
        <a class="back-button" href="${routeHref("/")}" data-link>Zpět na HP</a>
      </nav>

      <section class="module-detail receivables-hero" aria-labelledby="receivables-title">
        <div class="module-detail__icon">${renderModuleIcon(moduleItem)}</div>
        <div class="module-detail__body">
          <div class="module-detail__eyebrow">SMART ODPADY / FINANCE</div>
          <h1 id="receivables-title">Pohledávkový kompas AI</h1>
          <p>Dry-run modul pro balíčky otevřených faktur, párování plateb, rating platební morálky a bezpečná AI doporučení.</p>
          <div class="module-detail__status">
            <span>Stav</span>
            <strong>Fáze 1D · dry-run + Vistos preview</strong>
          </div>
        </div>
      </section>

      <div class="receivables-warning" role="status">
        <strong>${RECEIVABLES_PHASE_NOTICE}</strong>
        <span>Zdroj pravdy bude D1 + backend API. Frontend neposílá zákaznické zprávy a neobsahuje žádné API klíče.</span>
      </div>

      <nav class="receivables-tabs" aria-label="Sekce Pohledávkového kompasu AI">
        ${RECEIVABLES_TABS.map((tab) => `
          <a class="${activeTab === tab.id ? "is-active" : ""}" href="${routeHref(tab.route)}" data-link>${escapeHtml(tab.label)}</a>
        `).join("")}
      </nav>

      ${content}
    </main>
  `;
}

function modulePage(moduleItem, user, isDashboard = false) {
  if (moduleItem.id === "absence") {
    return absenceModulePage(moduleItem, user, isDashboard);
  }

  if (moduleItem.id === "fleet") {
    return fleetModulePage(moduleItem, user, { isDashboard });
  }

  if (moduleItem.id === "vehicle-tracking") {
    return vehicleTrackingPage(moduleItem, user);
  }

  if (moduleItem.id === "driver-reports") {
    return driverReportsPage(moduleItem, user, isDashboard);
  }

  if (moduleItem.id === COLLECTION_ROUTES_MODULE_KEY) {
    return collectionRoutesModulePage(moduleItem, user, isDashboard);
  }

  if (moduleItem.id === RECEIVABLES_MODULE_KEY) {
    return receivablesPage(moduleItem, user, isDashboard, { view: isDashboard ? "dashboard" : "dashboard" });
  }

  if (moduleItem.id === DATA_BOX_MODULE_KEY) {
    return dataBoxPage(moduleItem, user);
  }

  if (moduleItem.id === DATA_BOX_PLUS_MODULE_KEY) {
    return dataBoxPlusPage(moduleItem, user);
  }

  if (moduleItem.id === "system-check") {
    return systemCheckPage(moduleItem, user);
  }

  if (moduleItem.id === SELF_REPAIR_MODULE_KEY) {
    return selfRepairPage(moduleItem, user);
  }

  const isTyres = moduleItem.id === "tyres";
  const title = isDashboard ? moduleItem.pageTitle : moduleItem.title;
  const description = isTyres && !isDashboard
    ? "Hotový modul evidence pneumatik."
    : moduleItem.description;
  const dashboardLink = !isDashboard && moduleItem.dashboardRoute
    ? `<a class="secondary-link" href="${routeHref(moduleItem.dashboardRoute)}" data-link>Dashboard modulu</a>`
    : "";
  const tyresLink = isTyres && !isDashboard
    ? `
        <a class="primary-link" href="${TYRES_MODULE_URL}" target="_blank" rel="noopener noreferrer">
          Otevřít modul Pneumatiky
        </a>
      `
    : "";
  const usersPanel = moduleItem.id === "users" && !isDashboard ? usersManagementSection() : "";
  const settingsPanel = moduleItem.id === "settings" && !isDashboard ? settingsManagementSection(user) : "";
  const reportsPanel = moduleItem.id === "reports" && !isDashboard
    ? `${notificationCenterSection(user)}${customerMessagingSection(user)}`
    : "";
  const genericSettingsPanel = !isDashboard && moduleItem.id !== "dashboard" ? genericModuleSettingsSection(moduleItem) : "";

  return `
    <main class="app-shell module-page module-theme-scope" ${moduleThemeStyleAttribute()}>
      ${userBar(user)}
      <nav class="topbar" aria-label="Navigace">
        <a class="kaiser-logo kaiser-logo--small" href="${routeHref("/")}" data-link aria-label="Zpět na ${APP_NAME}">kaiser.</a>
        <a class="back-button" href="${routeHref("/")}" data-link>Zpět na HP</a>
      </nav>

      <section class="module-detail" aria-labelledby="module-title">
        <div class="module-detail__icon">${renderModuleIcon(moduleItem)}</div>
        <div class="module-detail__body">
          <div class="module-detail__eyebrow">${isDashboard ? "Modulový dashboard" : "Modul"}</div>
          <h1 id="module-title">${title}</h1>
          <p>${description}</p>
          <div class="module-detail__status">
            <span>Stav</span>
            <strong>${escapeHtml(moduleStatusLabel(moduleItem))}</strong>
          </div>
          <div class="module-actions">
            ${tyresLink}
            ${dashboardLink}
          </div>
        </div>
      </section>
      ${usersPanel}
      ${settingsPanel}
      ${reportsPanel}
      ${genericSettingsPanel}
    </main>
  `;
}

function notificationStatusLabel(status) {
  return NOTIFICATION_STATUS_LABELS[status] || status || "Neznámý stav";
}

function notificationChannelLabel(channel) {
  return NOTIFICATION_CHANNEL_LABELS[channel] || channel || "neuvedeno";
}

function notificationTypeLabel(type) {
  return NOTIFICATION_TYPE_LABELS[type] || type || "neuvedeno";
}

function notificationStatusBadge(status) {
  const normalized = String(status || "not_sent").trim();
  return `<span class="notification-status notification-status--${escapeHtml(normalized)}">${escapeHtml(notificationStatusLabel(normalized))}</span>`;
}

function notificationHasError(item) {
  return ["failed", "not_sent", "skipped"].includes(String(item?.status || "").trim());
}

function notificationErrorSummary(item) {
  const lastError = notificationHasError(item)
    ? String(item?.lastError || item?.messagePreview || "").trim()
    : "";

  if (!lastError) {
    return "bez chyby";
  }

  const normalized = lastError
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();

  if (normalized.includes("chybi e-mail prijemce") || normalized.includes("chybi prijemce e-mailu")) {
    return "Chybí e-mail příjemce";
  }

  if (normalized.includes("chybi telefon prijemce")) {
    return "Chybí telefon příjemce";
  }

  if (
    normalized.includes("chybi produkcni nastaveni odesilani") ||
    normalized.includes("email_provider") ||
    normalized.includes("sendgrid_api_key") ||
    normalized.includes("email_from")
  ) {
    return "Chybí nastavení e-mailu";
  }

  if (normalized.includes("chybi produkcni nastaveni sms") || normalized.includes("twilio_")) {
    return "Chybí nastavení SMS";
  }

  if (normalized.includes("sendgrid")) {
    return "Chyba SendGrid";
  }

  return lastError.length > 72 ? `${lastError.slice(0, 69)}...` : lastError;
}

function notificationSummaryCards() {
  const summary = notificationCenterState.summary;
  const cards = [
    ["E-maily odeslané", summary.emailSent],
    ["E-maily neodeslané", summary.emailNotSent],
    ["SMS odeslané", summary.smsSent],
    ["SMS neodeslané", summary.smsNotSent],
    ["Čeká na odeslání", summary.pending],
    ["Selhalo", summary.failed]
  ];

  return `
    <div class="notification-summary-grid">
      ${cards.map(([label, value]) => `
        <article>
          <span>${escapeHtml(label)}</span>
          <strong>${escapeHtml(value)}</strong>
        </article>
      `).join("")}
    </div>
  `;
}

