async function apiJson(path, options = {}) {
  const isFormData = options.body instanceof FormData;
  const response = await fetch(path, {
    credentials: "include",
    headers: {
      ...(isFormData ? {} : { "Content-Type": "application/json" }),
      ...(options.headers || {})
    },
    ...options
  });
  const payload = await response.json().catch(() => ({}));

  if (!response.ok) {
    const error = new Error(payload.error || "Požadavek se nepodařilo dokončit.");
    error.payload = payload;
    throw error;
  }

  return payload;
}

function dataBoxPlusHomeUnresolvedCount() {
  return Number(dataBoxPlusHomeState.unresolvedCount || 0) || 0;
}

async function loadDataBoxPlusHomeStatus(options = {}) {
  const force = Boolean(options.force);
  const now = Date.now();
  if (dataBoxPlusHomeState.loading) return;
  if (!force && dataBoxPlusHomeState.loaded && now - dataBoxPlusHomeState.lastLoadedAt < 60000) return;

  dataBoxPlusHomeState.loading = true;
  dataBoxPlusHomeState.error = "";
  try {
    const statusResult = await apiJson("/api/data-box-plus/status");
    const summary = statusResult.summary || {};
    dataBoxPlusHomeState.newCount = Number(summary.newCount || 0) || 0;
    dataBoxPlusHomeState.unresolvedCount = Number(summary.unresolvedCount || 0) || 0;
    dataBoxPlusHomeState.loaded = true;
    dataBoxPlusHomeState.lastLoadedAt = now;
  } catch (error) {
    dataBoxPlusHomeState.error = dataBoxPlusHumanError(error.payload?.error || error.message || "Počet zpráv DSP se teď nepodařilo načíst.");
  } finally {
    dataBoxPlusHomeState.loading = false;
    if (options.renderAfter !== false) {
      render();
    }
  }
}

function ensureDataBoxPlusHomeStatus(user) {
  if (!canViewModule(user, DATA_BOX_PLUS_MODULE_KEY)) return;
  void loadDataBoxPlusHomeStatus({ force: !dataBoxPlusHomeState.loaded });
}

async function loadDataBoxPlusData(options = {}) {
  const force = Boolean(options.force);
  const now = Date.now();
  if (dataBoxPlusState.loading) return;
  if (!force && dataBoxPlusState.loaded && now - dataBoxPlusState.lastLoadedAt < 60000) return;

  dataBoxPlusState.loading = true;
  dataBoxPlusState.error = "";
  try {
    const [statusResult, messagesResult, recommendationsResult, rulesResult, syncRunsResult] = await Promise.all([
      apiJson("/api/data-box-plus/status"),
      apiJson("/api/data-box-plus/messages?limit=150"),
      apiJson("/api/data-box-plus/recommendations?status=all&limit=150"),
      apiJson("/api/data-box-plus/rules"),
      apiJson("/api/data-box-plus/sync-runs?limit=20")
    ]);
    dataBoxPlusState.apiStatus = statusResult.apiStatus || "ready";
    dataBoxPlusState.mailboxes = Array.isArray(statusResult.mailboxes) ? statusResult.mailboxes : [];
    dataBoxPlusState.sendReadiness = statusResult.sendReadiness || null;
    dataBoxPlusState.learning = statusResult.learning || null;
    dataBoxPlusState.messages = Array.isArray(messagesResult.messages) ? messagesResult.messages : [];
    dataBoxPlusState.recommendations = Array.isArray(recommendationsResult.recommendations) ? recommendationsResult.recommendations : [];
    dataBoxPlusState.rules = Array.isArray(rulesResult.rules) ? rulesResult.rules : [];
    dataBoxPlusState.syncRuns = Array.isArray(syncRunsResult.syncRuns) ? syncRunsResult.syncRuns : [];
    dataBoxPlusState.loaded = true;
    dataBoxPlusState.lastLoadedAt = now;
  } catch (error) {
    dataBoxPlusState.apiStatus = error.payload?.apiStatus || "waiting";
    dataBoxPlusState.error = dataBoxPlusHumanError(error.payload?.error || error.message || "Datové schránky Plus se teď nepodařilo načíst.");
  } finally {
    dataBoxPlusState.loading = false;
    if (options.renderAfter !== false) {
      render();
    }
    updateDataBoxPlusCountdownNodes();
  }
}

function ensureDataBoxPlusData() {
  void loadDataBoxPlusData({ force: !dataBoxPlusState.loaded });
}

async function loadDataBoxPlusMessageDetail(messageId) {
  const id = String(messageId || "");
  if (!id) return;
  try {
    const result = await apiJson(`/api/data-box-plus/messages/${encodeURIComponent(id)}`);
    if (result.message?.id) {
      const index = dataBoxPlusState.messages.findIndex((message) => message.id === result.message.id);
      if (index >= 0) {
        dataBoxPlusState.messages = [
          ...dataBoxPlusState.messages.slice(0, index),
          result.message,
          ...dataBoxPlusState.messages.slice(index + 1)
        ];
      } else {
        dataBoxPlusState.messages = [result.message, ...dataBoxPlusState.messages];
      }
    }
  } catch (error) {
    dataBoxPlusState.notice = dataBoxPlusHumanError(error.payload?.error || error.message || "Detail zprávy se teď nepodařilo načíst.");
  }
}

async function runDataBoxPlusInstruction(messageIdValue, instructionValue, options = {}) {
  const messageId = String(messageIdValue || "").trim();
  const instruction = String(instructionValue || "").trim();
  if (!messageId) return;
  if (!instruction) {
    dataBoxPlusState.notice = "Napište pokyn k této zprávě.";
    render();
    return;
  }
  const requestId = `ds-plus-chat-${messageId}-${Date.now()}`;
  dataBoxPlusState.instructionChats[messageId] = dataBoxPlusPendingChatEntries(
    dataBoxPlusState.instructionChats[messageId],
    instruction,
    requestId
  );
  delete dataBoxPlusState.instructionDrafts[messageId];
  dataBoxPlusState.instructionLoadingId = messageId;
  dataBoxPlusState.notice = "Autopilot pracuje.";
  render();
  scrollDataBoxPlusChatToLatest();
  try {
    const result = await apiJson(`/api/data-box-plus/messages/${encodeURIComponent(messageId)}/instruction`, {
      method: "POST",
      body: JSON.stringify({
        instruction,
        ...(options.confirmationId ? { confirmationId: options.confirmationId } : {})
      })
    });
    const assistantText = result.notice || result.action?.assistantText || "Hotovo. Provedeno.";
    if (options.confirmationId) {
      dataBoxPlusState.instructionChats[messageId] = dataBoxPlusResolveConfirmationEntries(
        dataBoxPlusState.instructionChats[messageId],
        options.confirmationId,
        result.action?.outcome || result.status
      );
    }
    dataBoxPlusState.instructionChats[messageId] = dataBoxPlusResolvePendingChatEntries(
      dataBoxPlusState.instructionChats[messageId],
      requestId,
      assistantText,
      result.auditId,
      false,
      {
        createdAt: new Date().toISOString(),
        outcome: result.action?.outcome || result.status,
        intent: result.action?.intent,
        statusLabel: result.action?.statusLabel,
        understoodAs: result.action?.understoodAs,
        performedAction: result.action?.outcome === "done"
          ? result.action?.performedAction
          : "Nebylo provedeno nic",
        proposedAction: result.action?.proposedAction
      }
    );
    dataBoxPlusState.notice = assistantText;
    await loadDataBoxPlusData({ force: true, renderAfter: false });
    if (result.message?.id) {
      const index = dataBoxPlusState.messages.findIndex((message) => message.id === result.message.id);
      if (index >= 0) dataBoxPlusState.messages[index] = result.message;
    }
    if (["done", "draft_ready"].includes(result.status) && result.action?.intent === "prepare_reply" && result.action?.draftText) {
      dataBoxPlusState.replyDraftTexts[messageId] = result.action.draftText;
    }
  } catch (error) {
    const assistantText = dataBoxPlusHumanError(error.payload?.error || error.message || "Zprávu se nepodařilo zpracovat.");
    dataBoxPlusState.instructionChats[messageId] = dataBoxPlusResolvePendingChatEntries(
      dataBoxPlusState.instructionChats[messageId],
      requestId,
      assistantText,
      "",
      true,
      {
        createdAt: new Date().toISOString(),
        outcome: "failed",
        statusLabel: "Nelze provést",
        understoodAs: "Požadavek se nepodařilo zpracovat.",
        performedAction: "Nebylo provedeno nic."
      }
    );
    dataBoxPlusState.notice = assistantText;
  } finally {
    dataBoxPlusState.instructionLoadingId = "";
    render();
    scrollDataBoxPlusChatToLatest();
  }
}

async function submitDataBoxPlusInstruction(form) {
  await runDataBoxPlusInstruction(
    form?.dataset?.messageId,
    form?.elements?.instruction?.value
  );
}

function scrollDataBoxPlusChatToLatest() {
  requestAnimationFrame(() => {
    const messages = document.querySelector("[data-ds-plus-chat-messages]");
    if (messages) messages.scrollTop = messages.scrollHeight;
  });
}

async function confirmDataBoxPlusRecommendation(recommendationId, actionTypeOverride = "") {
  const id = String(recommendationId || "");
  if (!id) return;
  const item = dataBoxPlusRecommendations({ includeClosed: true }).find((recommendation) => recommendation.id === id);
  const action = item ? dataBoxPlusPreparedAction(item) : null;
  const selectedActionType = String(actionTypeOverride || action?.type || "");
  const secondaryAction = Array.isArray(action?.secondaryConfirmActions)
    ? action.secondaryConfirmActions.find((candidate) => candidate.type === selectedActionType)
    : null;
  const actionLabel = secondaryAction?.label || action?.confirmLabel || "Potvrzení akce";
  try {
    await apiJson(`/api/data-box-plus/recommendations/${encodeURIComponent(id)}/confirm`, {
      method: "POST",
      body: JSON.stringify({
        requireRadimMartin: true,
        actionType: selectedActionType,
        rememberPattern: dataBoxPlusState.instructionRemember[id] !== false
      })
    });
    dataBoxPlusState.confirmedRecommendationIds = Array.from(new Set([
      ...dataBoxPlusState.confirmedRecommendationIds,
      id
    ]));
    dataBoxPlusState.dismissedRecommendationIds = dataBoxPlusState.dismissedRecommendationIds.filter((item) => item !== id);
    dataBoxPlusState.notice = action
      ? `${actionLabel}: zapsáno do historie. Nic se neodeslalo mimo systém.`
      : "Doporučení je potvrzené a zapsané do historie. Nic se neodeslalo mimo systém.";
    delete dataBoxPlusState.instructionRemember[id];
    await loadDataBoxPlusData({ force: true, renderAfter: false });
  } catch (error) {
    dataBoxPlusState.notice = dataBoxPlusHumanError(error.payload?.error || error.message || "Potvrzení akce se nepodařilo uložit.");
  }
}

async function rejectDataBoxPlusRecommendation(recommendationId) {
  const id = String(recommendationId || "");
  if (!id) return;
  try {
    await apiJson(`/api/data-box-plus/recommendations/${encodeURIComponent(id)}/reject`, {
      method: "POST",
      body: JSON.stringify({ reason: "Nepoužito z UI Datové schránky Plus." })
    });
    dataBoxPlusState.dismissedRecommendationIds = Array.from(new Set([
      ...dataBoxPlusState.dismissedRecommendationIds,
      id
    ]));
    dataBoxPlusState.notice = "Připravená akce se zrušila. Zpráva zůstává k vyřízení a nic se neodeslalo mimo systém.";
    await loadDataBoxPlusData({ force: true, renderAfter: false });
  } catch (error) {
    dataBoxPlusState.notice = dataBoxPlusHumanError(error.payload?.error || error.message || "Rozhodnutí nepoužít návrh se nepodařilo uložit.");
  }
}

async function runDataBoxPlusServiceSync() {
  try {
    dataBoxPlusState.notice = "Servisní načtení běží na pozadí.";
    render();
    await apiJson("/api/data-box-plus/sync", { method: "POST", body: JSON.stringify({}) });
    dataBoxPlusState.notice = "Servisní načtení doběhlo. Běžný provoz dál počítá s automatickým načítáním.";
    await loadDataBoxPlusData({ force: true, renderAfter: false });
  } catch (error) {
    dataBoxPlusState.notice = dataBoxPlusHumanError(error.payload?.error || error.message || "Servisní načtení se nepodařilo spustit.");
  }
}

async function sendDataBoxPlusEmail(messageId) {
  const id = String(messageId || "").trim();
  const message = dataBoxPlusMessageById(id);
  if (!id || !message) return;
  const readiness = dataBoxPlusState.sendReadiness || {};
  if (!readiness.email?.enabled) {
    dataBoxPlusState.notice = readiness.email?.text || "E-mailový provider není připravený.";
    render();
    return;
  }
  const recipientEmail = window.prompt("Kam e-mail odeslat?", message.assignedTo?.includes("@") ? message.assignedTo : "faktury@kaiserservis.cz");
  const cleanRecipient = String(recipientEmail || "").trim();
  if (!cleanRecipient) return;
  const subject = window.prompt("Předmět e-mailu", message.subject || "Datová zpráva");
  const cleanSubject = String(subject || "").trim() || message.subject || "Datová zpráva";
  const body = window.prompt("Krátká zpráva do e-mailu", `Předávám datovou zprávu: ${message.subject || ""}`);
  const cleanBody = String(body || "").trim();
  if (!window.confirm(`Opravdu odeslat e-mail na ${cleanRecipient}? Akce se zapíše do historie DSP.`)) {
    return;
  }
  dataBoxPlusState.notice = "Odesílám e-mail přes serverový provider.";
  render();
  try {
    const result = await apiJson(`/api/data-box-plus/messages/${encodeURIComponent(id)}/email`, {
      method: "POST",
      body: JSON.stringify({
        confirmed: true,
        recipientEmail: cleanRecipient,
        subject: cleanSubject,
        body: cleanBody
      })
    });
    dataBoxPlusState.notice = result.notice || `E-mail byl odeslán na ${cleanRecipient}.`;
    await loadDataBoxPlusData({ force: true, renderAfter: false });
    if (result.message?.id) {
      const index = dataBoxPlusState.messages.findIndex((item) => item.id === result.message.id);
      if (index >= 0) dataBoxPlusState.messages[index] = result.message;
    }
  } catch (error) {
    dataBoxPlusState.notice = dataBoxPlusHumanError(error.payload?.error || error.message || "E-mail se nepodařilo odeslat.");
  } finally {
    render();
  }
}

function dataBoxPlusMailboxPayload(form) {
  const fields = form?.elements || {};
  return {
    id: String(fields.id?.value || form?.dataset?.mailboxId || "").trim(),
    slot: Number(fields.slot?.value || 0),
    name: String(fields.name?.value || "").trim(),
    company: String(fields.company?.value || "").trim(),
    isdsId: String(fields.isdsId?.value || "").trim(),
    username: String(fields.username?.value || "").trim(),
    password: String(fields.password?.value || "").trim(),
    active: Boolean(fields.active?.checked)
  };
}

