function receivablesFullRatingJobRequested() {
  return new URLSearchParams(window.location.search).get("ratingJob") === "full-confirmed";
}

async function runReceivablesFullRatingJob() {
  if (receivablesState.fullRatingJobRunning || receivablesState.fullRatingJobCompleted) return;
  receivablesState.fullRatingJobRunning = true;
  receivablesState.fullRatingJobError = "";
  let offset = 0;
  try {
    while (true) {
      const result = await apiJson("/api/receivables/ratings/recompute-all", {
        method: "POST",
        body: JSON.stringify({ offset, limit: 25, persist: true })
      });
      receivablesState.fullRatingJobProcessed += Number(result.summary?.processed || 0);
      receivablesState.fullRatingJobTotal = Number(result.total || 0);
      offset = Number(result.nextOffset || offset);
      if (result.done) break;
    }
    receivablesState.fullRatingJobCompleted = true;
    receivablesState.dashboardLoaded = false;
    await loadReceivablesDashboard({ renderAfter: false });
    const url = new URL(window.location.href);
    url.searchParams.delete("ratingJob");
    window.history.replaceState({}, "", `${url.pathname}${url.search}${url.hash}`);
  } catch (error) {
    receivablesState.fullRatingJobError = error.payload?.error || error.message || "Dávkový přepočet ratingů se nepodařil.";
  } finally {
    receivablesState.fullRatingJobRunning = false;
    render();
  }
}

async function runReceivablesDirectoryAudit() {
  if (receivablesState.directoryAuditRunning || receivablesState.directoryAuditCompleted) return;
  receivablesState.directoryAuditRunning = true;
  receivablesState.directoryAuditError = "";
  let offset = 0;
  try {
    while (true) {
      const result = await apiJson(`/api/receivables/vistos/customer-directory-audit?offset=${offset}&limit=25`);
      if (result.readOnly !== true || result.writesD1 !== false) {
        throw new Error("Auditní endpoint nepotvrdil read-only režim.");
      }
      const summary = result.summary || {};
      for (const key of ["foundValidIco", "foundInvalidIco", "missingIco", "multipleCandidates"]) {
        receivablesState.directoryAuditSummary[key] += Number(summary[key] || 0);
      }
      for (const item of result.results || []) {
        if (!item.sourceEntity || !item.sourceAttemptKey) continue;
        const source = `${item.sourceEntity} · ${item.sourceAttemptKey}`;
        receivablesState.directoryAuditSources[source] = (receivablesState.directoryAuditSources[source] || 0) + 1;
      }
      receivablesState.directoryAuditProcessed += Number(result.pagination?.returned || 0);
      receivablesState.directoryAuditTotal = Number(result.pagination?.total || 0);
      offset = Number(result.pagination?.nextOffset || offset);
      render();
      if (result.pagination?.done) break;
    }
    receivablesState.directoryAuditCompleted = true;
  } catch (error) {
    receivablesState.directoryAuditError = error.payload?.error || error.message || "Vistos Directory audit se nepodařilo dokončit.";
  } finally {
    receivablesState.directoryAuditRunning = false;
    render();
  }
}

function ensureReceivablesData(context = { view: "dashboard" }) {
  if (!receivablesState.dashboardLoaded && !receivablesState.dashboardLoading) {
    void loadReceivablesDashboard();
  }

  if (context.view === "customer" && context.customerId && receivablesState.selectedCustomerId !== context.customerId) {
    receivablesState.customerDetail = null;
    receivablesState.insolvencyPreview = null;
    receivablesState.insolvencyPreviewError = "";
    void loadReceivablesCustomerDetail(context.customerId);
  }

  if (context.view === "case" && context.caseId && receivablesState.selectedCaseId !== context.caseId) {
    receivablesState.caseDetail = null;
    void loadReceivablesCase(context.caseId);
  }

  if (context.view === "settings" && !receivablesState.settings && !receivablesState.settingsLoading) {
    void loadReceivablesSettings();
  }

  if (context.view === "import" && !receivablesState.invoiceSnapshotLoaded && !receivablesState.invoiceSnapshotLoading) {
    void loadReceivablesInvoiceSnapshot();
  }

  if (context.view === "import" && !receivablesState.incrementalLedgerDiffLoaded && !receivablesState.incrementalLedgerDiffLoading) {
    void loadReceivablesIncrementalLedgerDiff();
  }

  if (context.view === "import" && !receivablesState.paymentReconciliationLoaded && !receivablesState.paymentReconciliationLoading) {
    void loadReceivablesPaymentReconciliation();
  }

  if (context.view === "import" && !receivablesState.kbOnboardingLoaded && !receivablesState.kbOnboardingLoading) {
    void loadReceivablesKbOnboarding();
  }

  if (context.view === "import" && !receivablesState.kbSandboxProbeLoaded && !receivablesState.kbSandboxProbeLoading) {
    void loadReceivablesKbSandboxProbe();
  }

  if (context.view === "import" && receivablesFullRatingJobRequested()) {
    void runReceivablesFullRatingJob();
  }

  if (context.view === "directory-audit") {
    void runReceivablesDirectoryAudit();
  }

  if (
    context.view === "import"
    && receivablesState.invoiceSnapshotLoaded
    && !receivablesInvoiceSnapshotShouldAdvance()
    && !receivablesState.ledgerMappingLoaded
    && !receivablesState.ledgerMappingLoading
  ) {
    void loadReceivablesLedgerMapping();
  }
}

function collectionRoutesSourceRoutesApiUrl() {
  collectionRoutesSourceMaybeApplySmartDefaultFilters();
  const params = new URLSearchParams();
  const filters = collectionRoutesPilotState.sourceFilters || {};
  if (collectionRoutesPilotState.sourceSelectedBatchId) {
    params.set("batchId", collectionRoutesPilotState.sourceSelectedBatchId);
  }
  params.set("day", filters.day || "all");
  params.set("week", filters.week || "all");
  params.set("vehicle", filters.vehicle || "all");
  params.set("waste", collectionRoutesSourceWasteApiValue(filters.waste || "all"));
  params.set("mappingStatus", filters.mappingStatus || "all");
  params.set("limit", "2000");
  return `/api/collection-routes/svozove-trasy/routes?${params.toString()}`;
}

function collectionRoutesSourceDriverRunKeyFromState() {
  const filters = collectionRoutesPilotState.sourceFilters || {};
  return [
    collectionRoutesPilotState.sourceSelectedBatchId || "",
    filters.day || "all",
    filters.week || "all",
    filters.vehicle || "all",
    collectionRoutesSourceWasteApiValue(filters.waste || "all"),
    filters.mappingStatus || "all"
  ].join("|");
}

