async function loadDataBoxData(options = {}) {
  const { force = false, renderAfter = true } = options;

  if (dataBoxState.loading || (dataBoxState.loaded && !force)) {
    return;
  }

  dataBoxState.loading = true;
  dataBoxState.error = "";

  try {
    const status = await apiJson("/api/data-box/status");
    dataBoxState.status = status;
    dataBoxState.apiStatus = status.apiStatus || "waiting";
    dataBoxState.storageStatus = status.storageStatus || "waiting";
    dataBoxState.integrationStatus = status.integrationStatus || "inactive";
    dataBoxState.messages = [];
    dataBoxState.syncRuns = [];
    dataBoxState.aiBoostActions = [];

    if (dataBoxState.apiStatus === "ready") {
      const [messagesResult, syncRunsResult, actionsResult] = await Promise.all([
        apiJson("/api/data-box/messages?limit=100"),
        apiJson("/api/data-box/sync-runs?limit=50"),
        apiJson("/api/data-box/actions?limit=200")
      ]);
      dataBoxState.messages = messagesResult.messages || [];
      dataBoxState.syncRuns = syncRunsResult.runs || [];
      dataBoxState.aiBoostActions = (actionsResult.actions || []).filter(dataBoxActionShouldShowInAiBoost);
      dataBoxState.aiBoostLoaded = true;
    }

    dataBoxState.loaded = true;
  } catch (error) {
    dataBoxState.status = null;
    dataBoxState.messages = [];
    dataBoxState.syncRuns = [];
    dataBoxState.aiBoostActions = [];
    dataBoxState.apiStatus = error?.payload?.apiStatus || "waiting";
    dataBoxState.error = error?.payload?.error || error?.message || "Datovou schránku se teď nepodařilo načíst.";
    dataBoxState.loaded = true;
  } finally {
    dataBoxState.loading = false;
  }

  if (renderAfter) {
    render();
  }
}

function ensureDataBoxData() {
  if (!hasPermission(currentUser(), DATA_BOX_MODULE_KEY, "view")) {
    return;
  }

  void loadDataBoxData();
}

async function loadDataBoxMessageDetail(messageId, options = {}) {
  const id = String(messageId || "").trim();
  if (!id) {
    return;
  }

  const openReply = Boolean(options.openReply);
  const sameMessage = String(dataBoxState.selectedMessageId || "") === id;
  resetDataBoxAttachmentFeedback();

  dataBoxState.selectedPreviewMessageId = id;
  dataBoxState.selectedMessageId = id;
  dataBoxState.selectedMessage = dataBoxState.selectedMessage?.id === id ? dataBoxState.selectedMessage : null;
  dataBoxState.detailLoading = true;
  dataBoxState.detailError = "";
  dataBoxState.replyDraftOpen = openReply;
  dataBoxState.replyDraftError = "";
  if (!sameMessage || !openReply) {
    dataBoxState.replyDraftText = "";
  }
  render();

  try {
    const result = await apiJson(`/api/data-box/messages/${encodeURIComponent(id)}`);
    if (dataBoxState.selectedMessageId === id) {
      const detailMessage = result.message || null;
      dataBoxState.selectedMessage = detailMessage;
    }
  } catch (error) {
    if (dataBoxState.selectedMessageId === id) {
      dataBoxState.selectedMessage = null;
      dataBoxState.detailError = error?.payload?.error || error?.message || "Zprávu se teď nepodařilo načíst.";
      dataBoxState.replyDraftError = openReply ? "Návrh odpovědi se nepodařilo připravit." : "";
    }
  } finally {
    if (dataBoxState.selectedMessageId === id) {
      dataBoxState.detailLoading = false;
    }
  }

  render();
}

function openDataBoxReplyDraft(messageId) {
  const id = String(messageId || "").trim();
  if (!id) {
    dataBoxState.replyDraftOpen = true;
    dataBoxState.replyDraftError = "Návrh odpovědi se nepodařilo připravit.";
    render();
    return;
  }

  dataBoxState.replyDraftOpen = true;
  dataBoxState.replyDraftError = "";

  if (String(dataBoxState.selectedMessageId || "") !== id || String(dataBoxState.selectedMessage?.id || "") !== id) {
    void loadDataBoxMessageDetail(id, { openReply: true });
    return;
  }

  render();
}

function dataBoxMessageById(messageId) {
  const id = String(messageId || "").trim();
  return dataBoxState.selectedMessage?.id === id
    ? dataBoxState.selectedMessage
    : dataBoxState.messages.find((message) => String(message.id || "") === id) || null;
}

function resetDataBoxActionFeedback() {
  dataBoxState.actionNotice = "";
  dataBoxState.actionError = "";
}

async function refreshDataBoxAfterAction(messageId, detail = null) {
  await loadDataBoxData({ force: true, renderAfter: false });
  if (detail?.message) {
    dataBoxState.selectedMessage = detail.message;
  } else if (messageId && dataBoxState.selectedMessageId === messageId) {
    try {
      const result = await apiJson(`/api/data-box/messages/${encodeURIComponent(messageId)}`);
      dataBoxState.selectedMessage = result.message || dataBoxState.selectedMessage;
    } catch {
      dataBoxState.selectedMessage = dataBoxMessageById(messageId);
    }
  }
}

async function archiveDataBoxMessageAction(messageId) {
  const id = String(messageId || "").trim();
  if (!id) return;
  const message = dataBoxMessageById(id);
  const subject = message?.subject || "tuto zprávu";
  if (!window.confirm(`Archivovat datovou zprávu „${subject}“?`)) {
    return;
  }

  resetDataBoxActionFeedback();
  dataBoxState.actionLoading = "archive";
  render();

  try {
    const result = await apiJson(`/api/data-box/messages/${encodeURIComponent(id)}/archive`, {
      method: "POST",
      body: JSON.stringify({ confirmed: true })
    });
    dataBoxState.actionNotice = result.notice || "Zpráva byla archivována.";
    dataBoxState.actionError = "";
    await refreshDataBoxAfterAction(id, result);
  } catch (error) {
    dataBoxState.actionError = error?.payload?.error || error?.message || "Archivace se nepodařila.";
    dataBoxState.actionNotice = "";
  } finally {
    dataBoxState.actionLoading = "";
    render();
  }
}

async function archiveSelectedDataBoxMessagesAction() {
  const selectedMessages = dataBoxSelectedBulkMessages()
    .filter((message) => message.direction === "received" && dataBoxWorkflowStatus(message).id !== "archived");
  if (!selectedMessages.length) {
    dataBoxState.actionNotice = "";
    dataBoxState.actionError = "Nejsou vybrané žádné zprávy k archivaci.";
    render();
    return;
  }

  if (!window.confirm(`Archivovat ${selectedMessages.length} vybraných zpráv? Stav přečteno/nepřečteno se tím nezmění.`)) {
    return;
  }

  resetDataBoxActionFeedback();
  dataBoxState.actionLoading = "bulk-archive";
  render();

  const archivedIds = [];
  const failures = [];

  for (const message of selectedMessages) {
    const id = String(message.id || "");
    try {
      await apiJson(`/api/data-box/messages/${encodeURIComponent(id)}/archive`, {
        method: "POST",
        body: JSON.stringify({ confirmed: true })
      });
      archivedIds.push(id);
    } catch (error) {
      failures.push({
        id,
        error: error?.payload?.error || error?.message || "Archivace se nepodařila."
      });
    }
  }

  const archivedSet = new Set(archivedIds);
  dataBoxState.selectedBulkMessageIds = (dataBoxState.selectedBulkMessageIds || [])
    .filter((id) => !archivedSet.has(String(id || "")));

  if (archivedSet.has(String(dataBoxState.selectedMessageId || ""))) {
    dataBoxState.selectedMessageId = "";
    dataBoxState.selectedMessage = null;
    dataBoxState.selectedPreviewMessageId = "";
    clearDataBoxBulkSelection();
    dataBoxState.detailError = "";
    dataBoxState.replyDraftOpen = false;
    dataBoxState.replyDraftText = "";
    dataBoxState.replyDraftError = "";
  }

  try {
    await loadDataBoxData({ force: true, renderAfter: false });
  } catch {
    // Ponecháme výsledek archivace viditelný i když následné obnovení seznamu selže.
  }

  if (failures.length) {
    dataBoxState.actionError = `${failures.length} z ${selectedMessages.length} zpráv se nepodařilo archivovat. První chyba: ${failures[0].error}`;
    dataBoxState.actionNotice = archivedIds.length ? `${archivedIds.length} zpráv bylo archivováno.` : "";
  } else {
    dataBoxState.actionNotice = archivedIds.length === 1 ? "1 zpráva byla archivována." : `${archivedIds.length} zpráv bylo archivováno.`;
    dataBoxState.actionError = "";
  }

  dataBoxState.actionLoading = "";
  render();
}

async function emailDataBoxMessageAction(messageId) {
  const id = String(messageId || "").trim();
  if (!id) return;
  const message = dataBoxMessageById(id);
  const recipientEmail = window.prompt("Komu poslat datovou zprávu e-mailem?", "");
  const cleanRecipient = String(recipientEmail || "").trim();
  if (!cleanRecipient) {
    return;
  }
  const subject = message?.subject || "Datová zpráva";
  if (!window.confirm(`Odeslat zprávu „${subject}“ e-mailem na ${cleanRecipient}?`)) {
    return;
  }

  resetDataBoxActionFeedback();
  dataBoxState.actionLoading = "email";
  render();

  try {
    const result = await apiJson(`/api/data-box/messages/${encodeURIComponent(id)}/email`, {
      method: "POST",
      body: JSON.stringify({
        confirmed: true,
        recipientEmail: cleanRecipient,
        subject,
        body: "Datová zpráva odeslaná z Kaiser Smart po potvrzení uživatele."
      })
    });
    dataBoxState.actionNotice = result.notice || "Datová zpráva byla odeslána e-mailem.";
    dataBoxState.actionError = "";
    await refreshDataBoxAfterAction(id, result);
  } catch (error) {
    dataBoxState.actionError = error?.payload?.error || error?.message || "E-mail se nepodařilo odeslat.";
    dataBoxState.actionNotice = "";
  } finally {
    dataBoxState.actionLoading = "";
    render();
  }
}

async function sendDataBoxReplyAction(messageId) {
  const id = String(messageId || "").trim();
  if (!id) return;
  const message = dataBoxMessageById(id);
  const text = String(dataBoxState.replyDraftText || "").trim();
  if (!text) {
    dataBoxState.replyDraftError = "Nelze odeslat: text odpovědi je prázdný.";
    render();
    return;
  }
  const subject = dataBoxReplySubject(message || {});
  const recipient = dataBoxReplyRecipient(message || {});
  if (!window.confirm(`Opravdu odeslat odpověď přes datovou schránku?\n\nKomu: ${recipient}\nPředmět: ${subject}`)) {
    return;
  }

  resetDataBoxActionFeedback();
  dataBoxState.replyDraftError = "";
  dataBoxState.actionLoading = "reply";
  render();

  try {
    const result = await apiJson(`/api/data-box/messages/${encodeURIComponent(id)}/reply`, {
      method: "POST",
      body: JSON.stringify({
        confirmed: true,
        subject,
        body: text
      })
    });
    dataBoxState.actionNotice = result.notice || "Odpověď byla odeslána přes datovou schránku.";
    dataBoxState.actionError = "";
    dataBoxState.replyDraftOpen = false;
    dataBoxState.replyDraftText = "";
    await refreshDataBoxAfterAction(id, result);
  } catch (error) {
    const messageText = error?.payload?.error || error?.message || "Odpověď se nepodařilo odeslat.";
    dataBoxState.replyDraftError = messageText;
    dataBoxState.actionError = messageText;
    dataBoxState.actionNotice = "";
  } finally {
    dataBoxState.actionLoading = "";
    render();
  }
}

async function runDataBoxAiBoostAction() {
  if (dataBoxState.aiBoostLoading) {
    return;
  }

  dataBoxState.aiBoostLoading = true;
  dataBoxState.aiBoostError = "";
  dataBoxState.aiBoostMessage = "Autopilot připravuje koncepty...";
  render();

  try {
    const result = await apiJson("/api/data-box/ai-boost/run", {
      method: "POST",
      body: JSON.stringify({ limit: 30 })
    });
    dataBoxState.aiBoostMessage = result.message || `Autopilot připravil ${Number(result.created || 0)} konceptů.`;
    dataBoxState.aiBoostError = "";
    await loadDataBoxData({ force: true, renderAfter: false });
    dataBoxState.activeTab = "confirmations";
  } catch (error) {
    dataBoxState.aiBoostError = error?.payload?.error || error?.message || "Autopilot se nepodařilo spustit.";
    dataBoxState.aiBoostMessage = "";
  } finally {
    dataBoxState.aiBoostLoading = false;
    render();
  }
}

async function confirmDataBoxAiBoostAction(actionId) {
  const id = String(actionId || "").trim();
  if (!id || dataBoxState.aiBoostLoading) {
    return;
  }
  const action = dataBoxState.aiBoostActions.find((item) => String(item.id || "") === id);
  const label = dataBoxAiBoostActionLabel(action);
  const subject = action?.subject || "Koncept Autopilota";

  if (!window.confirm(`Potvrdit koncept Autopilota?\n\nAkce: ${label}\nZpráva: ${subject}\n\nBez potvrzení se nic neprovede.`)) {
    return;
  }

  dataBoxState.aiBoostLoading = true;
  dataBoxState.aiBoostError = "";
  dataBoxState.aiBoostMessage = "Potvrzuji koncept Autopilota...";
  render();

  try {
    const result = await apiJson(`/api/data-box/actions/${encodeURIComponent(id)}/confirm`, {
      method: "POST",
      body: JSON.stringify({ confirmed: true })
    });
    dataBoxState.aiBoostMessage = result.notice || "Koncept Autopilota byl potvrzen.";
    dataBoxState.aiBoostError = "";
    await loadDataBoxData({ force: true, renderAfter: false });
    dataBoxState.activeTab = "confirmations";
  } catch (error) {
    dataBoxState.aiBoostError = error?.payload?.error || error?.message || "Koncept Autopilota se nepodařilo potvrdit.";
    dataBoxState.aiBoostMessage = "";
  } finally {
    dataBoxState.aiBoostLoading = false;
    render();
  }
}

async function confirmDataBoxAiBoostGroup(actionType) {
  const type = String(actionType || "").trim().toLowerCase();
  if (!["archive", "email"].includes(type) || dataBoxState.aiBoostLoading) {
    return;
  }

  const actions = dataBoxState.aiBoostActions.filter((action) => (
    dataBoxAiBoostIsWaiting(action)
    && String(action.actionType || "").toLowerCase() === type
    && action.id
  ));

  if (!actions.length) {
    dataBoxState.aiBoostMessage = type === "email" ? "Žádný e-mail nečeká na potvrzení." : "Žádná archivace nečeká na potvrzení.";
    dataBoxState.aiBoostError = "";
    render();
    return;
  }

  const confirmText = type === "email"
    ? `Opravdu odeslat ${actions.length} e-mailových konceptů?\n\nE-maily se skutečně odešlou přes napojený backend. Bez tohoto potvrzení se nic neodešle.`
    : `Opravdu potvrdit ${actions.length} archivací?\n\nZprávy se označí jako archivované přes napojený backend. Bez tohoto potvrzení se nic neprovede.`;

  if (!window.confirm(confirmText)) {
    return;
  }

  dataBoxState.aiBoostLoading = true;
  dataBoxState.aiBoostError = "";
  dataBoxState.aiBoostMessage = type === "email" ? "Potvrzuji e-mailové koncepty..." : "Potvrzuji archivace...";
  render();

  const failures = [];

  try {
    for (const action of actions) {
      try {
        await apiJson(`/api/data-box/actions/${encodeURIComponent(action.id)}/confirm`, {
          method: "POST",
          body: JSON.stringify({ confirmed: true })
        });
      } catch (error) {
        failures.push({
          subject: action.subject || action.messageId || action.id,
          error: error?.payload?.error || error?.message || "Potvrzení selhalo."
        });
      }
    }

    await loadDataBoxData({ force: true, renderAfter: false });
    dataBoxState.activeTab = "confirmations";
    if (failures.length) {
      dataBoxState.aiBoostError = `${failures.length} z ${actions.length} akcí se nepodařilo potvrdit. První chyba: ${failures[0].error}`;
      dataBoxState.aiBoostMessage = `${actions.length - failures.length} akcí bylo potvrzeno.`;
    } else {
      dataBoxState.aiBoostMessage = type === "email"
        ? `${actions.length} e-mailových konceptů bylo potvrzeno.`
        : `${actions.length} archivací bylo potvrzeno.`;
      dataBoxState.aiBoostError = "";
    }
  } catch (error) {
    dataBoxState.aiBoostError = error?.payload?.error || error?.message || "Dávkové potvrzení se nepodařilo dokončit.";
    dataBoxState.aiBoostMessage = "";
  } finally {
    dataBoxState.aiBoostLoading = false;
    render();
  }
}

async function saveDataBoxAiBoostEditForm(form) {
  const actionId = String(form.dataset.actionId || "").trim();
  if (!actionId || dataBoxState.aiBoostLoading) {
    return;
  }

  const formData = new FormData(form);
  dataBoxState.aiBoostLoading = true;
  dataBoxState.aiBoostError = "";
  dataBoxState.aiBoostMessage = "Ukládám upravený návrh Autopilota...";
  render();

  try {
    const result = await apiJson(`/api/data-box/actions/${encodeURIComponent(actionId)}`, {
      method: "PATCH",
      body: JSON.stringify({
        actionType: String(formData.get("actionType") || "").trim(),
        recipient: String(formData.get("recipient") || "").trim(),
        subject: String(formData.get("subject") || "").trim(),
        bodyPreview: String(formData.get("bodyPreview") || "").trim(),
        editNote: String(formData.get("editNote") || "").trim()
      })
    });
    dataBoxState.aiBoostEditingId = "";
    dataBoxState.aiBoostMessage = result.notice || "Návrh Autopilota byl upraven.";
    dataBoxState.aiBoostError = "";
    await loadDataBoxData({ force: true, renderAfter: false });
    dataBoxState.activeTab = "confirmations";
  } catch (error) {
    dataBoxState.aiBoostError = error?.payload?.error || error?.message || "Návrh Autopilota se nepodařilo upravit.";
    dataBoxState.aiBoostMessage = "";
  } finally {
    dataBoxState.aiBoostLoading = false;
    render();
  }
}

async function rejectDataBoxAiBoostAction(actionId) {
  const id = String(actionId || "").trim();
  if (!id || dataBoxState.aiBoostLoading) {
    return;
  }

  const reason = window.prompt("Proč návrh zamítáme?", "Návrh není správný.");
  if (reason === null) {
    return;
  }

  dataBoxState.aiBoostLoading = true;
  dataBoxState.aiBoostError = "";
  dataBoxState.aiBoostMessage = "Zamítám návrh Autopilota...";
  render();

  try {
    const result = await apiJson(`/api/data-box/actions/${encodeURIComponent(id)}/reject`, {
      method: "POST",
      body: JSON.stringify({ reason: String(reason || "").trim() || "Zamítnuto uživatelem." })
    });
    dataBoxState.aiBoostEditingId = "";
    dataBoxState.aiBoostMessage = result.notice || "Návrh Autopilota byl zamítnut.";
    dataBoxState.aiBoostError = "";
    await loadDataBoxData({ force: true, renderAfter: false });
    dataBoxState.activeTab = "confirmations";
  } catch (error) {
    dataBoxState.aiBoostError = error?.payload?.error || error?.message || "Návrh Autopilota se nepodařilo zamítnout.";
    dataBoxState.aiBoostMessage = "";
  } finally {
    dataBoxState.aiBoostLoading = false;
    render();
  }
}

function dataBoxAiBoostRulePayloadFromForm(form) {
  const formData = new FormData(form);
  const textContains = String(formData.get("textContains") || "").trim();
  const scope = String(formData.get("scope") || "anywhere").trim();
  const actionType = String(formData.get("actionType") || "archive").trim();
  const safetyMode = String(formData.get("safetyMode") || "suggestion").trim();

  return {
    id: form.dataset.editingRuleId && !String(form.dataset.editingRuleId).startsWith("starter-")
      ? form.dataset.editingRuleId
      : `draft-${Date.now()}`,
    title: String(formData.get("title") || "").trim() || textContains || "Pracovní pravidlo",
    textContains,
    scope,
    actionType,
    safetyMode,
    source: "Pracovní návrh",
    active: true
  };
}

function createDataBoxAiBoostRuleDraft(form) {
  try {
    const draft = dataBoxAiBoostRulePayloadFromForm(form);
    if (!draft.textContains) {
      throw new Error("Vyplň, co má zpráva obsahovat.");
    }
    const editingId = String(form.dataset.editingRuleId || "");
    if (editingId && editingId.startsWith("starter-")) {
      dataBoxState.aiBoostDisabledRuleIds = Array.from(new Set([
        ...(dataBoxState.aiBoostDisabledRuleIds || []),
        editingId
      ]));
    }
    dataBoxState.aiBoostDraftRules = [
      ...(dataBoxState.aiBoostDraftRules || []).filter((rule) => String(rule.id || "") !== String(draft.id || "")),
      draft
    ];
    dataBoxState.aiBoostDraftRuleEditingId = "";
    dataBoxState.aiBoostMessage = `${dataBoxAiBoostRuleSentence(draft)} Pravidlo je zatím pracovní návrh.`;
    dataBoxState.aiBoostError = "";
    render();
  } catch (error) {
    dataBoxState.aiBoostError = error.message || "Návrh pravidla se nepodařilo připravit.";
    dataBoxState.aiBoostMessage = "";
    render();
  }
}

function createDataBoxAiBoostRuleDraftFromAction(actionId) {
  const action = dataBoxState.aiBoostActions.find((item) => String(item.id || "") === String(actionId || ""));
  const message = dataBoxAiBoostMessage(action);
  if (!action?.id) {
    dataBoxState.aiBoostError = "Návrh Autopilota nebyl nalezen.";
    dataBoxState.aiBoostMessage = "";
    render();
    return;
  }

  const actionType = String(action.actionType || action.result?.recommendedAction || "review").toLowerCase();
  const draft = {
    id: `draft-${Date.now()}`,
    title: `${dataBoxAiBoostActionLabel(action)}: ${message?.senderName || message?.subject || action.subject || "Datová zpráva"}`.slice(0, 140),
    textContains: message?.subject || action.subject || "",
    scope: "anywhere",
    actionType: actionType === "archive" ? "archive"
      : actionType === "reply" ? "reply"
        : actionType === "email" ? "handoff"
          : "handoff",
    safetyMode: "suggestion",
    source: "Pracovní návrh z AI výsledku",
    active: true
  };

  dataBoxState.aiBoostDraftRules = [
    ...(dataBoxState.aiBoostDraftRules || []),
    draft
  ];
  dataBoxState.aiBoostDraftRuleEditingId = draft.id;
  dataBoxState.aiBoostMessage = "Pracovní pravidlo vzniklo z AI návrhu. Uprav ho v průvodci a zkontroluj větu Když... navrhni...";
  dataBoxState.aiBoostError = "";
  render();
}

function openDataBoxAiBoostMessage(messageId) {
  const id = String(messageId || "").trim();
  if (!id) {
    return;
  }
  const message = dataBoxMessageById(id);
  if (message?.dataBoxId) {
    dataBoxState.selectedDataBoxId = message.dataBoxId;
  }
  dataBoxState.activeTab = "messages";
  void loadDataBoxMessageDetail(id);
}

async function loadDataBoxMessageInlineDetail(messageId) {
  const id = String(messageId || "").trim();
  if (!id) {
    return;
  }

  resetDataBoxAttachmentFeedback();

  dataBoxState.selectedPreviewMessageId = id;
  dataBoxState.selectedMessageId = id;
  dataBoxState.selectedMessage = dataBoxState.selectedMessage?.id === id ? dataBoxState.selectedMessage : null;
  dataBoxState.detailLoading = true;
  dataBoxState.detailError = "";
  render();

  try {
    const result = await apiJson(`/api/data-box/messages/${encodeURIComponent(id)}`);
    if (dataBoxState.selectedMessageId === id) {
      const detailMessage = result.message || null;
      dataBoxState.selectedMessage = detailMessage;
    }
  } catch (error) {
    if (dataBoxState.selectedMessageId === id) {
      dataBoxState.selectedMessage = null;
      dataBoxState.detailError = error?.payload?.error || error?.message || "Zprávu se teď nepodařilo načíst.";
    }
  } finally {
    if (dataBoxState.selectedMessageId === id) {
      dataBoxState.detailLoading = false;
    }
  }

  render();
}

async function runDataBoxManualSync() {
  if (dataBoxState.syncLoading) {
    return;
  }

  dataBoxState.syncLoading = true;
  dataBoxState.syncError = "";
  dataBoxState.syncMessage = "Načítám nové zprávy...";
  render();

  try {
    const result = await apiJson("/api/data-box/sync", {
      method: "POST",
      body: JSON.stringify({})
    });
    dataBoxState.syncMessage = result.message || result.sync?.message || "Načtení doběhlo.";
    await loadDataBoxData({ force: true, renderAfter: false });
  } catch (error) {
    dataBoxState.syncError = error?.payload?.error || error?.message || "Načtení se nepodařilo spustit.";
    await loadDataBoxData({ force: true, renderAfter: false }).catch(() => {});
  } finally {
    dataBoxState.syncLoading = false;
  }

  render();
}

function updateDataBoxMessageFilter(field) {
  const name = field?.name;
  if (!name || !Object.prototype.hasOwnProperty.call(dataBoxState.messageFilters, name)) {
    return;
  }

  clearDataBoxSearchRenderTimer();
  dataBoxState.messageFilters = {
    ...dataBoxState.messageFilters,
    [name]: field.value || ""
  };
  resetDataBoxPagination();
  dataBoxState.selectedPreviewMessageId = "";
  render();
}

async function loadVehicleTrackingStatus(options = {}) {
  const { force = false, renderAfter = true } = options;

  if (vehicleTrackingLiveState.loading || (vehicleTrackingLiveState.loaded && !force)) {
    return;
  }

  vehicleTrackingLiveState.loading = true;
  vehicleTrackingLiveState.error = "";

  try {
    const status = await apiJson("/api/vehicle-tracking/status");
    vehicleTrackingLiveState.status = status;
    vehicleTrackingLiveState.loaded = true;
  } catch (error) {
    vehicleTrackingLiveState.status = null;
    vehicleTrackingLiveState.error = error?.payload?.error || error?.message || VEHICLE_TRACKING_API_ERROR;
    vehicleTrackingLiveState.loaded = true;
  } finally {
    vehicleTrackingLiveState.loading = false;
  }

  if (renderAfter) {
    render();
    if (vehicleTrackingActiveSourceMode() === "tcars") {
      queueVehicleTrackingTcarsGoogleSync({ forceFit: true });
    }
  }
}

async function loadVehicleTrackingPreferences(options = {}) {
  const { force = false, renderAfter = true } = options;
  if (vehicleTrackingUiState.preferencesLoading || (vehicleTrackingUiState.preferencesLoaded && !force)) return;
  if (!hasPermission(currentUser(), "vehicle-tracking", "view")) return;

  vehicleTrackingUiState.preferencesLoading = true;
  try {
    const result = await apiJson("/api/vehicle-tracking/preferences");
    const preferences = normalizeVehicleTrackingPreferences(result.preferences || {});
    vehicleTrackingUiState.infoStyle = preferences.infoStyle;
    vehicleTrackingUiState.preferencesLoaded = true;
    vehicleTrackingUiState.preferencesMessage = "";
  } catch (error) {
    vehicleTrackingUiState.preferencesLoaded = true;
    vehicleTrackingUiState.preferencesMessage = "Používám výchozí vzhled; osobní volbu se nepodařilo načíst.";
  } finally {
    vehicleTrackingUiState.preferencesLoading = false;
  }

  if (renderAfter) {
    const camera = vehicleTrackingTcarsGoogleCamera();
    render();
    syncVehicleTrackingMapMaximizedDom();
    queueVehicleTrackingTcarsGoogleSync(camera ? { preserveCamera: camera } : { forceFit: true });
  }
}

async function saveVehicleTrackingInfoStyle(value) {
  const nextStyle = normalizeVehicleTrackingInfoStyle(value);
  const previousStyle = vehicleTrackingUiState.infoStyle;
  const camera = vehicleTrackingTcarsGoogleCamera();
  vehicleTrackingUiState.infoStyle = nextStyle;
  vehicleTrackingUiState.preferencesSaving = true;
  vehicleTrackingUiState.preferencesMessage = "Ukládám tvoji volbu…";
  render();
  syncVehicleTrackingMapMaximizedDom();
  queueVehicleTrackingTcarsGoogleSync(camera ? { preserveCamera: camera } : { forceFit: true });

  try {
    const result = await apiJson("/api/vehicle-tracking/preferences", {
      method: "PATCH",
      body: JSON.stringify({ infoStyle: nextStyle })
    });
    vehicleTrackingUiState.infoStyle = normalizeVehicleTrackingPreferences(result.preferences || {}).infoStyle;
    vehicleTrackingUiState.preferencesLoaded = true;
    vehicleTrackingUiState.preferencesMessage = "Vzhled cedule je uložený pro tvůj účet.";
  } catch (error) {
    vehicleTrackingUiState.infoStyle = previousStyle;
    vehicleTrackingUiState.preferencesMessage = error?.payload?.error || "Volbu se nepodařilo uložit.";
  } finally {
    vehicleTrackingUiState.preferencesSaving = false;
    render();
    syncVehicleTrackingMapMaximizedDom();
    queueVehicleTrackingTcarsGoogleSync(camera ? { preserveCamera: camera } : { forceFit: true });
  }
}

async function loadVehicleTrackingMapConfig(options = {}) {
  const { force = false, renderAfter = true } = options;

  if (vehicleTrackingMapConfigState.loading || (vehicleTrackingMapConfigState.loaded && !force)) {
    return;
  }

  if (!hasPermission(currentUser(), "vehicle-tracking", "view")) {
    return;
  }

  vehicleTrackingMapConfigState.loading = true;
  vehicleTrackingMapConfigState.error = "";

  try {
    const result = await apiJson("/api/vehicle-tracking/maps-config");
    vehicleTrackingMapConfigState.configured = result.configured === true && Boolean(result.browserApiKey);
    vehicleTrackingMapConfigState.apiStatus = result.apiStatus || "waiting";
    vehicleTrackingMapConfigState.provider = result.provider || "google-maps-javascript";
    vehicleTrackingMapConfigState.browserApiKey = String(result.browserApiKey || "").trim();
    vehicleTrackingMapConfigState.message = result.message || "";
    vehicleTrackingMapConfigState.loaded = true;
  } catch (error) {
    vehicleTrackingMapConfigState.configured = false;
    vehicleTrackingMapConfigState.apiStatus = "error";
    vehicleTrackingMapConfigState.browserApiKey = "";
    vehicleTrackingMapConfigState.message = "";
    vehicleTrackingMapConfigState.error = error?.payload?.error || error?.message || "Konfiguraci Google mapy se nepodařilo načíst.";
    vehicleTrackingMapConfigState.loaded = true;
  } finally {
    vehicleTrackingMapConfigState.loading = false;
  }

  if (renderAfter) {
    render();
    queueVehicleTrackingTcarsGoogleSync({ forceFit: true });
  }
}

async function loadVehicleTrackingWimSites(options = {}) {
  const { force = false, renderAfter = true } = options;

  if (vehicleTrackingLiveState.wimLoading || (vehicleTrackingLiveState.wimLoaded && !force)) {
    return;
  }

  if (!hasPermission(currentUser(), "vehicle-tracking", "view")) {
    return;
  }

  vehicleTrackingLiveState.wimLoading = true;
  vehicleTrackingLiveState.wimError = "";
  vehicleTrackingLiveState.wimAlertError = "";

  try {
    const sitesResult = await apiJson("/api/vehicle-tracking/wim-sites");
    vehicleTrackingLiveState.wimSites = Array.isArray(sitesResult.sites) ? sitesResult.sites : [];
    vehicleTrackingLiveState.wimSummary = sitesResult.summary || null;
    vehicleTrackingLiveState.wimSource = sitesResult.source || null;
    vehicleTrackingLiveState.wimApiStatus = sitesResult.apiStatus || "ready";
    try {
      const alertsResult = await apiJson("/api/vehicle-tracking/wim-alerts");
      vehicleTrackingLiveState.wimAlertEvents = Array.isArray(alertsResult.events) ? alertsResult.events : [];
    } catch (alertError) {
      vehicleTrackingLiveState.wimAlertEvents = [];
      vehicleTrackingLiveState.wimAlertError = alertError?.payload?.error || alertError?.message || "WIM alert log zatim neni dostupny.";
    }
    vehicleTrackingLiveState.wimLoaded = true;
    if (
      vehicleTrackingLiveState.selectedWimSiteId &&
      !vehicleTrackingLiveState.wimSites.some((site) => site.id === vehicleTrackingLiveState.selectedWimSiteId)
    ) {
      vehicleTrackingLiveState.selectedWimSiteId = "";
    }
    if (!vehicleTrackingLiveState.selectedWimSiteId && vehicleTrackingLiveState.wimSites[0]) {
      vehicleTrackingLiveState.selectedWimSiteId = vehicleTrackingLiveState.wimSites[0].id;
    }
  } catch (error) {
    vehicleTrackingLiveState.wimSites = [];
    vehicleTrackingLiveState.wimSummary = null;
    vehicleTrackingLiveState.wimSource = null;
    vehicleTrackingLiveState.wimApiStatus = error?.payload?.apiStatus || "waiting";
    vehicleTrackingLiveState.wimAlertEvents = [];
    vehicleTrackingLiveState.wimAlertError = "";
    vehicleTrackingLiveState.wimError = error?.payload?.error || error?.message || VEHICLE_TRACKING_WIM_WAITING;
    vehicleTrackingLiveState.wimLoaded = true;
  } finally {
    vehicleTrackingLiveState.wimLoading = false;
  }

  if (renderAfter) {
    render();
    if (vehicleTrackingActiveSourceMode() === "tcars") {
      queueVehicleTrackingTcarsGoogleSync({ forceFit: true });
    }
  }
}

async function loadFleetVehicles(options = {}) {
  const { force = false, renderAfter = true } = options;

  if (fleetVehiclesState.loading || (fleetVehiclesState.loaded && !force)) {
    return;
  }

  if (!hasPermission(currentUser(), "fleet", "view")) {
    return;
  }

  fleetVehiclesState.loading = true;
  fleetVehiclesState.error = "";

  try {
    const result = await apiJson("/api/vehicles");
    fleetVehiclesState.vehicles = Array.isArray(result.vehicles)
      ? result.vehicles.filter((item) => item && typeof item === "object")
      : [];
    fleetVehiclesState.driverCandidates = Array.isArray(result.driverCandidates)
      ? result.driverCandidates.filter((item) => item && typeof item === "object")
      : [];
    fleetVehiclesState.summary = result.summary || null;
    fleetVehiclesState.apiStatus = result.apiStatus || "waiting";
    fleetVehiclesState.provider = result.provider || "";
    fleetVehiclesState.source = result.source || "";
    fleetVehiclesState.telemetrySource = result.telemetrySource || "";
    fleetVehiclesState.message = result.message || "";
    fleetVehiclesState.lastFetchedAt = result.lastFetchedAt || "";
    fleetVehiclesState.loaded = true;
  } catch (error) {
    fleetVehiclesState.vehicles = [];
    fleetVehiclesState.driverCandidates = [];
    fleetVehiclesState.summary = null;
    fleetVehiclesState.apiStatus = "waiting";
    fleetVehiclesState.provider = "";
    fleetVehiclesState.source = "";
    fleetVehiclesState.telemetrySource = "";
    fleetVehiclesState.error = error?.payload?.error || error?.message || "Vozidla se teď nepodařilo načíst.";
  } finally {
    fleetVehiclesState.loading = false;
  }

  if (renderAfter) {
    render();
  }
}

function updateFleetVehicleFilter(field) {
  const name = field?.name;
  if (!name || !Object.prototype.hasOwnProperty.call(fleetUiState.vehicleFilters, name)) {
    return;
  }

  fleetUiState.vehicleFilters = {
    ...fleetUiState.vehicleFilters,
    [name]: field.value || (name === "search" ? "" : "all")
  };

  const shouldRestoreSearchFocus = name === "search";
  const selectionStart = shouldRestoreSearchFocus ? field.selectionStart : null;
  const selectionEnd = shouldRestoreSearchFocus ? field.selectionEnd : null;
  render();

  if (shouldRestoreSearchFocus) {
    requestAnimationFrame(() => {
      const searchInput = document.querySelector("[data-fleet-filter][name='search']");
      if (searchInput) {
        searchInput.focus();
        if (typeof searchInput.setSelectionRange === "function" && selectionStart !== null && selectionEnd !== null) {
          searchInput.setSelectionRange(selectionStart, selectionEnd);
        }
      }
    });
  }
}

function resetFleetVehicleFilters() {
  fleetUiState.vehicleFilters = {
    quick: "all",
    status: "all",
    type: "all",
    driver: "all",
    terms: "all",
    defects: "all",
    search: ""
  };
  render();
}

function updateFleetVehicleInState(vehicle) {
  if (!vehicle?.id) {
    return;
  }

  const index = fleetVehiclesState.vehicles.findIndex((item) => fleetVehicleMatchesId(item, vehicle.id));
  if (index === -1) {
    fleetVehiclesState.vehicles = [vehicle, ...fleetVehiclesState.vehicles];
    return;
  }

  fleetVehiclesState.vehicles = fleetVehiclesState.vehicles.map((item, itemIndex) => (
    itemIndex === index ? { ...item, ...vehicle } : item
  ));
}

async function submitFleetDriverAssignment(form) {
  const vehicleId = String(form?.dataset?.vehicleId || "").trim();

  if (!vehicleId) {
    fleetUiState.error = "Chybí ID vozidla.";
    render();
    return;
  }

  const formData = new FormData(form);
  const payload = {
    assignedDriverId: String(formData.get("assignedDriverId") || "").trim(),
    note: String(formData.get("note") || "").trim()
  };

  fleetUiState.savingAssignmentVehicleId = vehicleId;
  fleetUiState.message = "";
  fleetUiState.error = "";
  render();

  try {
    const result = await apiJson(`/api/vehicles/${encodeURIComponent(vehicleId)}`, {
      method: "PATCH",
      body: JSON.stringify(payload)
    });
    updateFleetVehicleInState(result.vehicle);
    fleetUiState.message = result.vehicle?.assignedDriverName
      ? `Řidič ${result.vehicle.assignedDriverName} je uložený k vozidlu.`
      : "Přiřazení řidiče bylo vymazáno.";
  } catch (error) {
    fleetUiState.error = error?.payload?.error || error?.message || "Řidiče se teď nepodařilo uložit.";
  } finally {
    fleetUiState.savingAssignmentVehicleId = "";
    render();
  }
}

function handleVehicleTrackingSourceMode(mode) {
  if (!["demo", "tcars"].includes(mode)) {
    return;
  }

  const nextHash = vehicleTrackingSourceModeHash(mode);
  if (window.location.hash !== nextHash) {
    window.history.replaceState({}, "", `${window.location.pathname}${window.location.search}${nextHash}`);
    lastRenderedUrl = window.location.href;
  }

  vehicleTrackingLiveState.sourceMode = mode;
  render();

  if (mode === "tcars") {
    loadVehicleTrackingPreferences();
    loadVehicleTrackingStatus();
    queueVehicleTrackingTcarsGoogleSync({ forceFit: true });
  } else {
    clearVehicleTrackingTcarsGoogleMap();
  }
}

function handleVehicleTrackingTcarsSelect(locationId, options = {}) {
  const normalizedId = String(locationId || "").trim();
  if (!normalizedId || !vehicleTrackingTcarsLocationById(normalizedId)) {
    return;
  }

  if (vehicleTrackingLiveState.selectedLocationId !== normalizedId) {
    vehicleTrackingUiState.routePanelOpen = false;
    vehicleTrackingLiveState.routeData = null;
    vehicleTrackingLiveState.routeError = "";
    vehicleTrackingLiveState.routeRequestKey = "";
  }
  vehicleTrackingLiveState.selectedLocationId = normalizedId;
  syncVehicleTrackingTcarsSelectionDom(normalizedId);
  queueVehicleTrackingTcarsGoogleSync({ focusSelected: options.focusMap !== false });
}

function handleVehicleTrackingTcarsSelectEvent(event) {
  const trackingTcarsSelect = event.target?.closest?.("[data-tracking-tcars-select]");
  if (!trackingTcarsSelect) {
    return false;
  }

  event.preventDefault();
  handleVehicleTrackingTcarsSelect(trackingTcarsSelect.dataset.trackingTcarsSelect || "");
  return true;
}

function handleVehicleTrackingWimSelect(siteId, options = {}) {
  const normalizedId = String(siteId || "").trim();
  if (!normalizedId || !vehicleTrackingWimSiteById(normalizedId)) {
    return;
  }

  vehicleTrackingLiveState.selectedWimSiteId = normalizedId;
  syncVehicleTrackingWimSelectionDom(normalizedId);
  queueVehicleTrackingTcarsGoogleSync({ focusWimSelected: options.focusMap !== false });
}

function handleVehicleTrackingWimSelectEvent(event) {
  const trackingWimSelect = event.target?.closest?.("[data-tracking-wim-select]");
  if (!trackingWimSelect) {
    return false;
  }

  event.preventDefault();
  handleVehicleTrackingWimSelect(trackingWimSelect.dataset.trackingWimSelect || "");
  return true;
}

function resetAssistantPromoState() {
  Object.assign(assistantPromoState, assistantPromoDefaultState);
}

function assistantPromoDateString(date = new Date()) {
  try {
    const parts = new Intl.DateTimeFormat("cs-CZ", {
      timeZone: "Europe/Prague",
      year: "numeric",
      month: "2-digit",
      day: "2-digit"
    }).formatToParts(date);
    const valueFor = (type) => parts.find((part) => part.type === type)?.value || "";
    const year = valueFor("year");
    const month = valueFor("month").padStart(2, "0");
    const day = valueFor("day").padStart(2, "0");

    if (year && month && day) {
      return `${year}-${month}-${day}`;
    }
  } catch {
    // Promo fallback must not block app start if Intl timezone support is missing.
  }

  return date.toISOString().slice(0, 10);
}

function isAssistantPromoActive(dateString = assistantPromoDateString()) {
  return dateString <= assistantPromoDefaultState.validUntil;
}

function shouldAutoShowAssistantPromo() {
  const path = normalizePath(window.location.pathname);
  return AI_ASSISTANT_PROMO_AUTOSHOW_ENABLED &&
    !path.startsWith(FLEET_ROUTE) &&
    !isCollectionRoutesPath(path) &&
    !path.startsWith(ABSENCE_ROUTE);
}

function applyAssistantPromoPayload(payload = {}) {
  assistantPromoState.promoKey = String(payload.promoKey || "");
  assistantPromoState.promoDate = String(payload.promoDate || "");
  assistantPromoState.validUntil = String(payload.validUntil || assistantPromoDefaultState.validUntil);
  assistantPromoState.action = String(payload.action || "");
  assistantPromoState.videoUrl = String(payload.videoUrl || assistantPromoDefaultState.videoUrl);
  assistantPromoState.fallbackImageUrl = String(payload.fallbackImageUrl || assistantPromoDefaultState.fallbackImageUrl);
}

async function recordAssistantPromoAction(action) {
  const result = await apiJson("/api/sarlota-promo", {
    method: "POST",
    body: JSON.stringify({ action })
  });
  applyAssistantPromoPayload(result);
  return result;
}

async function loadAssistantPromo(options = {}) {
  if (!AI_ASSISTANT_PROMO_AUTOSHOW_ENABLED) {
    assistantPromoState.visible = false;
    assistantPromoState.loaded = true;
    assistantPromoState.loading = false;
    return;
  }

  if (assistantPromoState.loaded || assistantPromoState.loading || authState.status !== "authenticated" || !authState.user) {
    return;
  }

  assistantPromoState.loading = true;
  assistantPromoState.error = "";

  try {
    const result = await apiJson("/api/sarlota-promo");
    applyAssistantPromoPayload(result);

    if (result.show && shouldAutoShowAssistantPromo()) {
      assistantPromoState.visible = true;
      assistantPromoState.videoFailed = false;
      aiAssistantState.welcomeVisible = false;
      aiAssistantState.welcomeAnimate = false;
      aiAssistantState.launcherVisible = false;
    } else {
      assistantPromoState.visible = false;
    }
  } catch (error) {
    assistantPromoState.error = error?.payload?.error || error?.message || "Promo Šarloty se teď nepodařilo ověřit.";
    assistantPromoState.promoDate = assistantPromoDateString();
    assistantPromoState.validUntil = assistantPromoDefaultState.validUntil;
    assistantPromoState.videoUrl = assistantPromoDefaultState.videoUrl;
    assistantPromoState.fallbackImageUrl = assistantPromoDefaultState.fallbackImageUrl;
    assistantPromoState.visible = isAssistantPromoActive(assistantPromoState.promoDate) && shouldAutoShowAssistantPromo();
    assistantPromoState.videoFailed = false;
    if (assistantPromoState.visible) {
      aiAssistantState.welcomeVisible = false;
      aiAssistantState.welcomeAnimate = false;
      aiAssistantState.launcherVisible = false;
    }
  } finally {
    assistantPromoState.loaded = true;
    assistantPromoState.loading = false;
  }

  if (options.renderAfter !== false) {
    render();
  }
}

function renderAssistantPromoLayer() {
  if (!shouldAutoShowAssistantPromo()) {
    return "";
  }

  return AiAssistantPromoModal({
    visible: assistantPromoState.visible && shouldAutoShowAssistantPromo(),
    videoUrl: assistantPromoState.videoUrl,
    fallbackImageUrl: assistantPromoState.fallbackImageUrl,
    videoFailed: assistantPromoState.videoFailed,
    saving: assistantPromoState.saving
  });
}

function unmuteAssistantPromoVideo(video) {
  if (!video) {
    return;
  }

  try {
    video.defaultMuted = false;
    video.muted = false;
    video.volume = 1;
  } catch {
    // Browser media policy is allowed to ignore volume changes.
  }
}

function syncAssistantPromoVideo() {
  const promoVideo = document.querySelector("[data-ai-promo-video]");

  if (!promoVideo) {
    return;
  }

  unmuteAssistantPromoVideo(promoVideo);
  promoVideo.addEventListener("loadedmetadata", () => unmuteAssistantPromoVideo(promoVideo), { once: true });
  promoVideo.addEventListener("play", () => unmuteAssistantPromoVideo(promoVideo), { once: true });
}

async function declineAssistantPromo() {
  if (assistantPromoState.saving) {
    return;
  }

  assistantPromoState.saving = true;
  render();

  try {
    await recordAssistantPromoAction("declined");
  } catch (error) {
    assistantPromoState.error = error?.payload?.error || error?.message || "Volbu se nepodařilo uložit.";
  } finally {
    assistantPromoState.visible = false;
    assistantPromoState.saving = false;
    render();
  }
}

async function acceptAssistantPromo() {
  if (assistantPromoState.saving) {
    return;
  }

  assistantPromoState.saving = true;
  assistantPromoState.visible = false;
  render();
  const savePromise = recordAssistantPromoAction("accepted").catch((error) => {
    assistantPromoState.error = error?.payload?.error || error?.message || "Volbu se nepodařilo uložit.";
  });

  try {
    openAiAssistant("voice");
    triggerAiHaptic(15);
    await startElevenLabsVoiceRecognition();
  } finally {
    await savePromise;
    assistantPromoState.saving = false;
    render();
  }
}

async function loadModuleFeedback(options = {}) {
  const user = currentUser();
  if (feedbackState.loaded || feedbackState.loading || !hasPermission(user, "feedback", "view")) {
    return;
  }

  feedbackState.loading = true;
  feedbackState.error = "";

  try {
    const result = await apiJson("/api/module-feedback");
    feedbackState.items = (result.feedback || [])
      .map(normalizeFeedback)
      .sort((a, b) => String(b.createdAt).localeCompare(String(a.createdAt)));
    feedbackState.apiStatus = result.apiStatus || "ready";
  } catch (error) {
    const missing = error.payload?.missingEndpoint;
    feedbackState.error = missing
      ? `Čeká na API: ${missing}`
      : "Připomínky se teď nepodařilo načíst.";
    feedbackState.apiStatus = error.payload?.apiStatus || "waiting";
  } finally {
    feedbackState.loaded = true;
    feedbackState.loading = false;
    if (options.render !== false) {
      render();
    }
  }
}

function selfRepairStatusLabel(status) {
  return SELF_REPAIR_STATUS_OPTIONS.find((option) => option.value === status)?.label || status || "Neznámý stav";
}

function selfRepairRiskLabel(riskLevel) {
  return SELF_REPAIR_RISK_OPTIONS.find((option) => option.value === riskLevel)?.label || riskLevel || "Nezatříděno";
}

function normalizeSelfRepairCase(item = {}) {
  const status = String(item.status || "new");
  const riskLevel = String(item.riskLevel || "unclassified");
  return {
    ...item,
    id: String(item.id || ""),
    feedbackId: String(item.feedbackId || ""),
    caseType: String(item.caseType || "bug"),
    caseTypeLabel: String(item.caseTypeLabel || (item.caseType === "improvement" ? "Drobná úprava" : "Chyba")),
    status,
    statusLabel: String(item.statusLabel || selfRepairStatusLabel(status)),
    riskLevel,
    riskLabel: String(item.riskLabel || selfRepairRiskLabel(riskLevel)),
    priority: String(item.priority || "Běžná"),
    moduleKey: String(item.moduleKey || ""),
    moduleName: String(item.moduleName || ""),
    targetRepoKey: String(item.targetRepoKey || ""),
    targetProductionUrl: String(item.targetProductionUrl || ""),
    title: String(item.title || ""),
    description: String(item.description || ""),
    expectedBehavior: String(item.expectedBehavior || ""),
    actualBehavior: String(item.actualBehavior || ""),
    reproductionSteps: String(item.reproductionSteps || ""),
    sourceRoute: String(item.sourceRoute || ""),
    buildVersion: String(item.buildVersion || ""),
    buildCommit: String(item.buildCommit || ""),
    browserInfo: String(item.browserInfo || ""),
    reporterUserName: String(item.reporterUserName || "Uživatel"),
    triageSummary: String(item.triageSummary || ""),
    internalNote: String(item.internalNote || ""),
    createdAt: String(item.createdAt || ""),
    updatedAt: String(item.updatedAt || "")
  };
}

function ensureSelfRepairData(options = {}) {
  if (!authState.user || selfRepairState.loading || !hasPermission(authState.user, SELF_REPAIR_MODULE_KEY, "view")) {
    return;
  }
  if (!selfRepairState.loaded || options.force) {
    void loadSelfRepairData(options);
  }
}

async function loadSelfRepairData(options = {}) {
  if (!authState.user || selfRepairState.loading || !hasPermission(authState.user, SELF_REPAIR_MODULE_KEY, "view")) {
    return;
  }

  selfRepairState.loading = true;
  selfRepairState.error = "";
  if (options.force) selfRepairState.message = "";

  try {
    const [casesResult, statusResult] = await Promise.all([
      apiJson("/api/self-repair/cases?limit=500"),
      apiJson("/api/self-repair/status").catch((error) => ({
        apiStatus: error.payload?.apiStatus || "waiting",
        error: error.payload?.error || error.message
      }))
    ]);
    selfRepairState.cases = (casesResult.cases || []).map(normalizeSelfRepairCase);
    selfRepairState.summary = { ...selfRepairState.summary, ...(casesResult.summary || {}) };
    selfRepairState.statusData = statusResult;
    selfRepairState.apiStatus = casesResult.apiStatus || statusResult.apiStatus || "ready";
    selfRepairState.loaded = true;

    if (!selfRepairState.cases.some((item) => item.id === selfRepairState.selectedId)) {
      selfRepairState.selectedId = selfRepairState.cases[0]?.id || "";
    }

    if (selfRepairState.selectedId) {
      const detailResult = await apiJson(`/api/self-repair/cases/${encodeURIComponent(selfRepairState.selectedId)}`);
      selfRepairState.detail = {
        case: normalizeSelfRepairCase(detailResult.case),
        evidence: Array.isArray(detailResult.evidence) ? detailResult.evidence : [],
        audit: Array.isArray(detailResult.audit) ? detailResult.audit : []
      };
    } else {
      selfRepairState.detail = null;
    }

    if (options.force) selfRepairState.message = "Případy a provozní stav byly obnoveny.";
  } catch (error) {
    selfRepairState.loaded = true;
    selfRepairState.apiStatus = error.payload?.apiStatus || "waiting";
    selfRepairState.error = error.payload?.error || error.message || "Případy Samooprav se teď nepodařilo načíst.";
  } finally {
    selfRepairState.loading = false;
    if (options.renderAfter !== false) render();
  }
}

async function runSelfRepairMonitorNow() {
  if (selfRepairState.monitorRunning) return;
  if (!hasPermission(currentUser(), SELF_REPAIR_MODULE_KEY, "manage") && !isFullAccessRole(currentUser())) {
    selfRepairState.error = "Nemáte oprávnění spustit read-only kontrolu.";
    render();
    return;
  }

  const confirmed = window.confirm(
    "Spustit read-only kontrolu veřejných produkčních stránek? Kontrola zapíše log a případné nálezy s návrhem promptu. Codex, změna kódu, nasazení ani e-mail se nespustí."
  );
  if (!confirmed) return;

  selfRepairState.monitorRunning = true;
  selfRepairState.error = "";
  selfRepairState.message = "Spouštím read-only kontrolu. Nic se neopravuje ani nenasazuje.";
  render();

  try {
    const result = await apiJson("/api/self-repair/monitor/run", {
      method: "POST",
      body: JSON.stringify({ confirmReadOnly: true })
    });
    await Promise.all([
      loadSelfRepairData({ renderAfter: false }),
      loadModuleRules(SELF_REPAIR_MODULE_KEY, { renderAfter: false })
    ]);
    selfRepairState.message = result.status === "skipped"
      ? "Kontrola pro tuto hodinu už proběhla; duplicitní spuštění bylo bezpečně zastaveno."
      : `Read-only kontrola dokončena: ${Number(result.routesChecked || 0)} stránek, ${Number(result.findingsTotal || 0)} nálezů. Codex, nasazení ani e-mail se nespustily.`;
  } catch (error) {
    selfRepairState.error = error.payload?.error || error.message || "Read-only kontrolu se teď nepodařilo spustit.";
    selfRepairState.message = "";
  } finally {
    selfRepairState.monitorRunning = false;
    render();
  }
}

async function loadSelfRepairDetail(id, options = {}) {
  const caseId = String(id || "");
  if (!caseId || selfRepairState.detailLoading) return;
  selfRepairState.selectedId = caseId;
  selfRepairState.detailLoading = true;
  selfRepairState.error = "";
  if (options.renderBefore !== false) render();

  try {
    const result = await apiJson(`/api/self-repair/cases/${encodeURIComponent(caseId)}`);
    selfRepairState.detail = {
      case: normalizeSelfRepairCase(result.case),
      evidence: Array.isArray(result.evidence) ? result.evidence : [],
      audit: Array.isArray(result.audit) ? result.audit : []
    };
  } catch (error) {
    selfRepairState.error = error.payload?.error || error.message || "Detail případu se teď nepodařilo načíst.";
  } finally {
    selfRepairState.detailLoading = false;
    if (options.renderAfter !== false) render();
  }
}

function applySelfRepairFilters(form) {
  if (!form) return;
  selfRepairFilters.status = form.elements.status?.value || "";
  selfRepairFilters.riskLevel = form.elements.riskLevel?.value || "";
  selfRepairFilters.moduleKey = form.elements.moduleKey?.value || "";
  selfRepairFilters.search = form.elements.search?.value.trim() || "";
  render();
}

function resetSelfRepairFilters() {
  Object.assign(selfRepairFilters, { status: "", riskLevel: "", moduleKey: "", search: "" });
  render();
}

function filteredSelfRepairCases() {
  const search = selfRepairFilters.search.toLowerCase();
  return selfRepairState.cases.filter((item) => {
    if (selfRepairFilters.status && item.status !== selfRepairFilters.status) return false;
    if (selfRepairFilters.riskLevel && item.riskLevel !== selfRepairFilters.riskLevel) return false;
    if (selfRepairFilters.moduleKey && item.moduleKey !== selfRepairFilters.moduleKey) return false;
    if (search) {
      const haystack = [item.title, item.description, item.moduleName, item.reporterUserName, item.triageSummary].join(" ").toLowerCase();
      if (!haystack.includes(search)) return false;
    }
    return true;
  });
}

async function updateSelfRepairCaseFromForm(form) {
  const caseId = String(form?.dataset.selfRepairCaseId || "");
  if (!caseId || selfRepairState.savingId) return false;
  selfRepairState.savingId = caseId;
  selfRepairState.error = "";
  selfRepairState.message = "";
  render();

  try {
    const result = await apiJson(`/api/self-repair/cases/${encodeURIComponent(caseId)}`, {
      method: "PATCH",
      body: JSON.stringify({
        status: form.elements.status?.value || "new",
        riskLevel: form.elements.riskLevel?.value || "unclassified",
        priority: form.elements.priority?.value || "Běžná",
        triageSummary: form.elements.triageSummary?.value.trim() || "",
        internalNote: form.elements.internalNote?.value.trim() || "",
        auditNote: "Ruční třídění ve správě Samooprav."
      })
    });
    const updated = normalizeSelfRepairCase(result.case);
    selfRepairState.cases = selfRepairState.cases.map((item) => item.id === caseId ? updated : item);
    selfRepairState.message = "Případ je uložený a změna je v auditu. Žádná oprava, zpráva ani nasazení se nespustily.";
    await loadSelfRepairDetail(caseId, { renderBefore: false, renderAfter: false });
    return true;
  } catch (error) {
    selfRepairState.error = error.payload?.error || error.message || "Případ se teď nepodařilo uložit.";
    return false;
  } finally {
    selfRepairState.savingId = "";
    render();
  }
}

